   public bool IsSkl_1_malop
   {
      get
      {
         string theTT = dbNavigationRestrictor_TT.RestrictedValues[0];

         TtInfo ttInfo = ZXC.TtInfo(Fld_TT);

         // 25.11.2016: 
         if(ttInfo.IsBlagajnaTT) return true;

