   public virtual bool IsSkl_2_malop
   {
      get
      {
         if(DoesSkl_2_exists) throw new Exception("IsSkl_2_malop NOT OVERRIDEN IN " + this.ToString());
         else return false;
      }
   }

   public bool DoesSkl_2_exists
   {
      get
      {
         string theTT = dbNavigationRestrictor_TT.RestrictedValues[0];

         TtInfo ttInfo = ZXC.TtInfo(Fld_TT);

         return ttInfo.TwinTT.NotEmpty() || ttInfo.SplitTT.NotEmpty();
      }
   }

