         //RNM_Grid.Size = new Size(RNM_Grid.Parent.Width - 2 * ZXC.QunMrgn, RNM_Grid.Parent.Height - 7 * ZXC.QunMrgn); //27.01.2017. premjestila na bebu jer su tamo hamperi!!!
         //RNM_Grid.Size = new Size(RNM_Grid.Parent.Width - 2 * ZXC.QunMrgn, RNM_Grid.Parent.Height - ZXC.Q3un);        //27.01.2017. premjestila na bebu jer su tamo hamperi!!!
         //RNM_Grid.Anchor = AnchorStyles.Bottom | AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right;           //27.01.2017. premjestila na bebu jer su tamo hamperi!!!

