      {
         // 01.03.2018. jo[ ne znam kako ali za probu ovako
         //CalcLocationSizeAnchor_TheDGVAndTheSumGrid_WidthTbxBottomOfSumGrid_WidthChooserGrid(TheG, ZXC.QunMrgn, ZXC.Qun8, hamp_twin, hamp_IznosUvaluti, false);

