         {
            VvHamper hmp = new VvHamper(); hmp.Size = new Size(ZXC.QUN, ZXC.Q3un);

            CalcLocationSizeAnchor_TheDGVAndTheSumGrid_WidthTbxBottomOfSumGrid_WidthChooserGrid(TheG, ZXC.QunMrgn, ZXC.Qun8, hamp_twin, hmp, false);

            hamp_irmKuponOUT.Location = new Point(TheG.Left, ZXC.QUN + ZXC.Qun2);
            hamp_irmKuponIN.Location = new Point(TheG.Right - hamp_irmKuponIN.Width, ZXC.QUN + ZXC.Qun2);
            hamp_irmKuponIN.Anchor = AnchorStyles.Top | AnchorStyles.Right;

         }
