         {
            VvHamper hmp = new VvHamper(); hmp.Size = new Size(ZXC.QUN, ZXC.Q3un + ZXC.Qun2);
            CalcLocationSizeAnchor_TheDGVAndTheSumGrid_WidthTbxBottomOfSumGrid_WidthChooserGrid(TheG, ZXC.QunMrgn, ZXC.Qun8, hamp_twin, hmp, false);
            hamp_ugoSvDuh.Location = new Point(TheG.Left, ZXC.Qun2);

         }
         else
