         else hamp_ciljaniMPC.Location = new Point(TheG.Right - hamp_IznosUvaluti.Width - hamp_ciljaniMPC.Width, hamp_IznosUvaluti.Top);

         hamp_ciljaniMPC.Anchor = AnchorStyles.Top | AnchorStyles.Right;


