      SetRtransColumnIndexes();

      CreateFakturDokumentPrintUC(this);

      this.IsShowingConvertedMoney = false;
      this.ValutaNameInUse = ZXC.ValutaNameEnum.EMPTY;

      this.Validating += new CancelEventHandler(FakturDUC_Validating);

      ResumeLayout();

      TheG.CellMouseDoubleClick += new DataGridViewCellMouseEventHandler(TheG_CellMouseDoubleClick_OpenArtiklUC);

      // 12.07.2018: 
      TheG.CellMouseDoubleClick += new DataGridViewCellMouseEventHandler(URA_NRD_SVD_Grid_CellMouseDoubleClick_Open_UGO_DUC);
      //01.09.2022.
      TheG.CellMouseDoubleClick += new DataGridViewCellMouseEventHandler(ZAH_SVD_Grid_CellMouseDoubleClick_Open_IZD_SVD_DUC);


      //RRD = new RiskRulesDsc(ZXC.dscLuiLst_riskRules);

      ZXC.RRD.SetMalopKupdob_rec(this);

      if(this is ZAH_SVD_DUC) Set_SvDUH_ZAHonlyKupdob_rec(this);

      #region dbNavigationRestrictor_SKL

      if(ZXC.IsTEXTHOany)
      {
         if(ZXC.IsTEXTHOshop)
         {
            if(this is PrimkaVpDUC || this is IzdatnicaDUC) // ovdje radimo spec. slucaj jer shopovi vide PrimkaDUC, a da ne vide centraline primke nego samo vlastite 
            {
               dbNavigationRestrictor_SKL =
                  new ZXC.DbNavigationRestrictor(Faktur.skladCd_colName,

                     ZXC.luiListaSkladista
                     .Where(lui => ZXC.ValOrZero_UInt(lui.Cd.Substring(0, 2)) == ZXC.vvDB_ServerID /*||
                                   ZXC.ValOrZero_UInt(lui.Cd.Substring(0, 2)) == ZXC.vvDB_ServerID_CENTRALA*/)
                     .Select(l => l.Cd).ToArray()
                     );
            }
            else // svi ostali FakturDUC-evi (classic, old way) 
            {
               dbNavigationRestrictor_SKL =
                  new ZXC.DbNavigationRestrictor(Faktur.skladCd_colName,

                     ZXC.luiListaSkladista
                     .Where(lui => ZXC.ValOrZero_UInt(lui.Cd.Substring(0, 2)) == ZXC.vvDB_ServerID ||
                                   ZXC.ValOrZero_UInt(lui.Cd.Substring(0, 2)) == ZXC.vvDB_ServerID_CENTRALA)
                     .Select(l => l.Cd).ToArray()
                     );
            }

            dbNavigationRestrictor_SKL2 = (IsSklCD2 == false ? ZXC.DbNavigationRestrictor.Empty :
               new ZXC.DbNavigationRestrictor(Faktur.skladCd2_colName,

                  ZXC.luiListaSkladista
                  .Where(lui => ZXC.ValOrZero_UInt(lui.Cd.Substring(0, 2)) == ZXC.vvDB_ServerID ||
                                ZXC.ValOrZero_UInt(lui.Cd.Substring(0, 2)) == ZXC.vvDB_ServerID_CENTRALA)
                  .Select(l => l.Cd).ToArray()
                  )
               );
         }
      } // if(ZXC.IsTEXTHOany)

      else
      {
         string skladWeWant = (ZXC.IsSvDUH) ? "10" : ZXC.TheVvForm.VvPref.findArtikl.LastUsedSkladCD;

         if(!ZXC.IsSvDUH && ZXC.RRD.Dsc_PreferedSkladOnUCLoad.NotEmpty())
         {
            skladWeWant = ZXC.RRD.Dsc_PreferedSkladOnUCLoad;
         }

         dbNavigationRestrictor_SKL = new ZXC.DbNavigationRestrictor
            (Faktur.skladCd_colName, new string[]
         {
            // 30.09.2020: 
          //(ZXC.IsSvDUH) ? "10" : ZXC.TheVvForm.VvPref.findArtikl.LastUsedSkladCD
            skladWeWant
         });
      }

      if(ZXC.IsSvDUH_ZAHonly)
      {
         //dbNavigationRestrictor_SKL2 = new ZXC.DbNavigationRestrictor
         //   ("addUID", new string[]
         //{
         //   ZXC.CURR_userName
         //});
         dbNavigationRestrictor_SKL2 = new ZXC.DbNavigationRestrictor
            ("kupdobTK", new string[]
         {
            ZXC.CURR_userName
         });

      }

      #endregion dbNavigationRestrictor_SKL

      TheTabControl.SelectionChanged += new Crownwood.DotNetMagic.Controls.SelectTabHandler(DecideIfShouldLoad_FakLinkgrid);

      // 27.04.2016. ovo je inace na FakturExtDUC-u ali ima previse dodatnih stvari kojih nema u FakturDUC-u pa da ne poprckam
      // dodala ovaj jednostavan zbog novog tab-a Veze a i na nekima koji imaju SaldaKonti da se ne prikazuje filter
      if(this is FakturExtDUC == false) TheTabControl.SelectionChanged += new Crownwood.DotNetMagic.Controls.SelectTabHandler(TheTabControl_SelectionChanged_FakturDUC);

      // 17.10.2017: first day on range w P26 Legion! :-)
      // Da li bi trebalo tu staviti i sve ostale? 
      SetSifrarAndAutocomplete<User>(null, VvSQL.SorterType.Code); // da ne ide po user sifrar u nezgodno vrijeme, recimo dok je sync IRM-a u background-u. 

      // 27.10.2021: 
      //31.03.2022. razdvajamo IsOnlyIOSknjizenje i ForceIRMkaoIRA??????
      if(ZXC.KSD.Dsc_IsOnlyIOSknjizenje)
      {
         SetSifrarAndAutocomplete<Kplan>(null, VvSQL.SorterType.None);
         FakturDao.Fak2Nal_CheckAndPrebaciIfNeeded(TheDbConnection);
      }
   }

   internal void Set_SvDUH_ZAHonlyKupdob_rec(FakturDUC theDUC)
   {
      if(theDUC == null) theDUC = ZXC.TheVvForm.TheVvUC as FakturDUC;

      ZXC.SvDUH_ZAHonlyKupdob_rec = theDUC.Get_Kupdob_FromVvUcSifrar_byTicker(ZXC.CURR_user_rec.UserName);

      if(ZXC.SvDUH_ZAHonlyKupdob_rec == null) ZXC.SvDUH_ZAHonlyKupdob_rec = new Kupdob();
   }

