      InitializeHamper_projekt(out hamp_projekt);
      hampCbxM_projekt = CreateCbxhamper4Migrators(hamp_projekt, 0, 0, 2, false);

      InitializeHamper_v1TT(out hamp_v1TT);
      InitializeHamper_v2TT(out hamp_v2TT);
      InitializeHamper_SukKC_K(out hamp_SukKC_K);
      InitializeHamper_osobaX(out hamp_osobaX);
      hampCbxM_osobaX = CreateCbxhamper4Migrators(hamp_osobaX, 0, 0, 2, false);

      InitializeHamper_prjIdent(out hamp_prjIdent);
      hampCbxM_prjIdent = CreateCbxhamper4Migrators(hamp_prjIdent, 0, 0, 2, false);

      InitializeHamper_iznosUvaluti(out hamp_IznosUvaluti);

      InitializeHamper_obrMPC(out hamp_obrMPC);
      InitializeHamper_ciljaniMPC(out hamp_ciljaniMPC);
      InitializeHamper_IrmInfoLabel(out hamp_irmInfoLabela);
      InitializeHamper_HappyHour(out hamp_HappyHour);
      InitializeHamper_decimal(out hamp_decimal);

      CreateExtHampers();
   }

   private void InitializeHamper_iznosUvaluti(out VvHamper hamper)
   {
      hamper = new VvHamper(2, 1, "", ThePolyGridTabControl.TabPages[0], false);

      hamper.VvColWdt = new int[] { labelWidth, ZXC.Q3un - ZXC.Qun4 };
      hamper.VvSpcBefCol = new int[] { faBefFirstCol, ZXC.Qun4 };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt = new int[] { ZXC.QUN };
      hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      hamper.CreateVvLabel(0, 0, "Iznosi u:", ContentAlignment.MiddleRight);
      tbx_IznosUvaluti = hamper.CreateVvTextBoxLookUp(1, 0, "tbx_iznos u", "Iznosi u:");
      tbx_IznosUvaluti.JAM_CharacterCasing = CharacterCasing.Upper;
      tbx_IznosUvaluti.JAM_Set_LookUpTable(ZXC.luiListaDeviza, (int)ZXC.Kolona.prva);
      tbx_IznosUvaluti.JAM_WriteOnly = true;
