      tbx_IznosUvaluti.JAM_IsSupressTab = true;

      if(this is RNZDUC) hamper.Visible = false;
      //12.05.2022.
      if(ZXC.IsSvDUH) hamper.Visible = false;

   }
   private void InitializeHamper_dokDate(out VvHamper hamper)
   {
      hamper = new VvHamper(2, 1, "", null, false);
      if(this is FakturExtDUC)
      {
         if(IsRadNalog) hamper.VvColWdt = new int[] { ZXC.Q6un - ZXC.Qun4, ZXC.Q4un + ZXC.Qun4 };
         else if(this is IFADUC ||
                 this is IRADUC ||
                 this is IRMDUC_2 ||
                 this is IRPDUC ||
                 this is IZMDUC ||
                 this is OdobrKupcuDUC ||
                 this is PovratKupcaDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.QUN + ZXC.Qun2 };
         else if(this is IRMDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q7un };
         else if(this is RNZDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q7un };
         else hamper.VvColWdt = new int[] { labelWidth, ZXC.Q4un + ZXC.Qun4 };

         hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol };
      }
      else
      {
         hamper.VvColWdt = new int[] { labelWidth, ZXC.Q4un + ZXC.Qun4 };
         hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol };
      }

      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt = new int[] { ZXC.QUN };
      hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      string text = "";

      if(IsRadNalog && this is RNMDUC == false) text = "Datum izrade ugovora:";
      else if(this is BORDUC) text = "Odlazak:";
      else if(this is RNZDUC) text = "Datum od:";
      else if(this is URA_SVD_DUC) text = "DatumRn:";
      else text = "Datum:";


      Label lbl = hamper.CreateVvLabel(0, 0, text, ContentAlignment.MiddleRight);
      tbx_DokDate = hamper.CreateVvTextBox(1, 0, "tbx_dokDate", "Datum dokumenta");
      tbx_DokDate.JAM_IsForDateTimePicker = true;
      dtp_DokDate = hamper.CreateVvDateTimePicker(1, 0, "", tbx_DokDate);
      dtp_DokDate.Name = "dtp_DokDate";
      if(this is RNZDUC == false) tbx_DokDate.JAM_Highlighted = true;

      dtp_DokDate.ValueChanged += new EventHandler(dtp_DokDate_ValueChanged_SetSkladAndPdvDate);

      // 02.05.2016: Try Validate like VvTextBox ___ START ___
      dtp_DokDate.Enter += new EventHandler(dtp_DokDate.OnEnter_BeginEdit);
      dtp_DokDate.Leave += new EventHandler(dtp_DokDate.OnLeave_EndEdit);

      dtp_DokDate.Validating += new CancelEventHandler(dtp_DokDate.EH_JAM_Validating);
      dtp_DokDate.JAM_MustTabOutBeforeSubmit = true;
      // 02.05.2016: Try Validate like VvTextBox ___  END  ___

      if(this is IFADUC ||
         this is IRADUC ||
         this is IRPDUC ||
         this is IRMDUC ||
         this is IRMDUC_2 ||
         this is OdobrKupcuDUC ||
         this is PovratKupcaDUC)
      {
         if(ZXC.IsFikalEra)
         {
            tbx_DokDate.JAM_IsForDateTimePicker_WithTimeDisplay = true;
         }
      }

      if(this is RNZDUC) tbx_DokDate.JAM_IsForDateTimePicker_WithTimeDisplay = true;

      this.ControlForInitialFocus = dtp_DokDate; // ovo je zbog internih fak koji nemaju partnera

   }
   private void InitializeHamper_dokDate2(out VvHamper hamper)
   {
      hamper = new VvHamper(2, 1, "", null, false);

