   private void InitializeHamper_vezniDok(out VvHamper hamper)
   {
      if(this is RNMDUC) hamper = new VvHamper(3, 1, "", null, false);
      else if(this is RNZDUC) hamper = new VvHamper(4, 1, "", null, false);
      else hamper = new VvHamper(2, 1, "", null, false);

      if(this is RNMDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q3un, ZXC.Q7un + ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + faBefCol };
      else if(this is RNZDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q3un, ZXC.Q5un + ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + faBefCol, ZXC.Q2un - faBefCol };
      else if(this is FakturExtDUC ||
              this is PredatUProizDUC ||
              this is PovratInterDUC ||
              this is PIPDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + 2 * faBefCol };
      else hamper.VvColWdt = new int[] { labelWidth, ZXC.Q7un - ZXC.Qun4 };

      if(this is RNMDUC) hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol, faBefCol };
      else if(this is RNZDUC) hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol, faBefCol, faBefCol };
      else hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol };

      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt = new int[] { ZXC.QUN };
      hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      string lblText, statText;

      if(this is FakturExtDUC)
      {
         if(this is BlgUplatDUC || this is BlgUplat_M_DUC) { lblText = "Svrha UPL:"; statText = "Svrha Uplate - Dnevnik Blagajne"; }
         else if(this is RNMDUC) { lblText = "VrstaRNM:"; statText = "Vrsta radnog naloga"; }
         else if(this is BlgIsplatDUC || this is BlgIsplat_M_DUC) { lblText = "Svrha ISP:"; statText = "Svrha Isplate - Dnevnik Blagajne"; }
         else if(IsRadNalog) { lblText = "RefDok:"; statText = "Referentni dokument - ugovor, narudžba ..."; }
         else if(this is IZMDUC_2) { lblText = "Soba:"; statText = "Broj sobe"; }
         else if(this is RNZDUC) { lblText = "VrstaRNZ:"; statText = "Vrsta radnog naloga"; }
         else if(this is UGODUC) { lblText = "Ugovor br:"; statText = "Broj Ugovora"; }
         else { lblText = "OrigBrDok:"; statText = "Vezni dokument - Originlni broj računa dobavljača (kupca)"; }
      }
      else
      {
         if(this is PredatUProizDUC || this is PovratInterDUC || this is PIPDUC) { lblText = "RefDok:"; statText = "Vezni dokument, Zahtjev ..."; }
         else
         {
            lblText = "OrigBr:"; statText = "Vezni dokument - Originlni broj računa dobavljača (kupca)";
         }
      }

      hamper.CreateVvLabel(0, 0, lblText, ContentAlignment.MiddleRight);
      if(this is RNMDUC) // 25.03.2016.
      {
         tbx_VezniDok = hamper.CreateVvTextBoxLookUp(1, 0, "tbx_vezniDok", statText, GetDB_ColumnSize(DB_ci.vezniDok));
         tbx_RNM_vrstaOpis = hamper.CreateVvTextBox(2, 0, "tbx_vrstaRNMopis", "Vrsta RNM opis");
         tbx_VezniDok.JAM_Set_LookUpTable(ZXC.luiListaVrstaRNM, (int)ZXC.Kolona.prva);
         tbx_VezniDok.JAM_lui_NameTaker_JAM_Name = tbx_RNM_vrstaOpis.JAM_Name;
         tbx_RNM_vrstaOpis.JAM_ReadOnly = true;
         tbx_VezniDok.JAM_DataRequired = true;

         tbx_VezniDok.JAM_FieldExitWithValidationMethod += new System.ComponentModel.CancelEventHandler(OnExitRNMkind_SetTtNum);
      }
      else if(this is RNZDUC)
      {
         tbx_VezniDok = hamper.CreateVvTextBoxLookUp(1, 0, "tbx_vezniDok", statText, GetDB_ColumnSize(DB_ci.vezniDok));
         tbx_RNZ_radMjOpis = hamper.CreateVvTextBox(2, 0, "tbx_radMjOpis", "Radno mjesto");
         tbx_RNZ_radMjBroj = hamper.CreateVvTextBox(3, 0, "tbx_radMjBroj", "Radno mjesto");
         //tbx_VezniDok.JAM_lui_NameTaker_JAM_Name    = tbx_RNZ_radMjOpis.JAM_Name;
         //tbx_VezniDok.JAM_lui_IntegerTaker_JAM_Name = tbx_RNZ_radMjBroj.JAM_Name;
         tbx_VezniDok.JAM_ReadOnly = true;
         tbx_RNZ_radMjOpis.JAM_ReadOnly = true;
         tbx_RNZ_radMjBroj.JAM_ReadOnly = true;
      }
      else
      {
         tbx_VezniDok = hamper.CreateVvTextBox(1, 0, "tbx_vezniDok", statText, GetDB_ColumnSize(DB_ci.vezniDok));
      }


      if(this is UFADUC || this is URADUC || this is URPDUC || this is URMDUC || this is UFMDUC || this is KalkulacijaMpDUC || this is KalkulacijaMpDUC_Dev ||
         this is PrimkaVpDUC || this is PRIpDUC || this is BlgIsplatDUC || this is BlgUplatDUC || this is PredatUProizDUC || this is PovratInterDUC || this is KKMDUC ||
         this is OdobrDobavDUC || this is PovratDobaDUC || this is IFADUC || this is BlgIsplat_M_DUC || this is BlgUplat_M_DUC || this is PIPDUC ||
         this is URA_SVD_DUC || this is NRD_SVD_DUC || this is UGODUC

         ) tbx_VezniDok.JAM_IsSupressTab = false;
      else tbx_VezniDok.JAM_IsSupressTab = true;

   }
   private void InitializeHamper_napomena(out VvHamper hamper)
   {
      hamper = new VvHamper(2, 1, "", null, false);

      if(this is FakturExtDUC && this is PIZpDUC == false && this is ProizvodnjaDUC == false)
      {
         if(this is BlgUplatDUC || this is BlgIsplatDUC ||
            this is BlgUplat_M_DUC || this is BlgIsplat_M_DUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.Q2un - 4 * ZXC.Qun8 - 2 * ZXC.Qun8 + 2 * faBefCol };
         else if(this is PIMDUC)                               hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.Q2un - ZXC.Qun2 };
         else if(this is IRMDUC)                               hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.Q2un - ZXC.Qun2 };
         else if(this is PIZpDUC)                              hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un * 2 + ZXC.Q4un + ZXC.Qun8 };
         else if(this is MedjuSkladVMIuDUC || this is MedjuSkladVMI2DUC ||
                 this is MedjuSkladMVIDUC || this is MedjuSkladMVI2DUC ||
                 this is MedjuSkladMMIDUC)                     hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un * 2 + ZXC.Q7un + ZXC.Qun8 };
         else if(this is PocetnoStanjeMPDUC || this is NivelacijaDUC ||
                 this is InventuraMPDUC)                       hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un };
         else if(this is WYRNDUC)                              hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un * 2 + ZXC.Q6un + ZXC.Qun2 };
         else if(this is RNZDUC)                               hamper.VvColWdt = new int[] { labelWidth, hamp_tt.Width - labelWidth - 2 * faBefFirstCol - faBefCol };
         else if(this is URMDUC && IsAutoKucaProjekt)          hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.Q7un - ZXC.Qun2 - ZXC.Qun12 };
         else if(this is ZAH_SVD_DUC)                          hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un * 2 + ZXC.Q6un + ZXC.Q3un + ZXC.Qun12 };
         else if(this is MOD_PTG_DUC)                          hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un * 3 + ZXC.Q4un - ZXC.Qun8 };
         else                                                  hamper.VvColWdt = new int[] { labelWidth, hamp_tt.Width * 3 - labelWidth - faBefFirstCol - faBefCol - ZXC.Qun4 * 3 };
      }
      else if(this is MedjuSkladDUC || this is MedjuSklad2DUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un * 2 + ZXC.Q7un + ZXC.Qun8 };
      else hamper.VvColWdt = new int[] { labelWidth, ZXC.Q10un + ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + 2 * faBefCol };

      hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt = new int[] { ZXC.QUN };
      hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      hamper.CreateVvLabel(0, 0, (this is RNZDUC) ? "" : "Napom:", ContentAlignment.MiddleRight);
      tbx_Napomena = hamper.CreateVvTextBox(1, 0, "tbx_napomena", "Napomena", GetDB_ColumnSize(DB_ci.napomena));
      tbx_Napomena.Font = ZXC.vvFont.SmallFont;
      if(this is RNZDUC) tbx_Napomena.JAM_ReadOnly = true;

   }
