   private void InitializeHamper_projekt(out VvHamper hamper)
   {
      hamper = new VvHamper(4, 1, "", null, false);

      // 29.10.2014. ne treba nam to na VMI/TRI tu ce doci dokDate2
      //if(this is MedjuSkladVMIuDUC || this is TransformDUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q4un + faBefCol - ZXC.Qun4 - ZXC.Qun2, ZXC.Q5un, ZXC.QUN - ZXC.Qun4 };
      /*else*/
      if(this is RNMDUC)
      {
         hamper.VvColWdt = new int[] { ZXC.Q4un, ZXC.Qun10, ZXC.Qun10, ZXC.Qun10 };
         hamper.VvSpcBefCol = new int[] { faBefFirstCol, 0, 0, 0 };
         hamper.VvRightMargin = hamper.VvLeftMargin;

         hamper.VvRowHgt = new int[] { ZXC.QUN };
         hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
         hamper.VvBottomMargin = hamper.VvTopMargin;

         tbx_ProjektCD = hamper.CreateVvTextBox(0, 0, "tbx_Projekt", "Projekt - ", GetDB_ColumnSize(DB_ci.projektCD));
         tbx_ProjektCD.JAM_ReadOnly = true;
         tbx_ProjektCD.Font = ZXC.vvFont.SmallFont;

      }
      else if(this is RNZDUC)
      {
         hamper.VvColWdt = new int[] { ZXC.Q3un - ZXC.Qun4, 0, 0, 0 };
         hamper.VvSpcBefCol = new int[] { faBefFirstCol, 0, 0, 0 };
         hamper.VvRightMargin = hamper.VvLeftMargin;

         hamper.VvRowHgt = new int[] { ZXC.QUN };
         hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
         hamper.VvBottomMargin = hamper.VvTopMargin;

         tbx_ProjektCD = hamper.CreateVvTextBox(0, 0, "tbx_Projekt", "Projekt - ", GetDB_ColumnSize(DB_ci.projektCD));
         tbx_ProjektCD.JAM_ReadOnly = true;
         tbx_ProjektCD.Font = ZXC.vvFont.SmallFont;

      }

      else if(this is URA_SVD_DUC || this is NRD_SVD_DUC || this is IZD_SVD_DUC)
      {
         hamper.VvColWdt = new int[] { labelWidth - ZXC.Qun4 + ZXC.Qun12, ZXC.Q4un + faBefCol + ZXC.Q2un + ZXC.Qun4, ZXC.Q5un, ZXC.QUN - ZXC.Qun4 };
         hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol, faBefCol, 0 };
         hamper.VvRightMargin = hamper.VvLeftMargin;

         hamper.VvRowHgt = new int[] { ZXC.QUN };
         hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
         hamper.VvBottomMargin = hamper.VvTopMargin;

         hamper.CreateVvLabel(0, 0, "Ugovor:", ContentAlignment.MiddleRight);
         tbx_ProjektName = hamper.CreateVvTextBox(1, 0, "tbx_ProjektName", "Ugovor");
         tbx_ProjektName.JAM_ReadOnly = true;
         tbx_ProjektCD = hamper.CreateVvTextBox(2, 0, "tbx_Projekt", "Ugovor - ", GetDB_ColumnSize(DB_ci.projektCD));

         tbx_ProjektCD.JAM_IsSupressTab = true;

         // 10.5.2011: 
         tbx_ProjektCD.JAM_SetAutoCompleteData(Faktur.recordName, Faktur.sorterTtNum.SortType, ZXC.AutoCompleteRestrictor.FAK_ExactTT_Only, new EventHandler(OnVvTBEnter_SetAutocmplt_Faktur_DUMMY), null);

         btn_proj = hamper.CreateVvButton(3, 0, new EventHandler(GoToProjektCD_RISK_Dokument_Click), "");
         btn_proj.Name = "projekt";
         btn_proj.FlatStyle = FlatStyle.Flat;
         btn_proj.FlatAppearance.BorderColor = ZXC.vvColors.userControl_BackColor;
         btn_proj.Image = VvIco.TriangleBlue16/*new Icon((ZXC.TheVvForm.GetManifestResourceStream("Vektor.Icons.ToolStrip_Modul.bullet_triangle_blue2.ico")), 16, 16)*/.ToBitmap();
         btn_proj.Tag = 10;
         btn_proj.TabStop = false;
      }
      else
      {
         hamper.VvColWdt = new int[] { labelWidth, ZXC.Q4un + faBefCol + ZXC.Q3un - ZXC.Qun4 - ZXC.Qun2, ZXC.Q5un - ZXC.Qun10, ZXC.QUN - ZXC.Qun4 };
         hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol, faBefCol, 0 };
         hamper.VvRightMargin = hamper.VvLeftMargin;

