   private void InitializeHamper_opis(out VvHamper hamper)
   {
      if(this is FakturExtDUC && this is PIZpDUC     == false && this is ProizvodnjaDUC  == false && this is RNZDUC == false &&
                                 this is URA_SVD_DUC == false && this is NRD_SVD_DUC     == false && this is IZD_SVD_DUC == false &&
                                 this is UGODUC      == false && this is CjenikKupca_DUC == false && this is ZAH_SVD_DUC == false && this is PST_PTG_DUC == false && this is MSI_PTG_DUC == false)
      {
              if(this is IRMDUC)                   hamper = new VvHamper(1, 3, "", null, false);
         else if(this is KIZDUC || this is PIKDUC) hamper = new VvHamper(1, 5, "", null, false);
         else                                      hamper = new VvHamper(1, 7, "", null, false);

         hamper.VvColWdt      = new int[] { ZXC.Q10un + 2 * faBefCol + ZXC.QUN + ZXC.Qun4 };
         hamper.VvSpcBefCol   = new int[] { faBefFirstCol };
         hamper.VvRightMargin = hamper.VvLeftMargin;

         for(int i = 0; i < hamper.VvNumOfRows; i++)
         {
            hamper.VvRowHgt[i] = ZXC.QUN;
            hamper.VvSpcBefRow[i] = ZXC.Qun8;
         }
         hamper.VvBottomMargin = hamper.VvTopMargin;

         hamper.CreateVvLabel(0, 0, "Opis:", ContentAlignment.MiddleLeft);
              if(this is IRMDUC)                   tbx_Opis = hamper.CreateVvTextBox(0, 1, "tbx_Opis", "Opis - dodatni opis potreban za ispis na računu", GetDB_ColumnSize(DB_ci.opis), 0, 1);
         else if(this is KIZDUC || this is PIKDUC) tbx_Opis = hamper.CreateVvTextBox(0, 1, "tbx_Opis", "Opis - dodatni opis potreban za ispis na računu", GetDB_ColumnSize(DB_ci.opis), 0, 3);
         else                                      tbx_Opis = hamper.CreateVvTextBox(0, 1, "tbx_Opis", "Opis - dodatni opis potreban za ispis na računu", GetDB_ColumnSize(DB_ci.opis), 0, 5);
         tbx_Opis.Font = ZXC.vvFont.SmallFont;
         tbx_Opis.Multiline = true;
         tbx_Opis.ScrollBars = ScrollBars.Both;
      }

      else
      {
         hamper = new VvHamper(2, 1, "", null, false);

         if(this is CjenikDUC) hamper.VvColWdt = new int[] { labelWidth, 2 * ZXC.Q10un + 2 * ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + 2 * faBefCol - ZXC.Qun2 - ZXC.Qun4 + 2 * faBefCol - ZXC.Qun2 + labelWidth };
         else hamper.VvColWdt = new int[] { labelWidth, hamp_tt.Width * 3 - labelWidth - faBefFirstCol - faBefCol - ZXC.Qun4 * 3 };

         hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol };
         hamper.VvRightMargin = hamper.VvLeftMargin;

         for(int i = 0; i < hamper.VvNumOfRows; i++)
         {
            hamper.VvRowHgt[i] = ZXC.QUN;
            hamper.VvSpcBefRow[i] = ZXC.Qun8;
         }
         hamper.VvBottomMargin = hamper.VvTopMargin;

         hamper.CreateVvLabel(0, 0, ((this is RNZDUC) ? "Napom:" : "Opis:"), ContentAlignment.MiddleRight);
         tbx_Opis = hamper.CreateVvTextBox(1, 0, "tbx_Opis", (this is RNZDUC) ? "Napomena:" : "Opis - dodatni opis potreban za ispis na računu", GetDB_ColumnSize(DB_ci.opis));
         if(this is RNZDUC == false) tbx_Opis.Font = ZXC.vvFont.SmallFont;
      }

      hamper.Name = "BOpis:";
   }
   private void InitializeHamper_SukKC_K(out VvHamper hamper)
   {
      bool isFakExt = this is FakturExtDUC;

      if(isFakExt)
      {
         hamper = new VvHamper(3, 2, "", ThePolyGridTabControl.TabPages[0], false);
         hamper.VvColWdt = new int[] { ZXC.Q3un - ZXC.Qun4, ZXC.Q4un, ZXC.Q5un };
         hamper.VvSpcBefCol = new int[] { ZXC.Qun4, ZXC.Qun4, ZXC.Qun4 };
      }
      else
      {
         hamper = new VvHamper(4, 1, "", ThePolyGridTabControl.TabPages[0], false);
         hamper.VvColWdt = new int[] { ZXC.Q3un, ZXC.Q4un, ZXC.Q3un, ZXC.Q4un };
         hamper.VvSpcBefCol = new int[] { ZXC.Qun8, ZXC.Qun8, ZXC.Qun8, ZXC.Qun8 };
      }

      hamper.VvRightMargin = hamper.VvLeftMargin;

      for(int i = 0; i < hamper.VvNumOfRows; i++)
      {
         hamper.VvRowHgt[i] = ZXC.QUN;
         hamper.VvSpcBefRow[i] = ZXC.Qun8;
      }
      hamper.VvBottomMargin = hamper.VvTopMargin;

      hamper.CreateVvLabel(0, 0, "Količina:", ContentAlignment.MiddleRight);
      tbx_S_ukK2 = hamper.CreateVvTextBox(1, 0, "tbx_S_ukK2", "S_ukK2", GetDB_ColumnSize(DB_ci.s_ukK2));
      tbx_S_ukK = hamper.CreateVvTextBox(isFakExt ? 2 : 1, 0, "tbx_S_ukK", "S_ukK", GetDB_ColumnSize(DB_ci.s_ukK));

      hamper.CreateVvLabel(isFakExt ? 1 : 2, isFakExt ? 1 : 0, "KOLxCIJ:", ContentAlignment.MiddleRight);
      tbx_S_ukKC = hamper.CreateVvTextBox(isFakExt ? 2 : 3, isFakExt ? 1 : 0, "tbx_S_ukKC", "S_ukKC", GetDB_ColumnSize(DB_ci.s_ukKC));

      tbx_S_ukK.JAM_MarkAsNumericTextBox(ZXC.RRD.Dsc_KolNumOfDecimalPlaces, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_S_ukK2.JAM_MarkAsNumericTextBox(ZXC.RRD.Dsc_AmbKolNumOfDecimalPlaces, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_S_ukKC.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);

      tbx_S_ukK.JAM_ReadOnly = true;
      tbx_S_ukK2.JAM_ReadOnly = true;
      tbx_S_ukKC.JAM_ReadOnly = true;

      tbx_S_ukK2.Visible = isFakExt;

      hamper.Visible = false;
   }
   private void InitializeHamper_osobaX(out VvHamper hamper)
