   // 28.10.2014: ovo umjesto 'DataGridView_IsProdukt_CellValueChanged' 
   void TheG_IsProdukt_CellLeave_RecalcDUC(object sender, DataGridViewCellEventArgs e)
   {

      // 10.12.2014: 
      if(ZXC.RISK_CopyToOtherDUC_inProgress == true) return; // bez ovoga je PPUK-u pri kopirnju npr. PRI u PUX rikavao u GetDgvLineFields1() 

      if(TheVvTabPage.WriteMode == ZXC.WriteMode.None) return;

      if(TheG.CurrentCell.ColumnIndex != DgvCI.iT_isProductLine) return;

      // here we go ... znaci u 'zutome' smo i u iT_isProductLine koloni 

      int rowIdx = TheG.CurrentRow.Index;

      //VvDataGridView dgv        = sender             as VvDataGridView;
      //VvCheckBox     vvCheckBox = dgv.EditingControl as VvCheckBox    ;
      //if(vvCheckBox == null || dgv.CurrentCell == null) return;

      // 28.04.2016: pokusaj ispravka bug-a da kad udjes u ispravi npr. PIZ-a i samo promjenis Checked ChkBoxa, NE digne se dirty flag ___ START 

      bool isProduktChkBoxChanged = TheG.EditingControl != null && ((VvCheckBoxEditingControl)(TheG.EditingControl)).EditingControlValueChanged;
      if(isProduktChkBoxChanged) TheVvTabPage.TheVvForm.SetDirtyFlag("TheG_IsProdukt_CellLeave_RecalcDUC");

      // 28.04.2016: pokusaj ispravka bug-a da kad udjes u ispravi npr. PIZ-a i samo promjenis Checked ChkBoxa, NE digne se dirty flag ___  END  

      TheG.EndEdit();
      //ZXC.TheVvForm.VvFlag_PretendDgvCurrentCellIsInEditMode = true;

      CheckIsArtiklKindAdequate(rowIdx);

      //ZXC.RISK_PULXPIZX_Calc_InProgress = true;
      //GetLineFlds_CalcTrans_PutLineFlds_PutSumFlds_FOR_ALL_ROWS();
      PutProduktCijenaAndIznos_OR_CheckKOLbalance();
      //ZXC.RISK_PULXPIZX_Calc_InProgress = false;

      // GetPIZ_IntersectTT 
      string errMsg;
      if((errMsg = GetPIZ_IntersectTT()).NotEmpty())
      {
         ZXC.aim_emsg(MessageBoxIcon.Error, "GREŠKA:\n\nDokument sadrži stavku(e) sa DUPLOM ULOGOM!\n\n" + errMsg);
         //e.Cancel = true;
      }
      // GetPIZ_IntersectTT 


      if(TheG.GetStringCell(ci.iT_isProductLine, rowIdx, false) == "X")
      {
         foreach(DataGridViewTextBoxCell tbxCell in TheG.Rows[rowIdx].Cells)
         {
            tbxCell.Style.BackColor = Color.PaleGreen;
         }
      }
      else
      {

         foreach(DataGridViewTextBoxCell tbxCell in TheG.Rows[rowIdx].Cells)
         {
            if(this.TheVvTabPage.WriteMode == ZXC.WriteMode.None) tbxCell.Style.BackColor = ZXC.vvColors.dataGridCellReadOnly_True_BackColor;
            else tbxCell.Style.BackColor = ZXC.vvColors.dataGridCellReadOnly_False_BackColor;
         }
      }

   }

