   void CheckPdvColTipValidity(object sender, System.ComponentModel.CancelEventArgs e)
   {
      if(this.Visible == false) return;

      VvDataGridView dgv = sender as VvDataGridView;
      VvTextBox vvTextBox = dgv.EditingControl as VvTextBox;

      int rowIdx = dgv.CurrentCell.RowIndex;

      ZXC.PdvKolTipEnum pdvColTip = GetPdvKolTipEnumFromFirstLetter(dgv.GetStringCell(ci.iT_pdvKolTip, rowIdx, true));
      decimal pdvStopa = dgv.GetDecimalCell(ci.iT_pdvSt, rowIdx, false, true);

      if(pdvStopa.NotZero())
      {
         if(ZXC.TtInfo(Fld_TT).IsIzlazniPdvTT)
         {
            if(pdvColTip != ZXC.PdvKolTipEnum.NIJE && pdvColTip != ZXC.PdvKolTipEnum.AVANS_STORNO)
            {
               e.Cancel = true;
            }
         }

         if(ZXC.TtInfo(Fld_TT).IsUlazniPdvTT)
         {
            if(pdvColTip == ZXC.PdvKolTipEnum.KOL07 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL08 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL09 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL10 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL11 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL12 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL13 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL14 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL15 ||
               pdvColTip == ZXC.PdvKolTipEnum.KOL16 ||
               pdvColTip == ZXC.PdvKolTipEnum.PROLAZ)
            {
               e.Cancel = true;
            }
         }
      }
      else // pdvStopa IsZero 
      {
         if(ZXC.TtInfo(Fld_TT).IsIzlazniPdvTT)
         {
            if(pdvColTip != ZXC.PdvKolTipEnum.KOL07 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL08 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL09 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL10 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL11 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL12 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL13 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL14 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL15 &&
               pdvColTip != ZXC.PdvKolTipEnum.KOL16 &&
               //15.02.2023
               pdvColTip != ZXC.PdvKolTipEnum.PROLAZ
               )
            {
               if(Fld_TT != Faktur.TT_IRA) // za spec potrebe knjig. servisa cemo dozvoliti praznu PK kolonu i pdvSt 0 
               {
                  e.Cancel = true;
               }
            }
         }

         if(ZXC.TtInfo(Fld_TT).IsUlazniPdvTT)
         {
            if(pdvColTip != ZXC.PdvKolTipEnum.NIJE && pdvColTip != ZXC.PdvKolTipEnum.AVANS_STORNO && pdvColTip != ZXC.PdvKolTipEnum.PROLAZ)
            {
               e.Cancel = true;
            }
         }

      } // else // pdvStopa IsZero  


      if(e.Cancel == true) ZXC.aim_emsg(MessageBoxIcon.Error, "Nekorektna PK kolona.");
   }

