   void CheckPdvStopa(object sender, System.ComponentModel.CancelEventArgs e)
   {
      if(this.Visible == false) return;

      VvDataGridView dgv = sender as VvDataGridView;
      VvTextBox vvTextBox = dgv.EditingControl as VvTextBox;

      int rowIdx = dgv.CurrentCell.RowIndex;

      decimal stopa = ZXC.ValOrZero_Decimal(vvTextBox.Text, 0);

      if(ZXC.VvDeploymentSite == ZXC.VektorSiteEnum.MANDAR)
      {
         if(stopa != 25.00M &&
            stopa != 23.00M &&
            stopa != 22.00M &&
            //stopa != 13.00M &&
            stopa != 10.00M &&
            //stopa !=  5.00M && 
            stopa != 0.00M)
         {
            ZXC.RaiseErrorProvider(vvTextBox, "Pogrešna stopa PDV-a: " + stopa.ToStringVv() + @"%");
            e.Cancel = true;
         }
      }
      else
      {
         if(stopa != 25.00M &&
            stopa != 23.00M &&
            stopa != 22.00M &&
            stopa != 13.00M &&
            stopa != 10.00M &&
            stopa != 5.00M &&
            stopa != 0.00M)
         {
            ZXC.RaiseErrorProvider(vvTextBox, "Pogrešna stopa PDV-a: " + stopa.ToStringVv() + @"%");
            e.Cancel = true;
         }
      }
   }

