   public DateTime Fld_DokDate
   {
      get
      {
         // 17.01.2013: !!! dodan if u pokusaju da DokDate u dataLayer zavrsi sa time komponentom samo gdje treba (IFA, IRA, IRM, ...)
         if(dtp_DokDate.TheVvTextBox.JAM_IsForDateTimePicker_WithTimeDisplay) return dtp_DokDate.Value;
         else                                                                 return dtp_DokDate.Value.Date;
      }
      set
      {
         if(value >= DateTimePicker.MinimumDateTime && value <= DateTimePicker.MaximumDateTime)
         {
            dtp_DokDate.Value = value;
         }
      }
   }
   public DateTime Fld_DokDate2
   {
      get
