         if(dtp_DokDate2.TheVvTextBox.JAM_IsForDateTimePicker_WithTimeDisplay) return dtp_DokDate2.Value     .IsEmpty() ? dtp_DokDate.Value      : dtp_DokDate2.Value     ;
         else                                                                  return dtp_DokDate2.Value.Date.IsEmpty() ? dtp_DokDate.Value.Date : dtp_DokDate2.Value.Date;
      }
      set
      {
         if(value >= DateTimePicker.MinimumDateTime && value <= DateTimePicker.MaximumDateTime)
         {
            dtp_DokDate2.Value = value;
         }
      }
