   public ZXC.MalopCalcKind Fld_MalopCalcKind
   {
      get
      {
         if(rbt_stMarze.Checked) return ZXC.MalopCalcKind.By_MARZA;
         else if(rbt_vpc.Checked) return ZXC.MalopCalcKind.By_VPC;
         else if(rbt_mpc.Checked) return ZXC.MalopCalcKind.By_MPC;

            // 12.10.2016: 
       //else throw new Exception("Fld_MalopCalcKind: who df is checked?");
       ZXC.aim_emsg(MessageBoxIcon.Error, "Fld_MalopCalcKind: who df is checked?");
       return ZXC.MalopCalcKind.By_MPC;
      }
      set
      {
         // dodano tek 17.12.2012: 
         // dohjebano  28.01.2013: 
         if(ZXC.RISK_InitZPCvalues_InProgress == false)
         {
            rbt_stMarze.Checked =
            rbt_vpc.Checked =
            rbt_mpc.Checked = false;
         }

         switch(value)
         {
            case ZXC.MalopCalcKind.By_MARZA: rbt_stMarze.Checked = true; break;
            case ZXC.MalopCalcKind.By_VPC: rbt_vpc.Checked = true; break;
            case ZXC.MalopCalcKind.By_MPC: rbt_mpc.Checked = true; break;
         }

         rbt_stMarze.Tag = rbt_stMarze.Checked; // bez ovoga bi VvHamper.ClearClearFieldContents uvijek postavljao prvi rbt na defaultni 
         rbt_vpc.Tag = rbt_vpc.Checked; // bez ovoga bi VvHamper.ClearClearFieldContents uvijek postavljao prvi rbt na defaultni 
         rbt_mpc.Tag = rbt_mpc.Checked; // bez ovoga bi VvHamper.ClearClearFieldContents uvijek postavljao prvi rbt na defaultni 
      }
   }
   public bool Fld_IsViaRabat
   {
      get
      {
         if(rbt_ciljMPCknjigMPC.Checked) return false;
         else if(rbt_ciljMPCrabat.Checked) return true;

         else throw new Exception("Fld_IsViaRabat: who df is checked?");
         //else return ZXC.MalopCalcKind.By_MARZA;
      }
      set
      {
         if(value == true) rbt_ciljMPCrabat.Checked = true;
         else rbt_ciljMPCknjigMPC.Checked = true;

         rbt_ciljMPCknjigMPC.Tag = rbt_ciljMPCknjigMPC.Checked; // bez ovoga bi VvHamper.ClearClearFieldContents uvijek postavljao prvi rbt na defaultni 
         rbt_ciljMPCrabat.Tag = rbt_ciljMPCrabat.Checked; // bez ovoga bi VvHamper.ClearClearFieldContents uvijek postavljao prvi rbt na defaultni 
      }
   }

