   #region PutFields(), GetFields()

   public override void PutDefaultDUCfields()
   {
      bool ttIsGoodToGo = true;

      if(dbNavigationRestrictor_TT.RestrictedValues[0] != null)
      {
         if(CtrlOK(tbx_TT))
         {
            Fld_TT = dbNavigationRestrictor_TT.RestrictedValues[0];
            tbx_TT.EndEdit(); // Da se digne event OnExitSetLookUp_DataTakers
         }

         VvLookUpItem theLui = ZXC.luiListaFakturType.SingleOrDefault(lui => lui.Cd == Fld_TT);

         if(theLui != null) Fld_TtOpis = theLui.Name;

      }

      TtInfo ttInfo = ZXC.TtInfo(Fld_TT);

      // TODO: !!! ovdje treba ici zadnje koristeno skladiste nesto kao na ArtiklUC-u 
      if(ttInfo.IsSklCdInTtNum ||
         ttInfo.IsArtiklStatusInfluencer ||
         Faktur.IsFiskalDutyTT(Fld_DokDate, Fld_TT) ||
         Fld_TT == Faktur.TT_PON ||
         Fld_TT == Faktur.TT_NRD ||
         Fld_TT == Faktur.TT_MOD ||
         Fld_TT == Faktur.TT_ZAH ||
         Fld_TT == Faktur.TT_PNM)
      {
         if(ZXC.RISK_CopyToOtherDUC_inProgress == false)
         {
            VvLookUpItem theLui;

            if(ttInfo.IsMalopTT && ttInfo.HasTwinTT == false) // TwinTT VMI treba sklCD VPSK a skl2CD MPSK 
            {
               theLui = ZXC.luiListaSkladista.SingleOrDefault(lui => lui.Cd == ZXC.TheVvForm.VvPref.findArtikl.LastUsedSkladCD); // probaj naci lui sa integerom '1' (integer nam je kao intera sifra skladista) 
               if(theLui == null)
               {
                  theLui = ZXC.luiListaSkladista.FirstOrDefault(lui => lui.Flag == true); // probaj naci lui sa mal flagom  
               }
            }
            else // default, velep, VMI, ...
            {
               // 22.02.2013: 
               //theLui = ZXC.luiListaSkladista.SingleOrDefault(lui => lui.Integer == 1); // probaj naci lui sa integerom '1' (integer nam je kao intera sifra skladista) 
               theLui = ZXC.luiListaSkladista.SingleOrDefault(lui => lui.Cd == ZXC.TheVvForm.VvPref.findArtikl.LastUsedSkladCD); // probaj naci lui sa integerom '1' (integer nam je kao intera sifra skladista) 

               // 02.07.2018: SVD-u uvijek '10' 
             //if(theLui == null)
               if(theLui == null || ZXC.IsSvDUH)
               {
                  theLui = ZXC.luiListaSkladista.SingleOrDefault(lui => lui.Integer == 1); // probaj naci lui sa integerom '1' (integer nam je kao intera sifra skladista) 
               }
            }

            if(theLui != null)
            {
               Fld_SkladCD = theLui.Cd;
               Fld_SkladOpis = theLui.Name;
               // 18.03.2014: Komisija News
               //Fld_SkladBR = (uint)theLui.Integer;
               if(ZXC.IsOPPsljednost(Fld_TT, theLui.Uinteger))
               {
                  Fld_SkladBR = theLui.Uinteger;
               }
               else
               {
                  Fld_SkladBR = (uint)theLui.Integer;
               }

               if(ttInfo.HasSplitTT) // Proizvodnja 
               {
                  Fld_SkladCD2 = theLui.Cd;
                  Fld_Sklad2Opis = theLui.Name;
                  Fld_SkladBR2 = (uint)theLui.Integer;
               }
               else if(ttInfo.HasTwinTT) // Meduskladisnica, Komisija, VMI 
               {
                  if(ttInfo.TheTT == Faktur.TT_VMI /*IsMalopTT*/) // VMI 
                  {
                     theLui = ZXC.luiListaSkladista.FirstOrDefault(lui => lui.Flag == true); // probaj naci lui sa mal flagom  
                  }
                  else if(ttInfo.TheTT == Faktur.TT_MSI)
                  {
                     theLui = ZXC.luiListaSkladista.SingleOrDefault(lui => lui.Integer == 2); // probaj naci lui sa integerom '2' (integer nam je kao intera sifra skladista) 
                  }
                  else if(ttInfo.TheTT == Faktur.TT_PIK)
                  {
                     theLui = ZXC.luiListaSkladista.SingleOrDefault(lui => lui.Integer == 1); // probaj naci lui sa integerom '1' (integer nam je kao intera sifra skladista) 
                  }
                  else if(ttInfo.TheTT == Faktur.TT_KIZ)
                  {
                     theLui = ZXC.luiListaSkladista.OrderBy(l => l.Integer).FirstOrDefault(lui => lui.Integer > 10); // Komisijska skladista idu 11 - 99 
                  }

                  if(theLui != null) // Set SkladCD2 data 
                  {
                     Fld_SkladCD2 = theLui.Cd;
                     Fld_Sklad2Opis = theLui.Name;
                     Fld_SkladBR2 = (uint)theLui.Integer;

                     if(ttInfo.TheTT == Faktur.TT_KIZ) // Set Komisija Partner
                     {
                        oldSkladCD2 = "";
                        OnExitSkladCD2_SetKomisijaPartner(tbx_Sklad2Cd, new CancelEventArgs());
                        this.originalText = (this as FakturExtDUC).Fld_KupdobName; // da ne radi probleme tam... 
                     }
                  }

               }

            }
            else ttIsGoodToGo = false;

            // 23.10.2014: 
            if(ZXC.IsTEXTHOany)
            {
               VvLookUpItem THskladCD1lui = GetTHskladCD1lui();

               if(THskladCD1lui != null)
               {
                  Fld_SkladCD = THskladCD1lui.Cd;
                  Fld_SkladOpis = THskladCD1lui.Name;
                  Fld_SkladBR = (uint)THskladCD1lui.Integer;
               }

               VvLookUpItem THskladCD2lui = GetTHskladCD2lui();
               if(THskladCD2lui != null)
               {
                  Fld_SkladCD2 = THskladCD2lui.Cd;
                  Fld_Sklad2Opis = THskladCD2lui.Name;
                  Fld_SkladBR2 = (uint)THskladCD2lui.Integer;
               }

               if(this is IRMDUC)
               {
                  // THPR news: 
                //ZXC.TH_CycleMoment         TH_CycleMoment = ZXC.Get_TH_CycleMoment(/*Fld_DokDate*/DateTime.Now, ZXC.IsTH_5WeekShop(Fld_SkladCD), Fld_SkladCD);
                  TH_PriceRuleForCycleMoment theTHPR        = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay(Fld_SkladCD, DateTime.Now);

                  if(theTHPR != null)
                  {
                     irmInfoLabel.Text = theTHPR.Opis;

                     if(theTHPR.HHpercent.NotZero())
                     {
                        hamp_HappyHour.Visible = true;
                     }
                     else
                     {
                        hamp_HappyHour.Visible = false;
                     }
                  } // if(theTHPR != null)
               } // if(this is IRMDUC) 

               ttIsGoodToGo = true;

            } // if(ZXC.IsTEXTHOany)

            //04.12.2019.
            if(ZXC.IsSvDUH && Fld_TT == Faktur.TT_PIZ)
            {
               // 09.12.2019: privremeno vracamo na "10" jer na 77 nemaju nista a od nove godine ca sa 77 
             //VvLookUpItem luiSklad1 = ZXC.luiListaSkladista.GetLuiForThisCd("77");
               VvLookUpItem luiSklad1 = ZXC.luiListaSkladista.GetLuiForThisCd("10");
               VvLookUpItem luiSklad2 = ZXC.luiListaSkladista.GetLuiForThisCd("10");

               Fld_SkladCD    = luiSklad1.Cd;
               Fld_SkladOpis  = luiSklad1.Name;
               Fld_SkladBR    = (uint)luiSklad1.Integer;

               Fld_SkladCD2   = luiSklad2.Cd;
               Fld_Sklad2Opis = luiSklad2.Name;
               Fld_SkladBR2   = (uint)luiSklad2.Integer;
            }

            if(ZXC.IsPCTOGO)
            {
               VvLookUpItem luiSkladZNJ = ZXC.luiListaSkladista.GetLuiForThisCd("ZNJ");
               VvLookUpItem luiSkladUNJ = ZXC.luiListaSkladista.GetLuiForThisCd("UNJ");

               if(luiSkladZNJ != null && (Fld_TT == Faktur.TT_UGN || Fld_TT == Faktur.TT_AUN || Fld_TT == Faktur.TT_DOD || Fld_TT == Faktur.TT_MOD))
               {
                  Fld_SkladCD    =       luiSkladZNJ.Cd     ;
                  Fld_SkladOpis  =       luiSkladZNJ.Name   ;
                  Fld_SkladBR    = (uint)luiSkladZNJ.Integer;
               }
               if(luiSkladZNJ != null && (Fld_TT == Faktur.TT_PVR))
               {
                  Fld_SkladCD2   =       luiSkladZNJ.Cd     ;
                  Fld_Sklad2Opis =       luiSkladZNJ.Name   ;
                  Fld_SkladBR2   = (uint)luiSkladZNJ.Integer;
               }

               if(luiSkladUNJ != null && (Fld_TT == Faktur.TT_UGN || Fld_TT == Faktur.TT_AUN || Fld_TT == Faktur.TT_DOD))
               {
                  Fld_SkladCD2   =       luiSkladUNJ.Cd     ;
                  Fld_Sklad2Opis =       luiSkladUNJ.Name   ;
                  Fld_SkladBR2   = (uint)luiSkladUNJ.Integer;
               }
               if(luiSkladUNJ != null && (Fld_TT == Faktur.TT_PVR))
               {
                  Fld_SkladCD    =       luiSkladUNJ.Cd     ;
                  Fld_SkladOpis  =       luiSkladUNJ.Name   ;
                  Fld_SkladBR    = (uint)luiSkladUNJ.Integer;
               }

            } //if(ZXC.IsPCTOGO) 

         } // if(ZXC.RISK_CopyToOtherDUC_inProgress == false) 
      }

      bool isCentToCentMSI = (this is MedjuSkladDUC) &&
                             Fld_SkladCD.StartsWith(ZXC.vvDB_ServerID_CENTRALA.ToString("00")) &&
                             Fld_SkladCD2.StartsWith(ZXC.vvDB_ServerID_CENTRALA.ToString("00"));

      string skladCD4_ttNum = GetSkladCD4_ttNum(/*out isSkladCD2*/); // 12.12.2014: Logika za slijednost brojeva: vidi komentar kod GetSkladCD4_ttNum() 

      // 26.03.2016: eventualRNMkind start 
      if(this is RNMDUC)
      {
         string defaultRNMkindCD, defaultRNMkindName;

         VvLookUpItem lui = ZXC.luiListaVrstaRNM.FirstOrDefault();
         if(lui != null) { defaultRNMkindCD = lui.Cd; defaultRNMkindName = lui.Name; }
         else            { defaultRNMkindCD =         defaultRNMkindName = ""      ; }

         Fld_VezniDok      = defaultRNMkindCD;
         Fld_VezniDok_Opis = defaultRNMkindName;
      }
      if(this is RNZDUC && Fld_VezniDok.IsEmpty())
      {
         string defaultRNZkindCD, defaultRNZkindName;
         int    defaultRNZkindNum;

         VvLookUpItem lui = ZXC.luiListaRadnoMjesto.FirstOrDefault();
         if(lui != null) { defaultRNZkindCD = lui.Cd; defaultRNZkindName = lui.Name; defaultRNZkindNum = lui.Integer; }
         else            { defaultRNZkindCD =         defaultRNZkindName = ""      ; defaultRNZkindNum = 0          ; }

         Fld_VezniDok             = defaultRNZkindCD  ;
         Fld_RNZ_RadnoMjesto_Opis = defaultRNZkindName;
         Fld_RNZ_RadnoMjesto_Broj = defaultRNZkindNum ;
      }
    //string vezniDokAsRNMkind = (this is RNMDUC                   ? Fld_VezniDok      : "");
      string vezniDokAsRNMkind = (this is RNMDUC || this is RNZDUC ? Fld_VezniDok      : "");
      int    eventualRNZmonth  = (                  this is RNZDUC ? Fld_DokDate.Month :  0);
      // 26.03.2016: eventualRNMkind end 

      #region PTG news

      // 13.07.2021: 
      uint KUGnum      = 0;
      uint UGNorAUNnum = 0;
      if(this is UGNorAUN_PTG_DUC || // nijedan PTG DUC ne treba ove stvari 
         this is KUG_PTG_DUC ||
         this is DOD_PTG_DUC ||
         this is MOD_PTG_DUC
         )
      {
         skladCD4_ttNum    =    ""; 
         isCentToCentMSI   = false; 
         vezniDokAsRNMkind =    ""; 
         eventualRNZmonth  =     0;              
      }

      if(this is    ANU_PTG_DUC || // Aneksi i Dodaci i KOP trebaju svoj KUGnum 
         this is A1_ANU_PTG_DUC || 
         this is    DOD_PTG_DUC //||
       //this is    KOP_PTG_DUC
         )
      {
         KUGnum = Fld_V1_ttNum = ZXC.FakturRec.V1_ttNum;
      }

      if(this is DOD_PTG_DUC /*|| this is KOP_PTG_DUC*/) // Dodatak DUC treba jos i UGNorAUNnum 
      {
         UGNorAUNnum = Fld_V2_ttNum = ZXC.FakturRec.V2_ttNum;
      }

      if(this is ANU_PTG_DUC) // Aneksi trebaju svoj KUG_KupdobTK (u 'konto') 
      {
         Fld_Konto = ZXC.FakturRec.KupdobTK;
      }

      if(this is ZAH_SVD_DUC) 
      {
         skladCD4_ttNum = ZXC.CURR_userName;
      }

      #endregion PTG news

      // 09.10.2017: 
    //if(ttIsGoodToGo) Put_NewTT_Num(TheVvDao.GetNextTtNum(TheDbConnection, Fld_TT, /*Fld_SkladCD*/skladCD4_ttNum/*, isSkladCD2*/, isCentToCentMSI, vezniDokAsRNMkind                                       ));
      // PTG news:                                                                                                                                                                                             
    //if(ttIsGoodToGo) Put_NewTT_Num(TheVvDao.GetNextTtNum(TheDbConnection, Fld_TT, /*Fld_SkladCD*/skladCD4_ttNum/*, isSkladCD2*/, isCentToCentMSI, vezniDokAsRNMkind, eventualRNZmonth                     ));
      if(ttIsGoodToGo) Put_NewTT_Num(TheVvDao.GetNextTtNum(TheDbConnection, Fld_TT, /*Fld_SkladCD*/skladCD4_ttNum/*, isSkladCD2*/, isCentToCentMSI, vezniDokAsRNMkind, eventualRNZmonth, KUGnum, UGNorAUNnum));

      SetDefaulFakExDucFields();
   }

   private VvLookUpItem GetTHskladCD1lui()
   {
      string vvDB_ServerID_skl1 = ZXC.vvDB_ServerID.ToString("00");

      string sklCdRoot = vvDB_ServerID_skl1 + (IsSkl_1_malop ? "M" : "B");

      if(this is MedjuSkladDUC && (this is MedjuSklad2DUC == false) ||
         this is PrimkaDevDUC      ||
         this is ProizvodnjaDUC    ||
         this is MedjuSkladVMIuDUC ||
         this is MedjuSkladVMI2DUC) // 12BGS ... we want ... osim kada je ProizvodnjaDUC tada 12BPS i 27.04.2018. za MedjuSkladVMI2DUC isto skald povrata
      {
         vvDB_ServerID_skl1 = ZXC.vvDB_ServerID_CENTRALA.ToString("00");

       //27.04.2018.
       //sklCdRoot = vvDB_ServerID_skl1 + (IsSkl_1_malop ? "M" : "B") + (this is ProizvodnjaDUC                                ? "P" : "G");
         sklCdRoot = vvDB_ServerID_skl1 + (IsSkl_1_malop ? "M" : "B") + ((this is ProizvodnjaDUC || this is MedjuSkladVMI2DUC) ? "P" : "G");

         // 05.02.2015: 
         if(!ZXC.IsTEXTHOcentrala && ZXC.GetTEXTHO_Regija(/*Fld_SkladCD*/ZXC.vvDB_ServerID) == 1) sklCdRoot += "S";
         if(!ZXC.IsTEXTHOcentrala && ZXC.GetTEXTHO_Regija(/*Fld_SkladCD*/ZXC.vvDB_ServerID) == 2) sklCdRoot += "2";

      }

      VvLookUpItem lui = ZXC.luiListaSkladista./*Single*/FirstOrDefault(l => l.Cd.StartsWith(sklCdRoot));

      if(lui == null) { ZXC.aim_emsg(MessageBoxIcon.Error, "sklCdRoot [" + sklCdRoot + "] UNDEFINED in luiListaSkladista!"); return null; }

      return lui;
   }

   private VvLookUpItem GetTHskladCD2lui()
   {
      if(DoesSkl_2_exists == false) return null;

      string vvDB_ServerID_skl2 = ZXC.vvDB_ServerID.ToString("00");

      string sklCdRoot = vvDB_ServerID_skl2 + (IsSkl_2_malop ? "M" : "B");

      // 11.09.2015: 
      //if(this is MedjuSklad2DUC || this is MedjuSkladMVIDUC || this is ProizvodnjaDUC                             ) // 12BPS ... we want ... osim kada je MedjuSklad2DUC tada 12BGS 
      if(this is MedjuSklad2DUC || this is MedjuSkladMVIDUC || this is ProizvodnjaDUC || this is MedjuSkladMVI2DUC) // 12BPS ... we want ... osim kada je MedjuSklad2DUC tada 12BGS 
      {
         vvDB_ServerID_skl2 = ZXC.vvDB_ServerID_CENTRALA.ToString("00");

         // 11.09.2015: 
         //sklCdRoot = vvDB_ServerID_skl2 + (IsSkl_2_malop ? "M" : "B") + ((this is MedjuSklad2DUC                             ) ? "G" : "P");
         sklCdRoot = vvDB_ServerID_skl2 + (IsSkl_2_malop ? "M" : "B") + ((this is MedjuSklad2DUC || this is MedjuSkladMVI2DUC) ? "G" : "P");

         // 05.02.2015: 
         if(!ZXC.IsTEXTHOcentrala && ZXC.GetTEXTHO_Regija(/*Fld_SkladCD2*/ ZXC.vvDB_ServerID) == 1) sklCdRoot += "S";
         if(!ZXC.IsTEXTHOcentrala && ZXC.GetTEXTHO_Regija(/*Fld_SkladCD2*/ ZXC.vvDB_ServerID) == 2) sklCdRoot += "2";
      }

      VvLookUpItem lui = ZXC.luiListaSkladista./*Single*/FirstOrDefault(l => l.Cd.StartsWith(sklCdRoot));

      if(lui == null) { ZXC.aim_emsg(MessageBoxIcon.Error, "sklCdRoot [" + sklCdRoot + "] UNDEFINED in luiListaSkladista!"); return null; }

      return lui;
   }

   public override void PutFields(VvDataRecord _faktur)
   {
      #region ToggleDeviza Additions

      TheVvTabPage.TheVvForm.ToggleDevizaVisualApperiance(false, "", "");
      this.IsShowingConvertedMoney = false;

      Fld_ShowInValutaLookUp = ZXC.ValutaNameEnum.EMPTY;

      #endregion ToggleDeviza Additions

      PutFields(_faktur, false);

      #region ToggleDeviza Additions

      if(this is FakturExtDUC &&
         ((Faktur)_faktur).DevName.NotEmpty() &&
         ((Faktur)_faktur).DevName != /*ZXC.ValutaNameEnum.HRK*/ZXC.EURorHRK_NameEnum.ToString())

         TheVvTabPage.TheVvForm.RISK_ToggleKnDeviza(null, EventArgs.Empty);

      #endregion ToggleDeviza Additions

   }

   public override void PutFields(VvDataRecord _faktur, bool isCopyingToAnotherDUC)
   {
      // 15.02.2015: dodan ovdje na vrh: 
      SetSifrarAndAutocomplete<Artikl>(null, VvSQL.SorterType.None);

      Faktur fakturLocal_rec = (Faktur)_faktur;

      faktur_rec.TakeTransesFrom (fakturLocal_rec);
      faktur_rec.TakeTransesFrom2(fakturLocal_rec);
      faktur_rec.TakeTransesFrom3(fakturLocal_rec);

      bool IsShowingConvertedMoney_BUG_Repair_InProgress = false; // ShowingConvertedMoney_BUG_Repair 

      if(fakturLocal_rec != null)
      {
         #region ShowingConvertedMoney_BUG_Repair

         // new order 2023: !!! 
         // Mijenjamo logiku 'VvCurrency'  pri odlasku u 'zeleno' tj prikazivanja konvertirane NON data layer vrijednosti                   
         // necemo vise jedan po jedan novcani iznos (cijena, ukupno, ...) konvertirati nego cemo samo cijenu, pa pozvati calc svega nanovo 
         if(IsShowingConvertedMoney) // ShowingConvertedMoney_BUG_Repair 
         {
            IsShowingConvertedMoney_BUG_Repair_InProgress = true;

            fakturLocal_rec.Transes.ForEach(rtr => 
               { 
                  rtr.T_cij = VvCurrency(rtr.T_cij);

                  rtr.CalcTransResults(null); 
               } 
            );

            fakturLocal_rec.TakeTransesSumToDokumentSum(true);

            IsShowingConvertedMoney = false; // privremeno! 
         }

         #endregion ShowingConvertedMoney_BUG_Repair

         // 23.01.2018: 
         //if(ZXC.IsTEXTHOany                  )
         if(ZXC.IsTEXTHOany && this is IRMDUC)
         {
            // THPR news: 
            TH_PriceRuleForCycleMoment theTHPR = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay(fakturLocal_rec.SkladCD, fakturLocal_rec.DokDate);
            if(theTHPR != null)
            {
               irmInfoLabel.Text = theTHPR.Opis;
            }
         }

         PutMetaFileds(fakturLocal_rec.AddUID, fakturLocal_rec.AddTS, fakturLocal_rec.ModUID, fakturLocal_rec.ModTS, fakturLocal_rec.RecID, fakturLocal_rec.LanSrvID, fakturLocal_rec.LanRecID);

         PutIdentityFields(fakturLocal_rec.TT + "-" + fakturLocal_rec.TtNum.ToString(/*"000000"*/), fakturLocal_rec.DokDate.ToString(ZXC.VvDateFormat), "", "");

         // 17.12.2012: dodao if() 
         if(ZXC.RISK_ToggleKnDeviza_InProgress == false) VvHamper.SetChkBoxRadBttnAutoCheck(this, true);

         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_DokNum)) Fld_DokNum   = fakturLocal_rec.DokNum;
         if(CtrlOK(tbx_DokDate))   Fld_DokDate  = fakturLocal_rec.DokDate;
         if(CtrlOK(tbx_DokDate2))  Fld_DokDate2 = fakturLocal_rec.DokDate2;

         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_TT))     Fld_TT = fakturLocal_rec.TT;

         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_TtNum)) Fld_TtNum    = fakturLocal_rec.TtNum;
         if(CtrlOK(tbx_SkladCd))  Fld_SkladCD  = fakturLocal_rec.SkladCD;
         if(CtrlOK(tbx_VezniDok)) Fld_VezniDok = fakturLocal_rec.VezniDok;
         if(CtrlOK(tbx_Napomena)) Fld_Napomena = fakturLocal_rec.Napomena;

         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_TtOpis  )) Fld_TtOpis      = fakturLocal_rec.TTopis    /*ZXC.luiListaFakturType.GetNameForThisCd(fakturLocal_rec.TT)*/;
         if(CtrlOK(tbx_SkladOpis  )) Fld_SkladOpis   = fakturLocal_rec.SkladName /*ZXC.luiListaSkladista.GetNameForThisCd(fakturLocal_rec.SkladCD)*/;
         if(CtrlOK(tbx_Konto      )) Fld_Konto       = fakturLocal_rec.Konto;
         if(CtrlOK(tbx_Sklad2Cd   )) Fld_SkladCD2    = fakturLocal_rec.SkladCD2;
         if(CtrlOK(tbx_Sklad2Opis )) Fld_Sklad2Opis  = fakturLocal_rec.Sklad2Name /*ZXC.luiListaSkladista.GetNameForThisCd(fakturLocal_rec.SkladCD2)*/;
         if(CtrlOK(tbx_Opis       )) Fld_Opis        = fakturLocal_rec.Opis;
         if(CtrlOK(tbx_ProjektCD  )) Fld_ProjektCD   = fakturLocal_rec.ProjektCD;
         if(CtrlOK(tbx_ProjektName)) Fld_ProjektName = GetProjektName_ForTtTtNum(fakturLocal_rec.ProjektCD);
         if(CtrlOK(tbx_osobaX     )) Fld_OsobaX      = fakturLocal_rec.OsobaX;

         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_v1_tt    )) Fld_V1_tt     = fakturLocal_rec.V1_tt;
         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_v1_ttOpis)) Fld_V1_ttOpis = ZXC.luiListaFakturType.GetNameForThisCd(fakturLocal_rec.V1_tt);
         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_v1_ttNum )) Fld_V1_ttNum  = fakturLocal_rec.V1_ttNum;

         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_v2_tt    )) Fld_V2_tt     = fakturLocal_rec.V2_tt;
         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_v2_ttOpis)) Fld_V2_ttOpis = ZXC.luiListaFakturType.GetNameForThisCd(fakturLocal_rec.V2_tt);
         if(!isCopyingToAnotherDUC)
            if(CtrlOK(tbx_v2_ttNum )) Fld_V2_ttNum  = fakturLocal_rec.V2_ttNum;

         if(CtrlOK(tbx_S_ukK )) Fld_S_ukK  =           (fakturLocal_rec.S_ukK);
         if(CtrlOK(tbx_S_ukK2)) Fld_S_ukK2 =           (fakturLocal_rec.S_ukK2);
         if(CtrlOK(tbx_S_ukKC)) Fld_S_ukKC = VvCurrency(fakturLocal_rec.S_ukKC);

         if(CtrlOK(tbx_twinS_ukKC)) Fld_TwinS_ukKC = VvCurrency(fakturLocal_rec.S_ukKC);

         if(CtrlOK(tbx_S_ukCount )) Fld_S_ukCount = fakturLocal_rec.S_ukTrnCount;

         if(CtrlOK(tbx_prjIdent))
         {
            fakturLocal_rec.prjFaktur_rec_LOADED = false;

            Fld_PrjIdent = fakturLocal_rec.ProjektIdent1;
         }


         Fld_DevTecaj = fakturLocal_rec.DevTecaj.ToString();

         if(CtrlOK(tbx_decimal01)) Fld_Decimal01 = fakturLocal_rec.Decimal01;
         if(CtrlOK(tbx_decimal02)) Fld_Decimal02 = fakturLocal_rec.Decimal02;

         //25.03.2016.
         if(this is RNMDUC) if(CtrlOK(tbx_VezniDok)) Fld_VezniDok_Opis = ZXC.luiListaVrstaRNM.GetNameForThisCd(fakturLocal_rec.VezniDok);

         // 09.10.2017: 
         if(this is RNZDUC)
         {
            if(CtrlOK(tbx_VezniDok))
            {
               #region Radno mjesto - Vrsta RNZ

               VvLookUpItem radnoMjestoLUI = ZXC.luiListaRadnoMjesto.GetLuiForThisCd(fakturLocal_rec.VezniDok);
               if(radnoMjestoLUI != null)
               {
                //Fld_VezniDok             = radnoMjestoLUI.Cd     ;
                  Fld_RNZ_RadnoMjesto_Opis = radnoMjestoLUI.Name   ;
                  Fld_RNZ_RadnoMjesto_Broj = radnoMjestoLUI.Integer;
               }
               else
               {
                  Fld_VezniDok             = "";
                  Fld_RNZ_RadnoMjesto_Opis = "";
                  Fld_RNZ_RadnoMjesto_Broj =  0;
               }

               #endregion Radno mjesto - Vrsta RNZ
            }
         }

         // 07.03.2018: 
         if(this is IRMDUC && ZXC.IsTEXTHOany)
         {
            if(fakturLocal_rec.IsTextho_IRM_KPN_Izdan)      (this as IRMDUC).lbl_kpnOut1.Text = "IZDAN JE"  ;
            else                                            (this as IRMDUC).lbl_kpnOut1.Text = "NIJE IZDAN";

            if(fakturLocal_rec.IsTextho_IRM_KPN_Zaprimljen) (this as IRMDUC).lbl_kpnIn1.Text = "ZAPRIMLJEN" ;
            else                                            (this as IRMDUC).lbl_kpnIn1.Text = "";
         }
         //= Fld_SkladBR === start =================================================================== 
         uint sklBR;
         VvLookUpItem lui = ZXC.luiListaSkladista.GetLuiForThisCd(fakturLocal_rec.SkladCD);
         if(lui != null)
         {
            // 18.03.2014: Komisija News
            //sklBR = (uint)lui.Integer;
            if(ZXC.IsOPPsljednost(fakturLocal_rec.TT, lui.Uinteger))
            {
               sklBR = lui.Uinteger;
            }
            else
            {
               sklBR = (uint)lui.Integer;
            }
         }
         else
         {
            sklBR = 0;
         }
         if(CtrlOK(tbx_SkladBR)) Fld_SkladBR = sklBR;
         //= Fld_SkladBR === end ===================================================================== 

         //= Fld_SkladBR2 === start ================================================================== 
         lui = ZXC.luiListaSkladista.GetLuiForThisCd(fakturLocal_rec.SkladCD2);
         if(lui != null) sklBR = (uint)lui.Integer;
         else sklBR = 0;
         if(CtrlOK(tbx_SkladRbr2)) Fld_SkladBR2 = sklBR;
         //= Fld_SkladBR2 === end ==================================================================== 

         AddToolTipToTbx();

         #region isCopyingToAnotherDUC == true ... postavi Vx_tt & Vx_ttNum da znamo odkuda je kopirano u ovo

         if(isCopyingToAnotherDUC)
         {
            SetVezaFields(fakturLocal_rec);
         }

         #endregion isCopyingToAnotherDUC == true ... postavi Vx_tt & Vx_ttNum da znamo odkuda je kopirano u ovo

         if(fakturLocal_rec.IsExtendable) PutExtFields(fakturLocal_rec/*.TheEx*/, isCopyingToAnotherDUC);

         // 15.02.2017: BIG NEWS prebacio ovaj 'DecideIfShouldLoad_RNMgrid' prije PutDgvFieldsa() 
         realizacRrtransesLoaded = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable
         IfShould_Load_RealizacGrid(null, null, null);

         PutDgvFields();

         PTG_OplLoaded             = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable 
         PTG_DOD_Grid_Loaded       = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable 
         PTG_Una_Ana_Loaded        = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable 
         PTG_Una_Sin_Loaded        = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable 
         PTG_DOD_rtransList_Loaded = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable 
         IfShould_Load_PTG_OPL_Grid(null, null, null);
         IfShould_Load_PTG_DOD_Grid(null, null, null);
         IfShould_Load_PTG_UNA_ANA_Grid(null, null, null);
         IfShould_Load_PTG_UNA_SIN_Grid(null, null, null);

         // 13.09.2021: start za PTG ove kompozitne TtNum-ove stavljamo sami u sebe svoje baze kakve su i dalje u sljedbenicima - ovisnicima (u istim tim V1/V2 poljima) 
         if(faktur_rec.TT == Faktur.TT_KUG && faktur_rec.V1_ttNum != faktur_rec.TtNum                                     ) ZXC.aim_emsg(MessageBoxIcon.Warning, "faktur_rec.V1_ttNum != faktur_rec.TtNum                                     ");
         if(faktur_rec.TT == Faktur.TT_UGN && faktur_rec.V2_ttNum != faktur_rec.TtNum                                     ) ZXC.aim_emsg(MessageBoxIcon.Warning, "faktur_rec.V2_ttNum != faktur_rec.TtNum                                     ");
         if(faktur_rec.TT == Faktur.TT_AUN && faktur_rec.V2_ttNum != ZXC.GetDesnoOdZareza_asUint(faktur_rec.TtNum, 100000)) ZXC.aim_emsg(MessageBoxIcon.Warning, "faktur_rec.V2_ttNum != ZXC.GetDesnoOdZareza_asUint(faktur_rec.TtNum, 100000)");
         // 13.09.2021:  end  

         //PutDgvFields();

         // 03.02.2012:
         if(fakturLocal_rec.IsExtendable) PutExtFields_RUC_Values(fakturLocal_rec);

         if(ZXC.RISK_ToggleKnDeviza_InProgress == false) VvHamper.SetChkBoxRadBttnAutoCheck(this, false);

         InitializeFilterUCFields();

         recordReportLoaded = false;
         DecideIfShouldLoad_VvReport(null, null, null);

         SetWarningColorsAndLabel();

         #region ShowingConvertedMoney_BUG_Repair

         if(IsShowingConvertedMoney_BUG_Repair_InProgress) // ShowingConvertedMoney_BUG_Repair 
         {
            fakturLocal_rec.Transes.ForEach(rtr => 
               { 
                //rtr.T_cij = VvCurrency(rtr.T_cij); 
                  rtr.T_cij =           (rtr.T_cij * DevTecaj); 
                  rtr.CalcTransResults(null); 
               } 
            );

            fakturLocal_rec.TakeTransesSumToDokumentSum(true);

            IsShowingConvertedMoney = true; // vrati na true 
         }

         #endregion ShowingConvertedMoney_BUG_Repair

      }

      TheG.ClearSelection();
      TheSumGrid.ClearSelection();

      // 01.08.2023: 
      if(this is FakturPDUC)
      {
         TheG2.ClearSelection();
         TheSumGrid2.ClearSelection();

      }

      ftransesLoaded = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable
      DecideIfShouldLoad_TransDGV(null, null, null);

      // 15.02.2017: BIG NEWS prebacio prije PutDgvFieldsa() 
    //RNM_rtransesLoaded = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable
    //DecideIfShouldLoad_RNMgrid(null, null, null);

      fakLinkLoaded = false; // ovdje treba nulirati sve postojece 'xyLoaded' varijable
      DecideIfShouldLoad_FakLinkgrid(null, null, null);

   }

   private string GetProjektName_ForTtTtNum(string ttTtNum)
   {
      string tt;
      uint ttNum;

      Ftrans.ParseTipBr(ttTtNum, out tt, out ttNum);

      if(tt.IsEmpty()) return "";

      VvLookUpItem theLui = ZXC.luiListaFakturType.SingleOrDefault(lui => lui.Cd == tt);

      if(theLui == null) return "";

      return theLui.Name;
   }

   public override void SetWarningColorsAndLabel()
   {
      if(this is MOD_PTG_DUC) return;

      #region Set Warning Colors And Label

      if(faktur_rec.Napomena.NullSafe().ToUpper().Contains("STORNO")) // daj STORNO BOJE i labelu
      {
         TheVvTabPage.labDeviza.Visible = true;
         TheVvTabPage.labDeviza.Text = "STORNO";
         TheVvTabPage.labDeviza.ForeColor = Color.Red;
         TheVvTabPage.TamponPanel_Header.BackColor = Color.Black;

         if(this.IsShowingConvertedMoney) TheVvTabPage.TamponPanel_Footer.BackColor = Color.GreenYellow;
         else TheVvTabPage.TamponPanel_Footer.BackColor = ZXC.vvColors.tamponPanel_BackColor;
      }
      //else if(faktur_rec.Has_TrnSum_vs_S_Sum_Discrepancy().NotEmpty()) // daj nejednake sume boje i labelu 
      else if(faktur_rec.Has_TrnSum_vs_S_Sum_Discrepancy.NotEmpty()) // daj nejednake sume boje i labelu 
      {
         string preffix = TheVvTabPage.TheVvForm.Width > 1280 ? "1RAZLIKA SUMA: " : "";

         TheVvTabPage.labDeviza.Visible = true;
         //TheVvTabPage.labDeviza.Text = preffix + faktur_rec.Has_TrnSum_vs_S_Sum_Discrepancy();
         TheVvTabPage.labDeviza.Text = preffix + faktur_rec.Has_TrnSum_vs_S_Sum_Discrepancy;
         TheVvTabPage.labDeviza.ForeColor = Color.Black;
         TheVvTabPage.TamponPanel_Header.BackColor = Color.Red;

         if(this.IsShowingConvertedMoney) TheVvTabPage.TamponPanel_Footer.BackColor = Color.GreenYellow;
         else TheVvTabPage.TamponPanel_Footer.BackColor = ZXC.vvColors.tamponPanel_BackColor;

      }
      else // daj normalne boje i bez labele
      {
         if(IsShowingConvertedMoney == false) TheVvTabPage.labDeviza.Visible = false;
         VvHamper.ApplyVVColorAndStyleTabCntrolChange(TheVvTabPage);
      }

      #endregion Set Warning Colors And Label

   }

   public void SetVezaFields(Faktur faktur)
   {
      // 13.09.2021:
      if(faktur.TtInfo.IsV1andV2specialUseTT) return;

      if(faktur.IsExtendable)
      {
         switch(FirstEmptyVezaField)
         {
            case 1: Fld_V1_ttNum = faktur.TtNum;
               Fld_V1_tt = faktur.TT;
               break;
            case 2: Fld_V2_ttNum = faktur.TtNum;
               Fld_V2_tt = faktur.TT;
               break;
            case 3: (this as FakturExtDUC).Fld_V3_ttNum = faktur.TtNum;
               (this as FakturExtDUC).Fld_V3_tt = faktur.TT;
               break;
            case 4: (this as FakturExtDUC).Fld_V4_ttNum = faktur.TtNum;
               (this as FakturExtDUC).Fld_V4_tt = faktur.TT;
               break;

            default: ZXC.aim_emsg(MessageBoxIcon.Warning, "Na 'primaocu' nema više mjesta za upis nove veze."); break;
         }
      }
      else
      {
         switch(FirstEmptyVezaField)
         {
            case 1: Fld_V1_ttNum = faktur.TtNum;
               Fld_V1_tt = faktur.TT;
               break;
            case 2: Fld_V2_ttNum = faktur.TtNum;
               Fld_V2_tt = faktur.TT;
               break;
            //case 3: Fld_V3_ttNum = fakturLocal_rec.TtNum;
            //        Fld_V3_tt    = fakturLocal_rec.TT;
            //        break;
            //case 4: Fld_V4_ttNum = fakturLocal_rec.TtNum;
            //        Fld_V4_tt    = fakturLocal_rec.TT;
            //        break;

            default: ZXC.aim_emsg(MessageBoxIcon.Warning, "Na 'primaocu' nema više mjesta za upis nove veze."); break;
         }
      }

      if(ZXC.MIXER_CopyToOtherDUC_inProgress)
      {
         Fld_V1_ttNum = faktur.V1_ttNum;
         Fld_V1_tt = faktur.V1_tt;
      }
   }

