   public override void GetFields(bool dirtyFlagging)
   {
      if(CtrlOK(tbx_DokNum  )) faktur_rec.DokNum   = Fld_DokNum;
      if(CtrlOK(tbx_DokDate )) faktur_rec.DokDate  = Fld_DokDate;
      if(CtrlOK(tbx_DokDate2)) faktur_rec.DokDate2 = Fld_DokDate2;
      if(CtrlOK(tbx_TT      )) faktur_rec.TT       = Fld_TT;
      if(CtrlOK(tbx_TtNum))
      {
         faktur_rec.TtNum  = Fld_TtNum;
         faktur_rec.TtSort = ZXC.TtInfo(faktur_rec.TT).TtSort;
      }

      if(CtrlOK(tbx_SkladCd  )) faktur_rec.SkladCD      = Fld_SkladCD;
      if(CtrlOK(tbx_VezniDok )) faktur_rec.VezniDok     = Fld_VezniDok;
      if(CtrlOK(tbx_Napomena )) faktur_rec.Napomena     = Fld_Napomena;
      if(CtrlOK(tbx_Konto    )) faktur_rec.Konto        = Fld_Konto;
      if(CtrlOK(tbx_Sklad2Cd )) faktur_rec.SkladCD2     = Fld_SkladCD2;
      if(CtrlOK(tbx_Opis     )) faktur_rec.Opis         = Fld_Opis;
      if(CtrlOK(tbx_ProjektCD)) faktur_rec.ProjektCD    = Fld_ProjektCD;
      if(CtrlOK(tbx_v1_tt    )) faktur_rec.V1_tt        = Fld_V1_tt;
      if(CtrlOK(tbx_v1_ttNum )) faktur_rec.V1_ttNum     = Fld_V1_ttNum;
      if(CtrlOK(tbx_v2_tt    )) faktur_rec.V2_tt        = Fld_V2_tt;
      if(CtrlOK(tbx_v2_ttNum )) faktur_rec.V2_ttNum     = Fld_V2_ttNum;
      if(CtrlOK(tbx_S_ukK    )) faktur_rec.S_ukK        = Fld_S_ukK;
      if(CtrlOK(tbx_S_ukK2   )) faktur_rec.S_ukK2       = Fld_S_ukK2;
      if(CtrlOK(tbx_S_ukKC   )) faktur_rec.S_ukKC       = Fld_S_ukKC;

      if(CtrlOK(tbx_S_ukCount)) faktur_rec.S_ukTrnCount = Fld_S_ukCount;
      if(CtrlOK(tbx_osobaX   )) faktur_rec.OsobaX       = Fld_OsobaX;

      if(CtrlOK(tbx_decimal01)) faktur_rec.Decimal01    = Fld_Decimal01;
      if(CtrlOK(tbx_decimal02)) faktur_rec.Decimal02    = Fld_Decimal02;

      // 13.09.2021: start za PTG ove kompozitne TtNum-ove stavljamo sami u sebe svoje baze kakve su i dalje u sljedbenicima - ovisnicima (u istim tim V1/V2 poljima) 
      if(faktur_rec.TT == Faktur.TT_KUG) faktur_rec.V1_ttNum = faktur_rec.TtNum;
      if(faktur_rec.TT == Faktur.TT_UGN) faktur_rec.V2_ttNum = faktur_rec.TtNum;
      if(faktur_rec.TT == Faktur.TT_AUN) faktur_rec.V2_ttNum = ZXC.GetDesnoOdZareza_asUint(faktur_rec.TtNum, 100000);
      // 13.09.2021:  end  

      GetExtFields();

      GetDgvFields(dirtyFlagging);
   }

