   public /*private*/ void PutDgvFields1()
   {
      int rowIdx, idxCorrector;

      TheG.RowsRemoved -= new DataGridViewRowsRemovedEventHandler(grid_RowsRemoved);
      TheG.RowsAdded   -= new DataGridViewRowsAddedEventHandler  (grid_RowsAdded  );
      TheG.Rows.Clear();

      idxCorrector = GetDGVsIdxCorrrector(TheG);

      #region 1.4.2011 Additions bikoz of ToggleKunaDeviza

      List<Rtrans> rtransList = faktur_rec.Transes;

      if(TheVvTabPage.WriteMode != ZXC.WriteMode.None) // znaci, PutFields dignut u 'žutome' stanju, probably smo u ToggleKunaDeviza pa je Transes malo chuspajzovit! 
         rtransList = faktur_rec.Transes.Where(rtrn => rtrn.SaveTransesWriteMode != ZXC.WriteMode.Delete).OrderBy(rtrn => rtrn.T_serial).ToList();

      #endregion 1.4.2011 Additions bikoz of ToggleKunaDeviza

      if(CtrlOK(rbt_stMarze) && rtransList.Count > 0) Fld_MalopCalcKind = rtransList[0].T_mCalcKind;

      //if(faktur_rec.Transes != null)
      if(rtransList != null)
      {
         // TODO: preseli zbog brzine negdje ranije
         // 15.02.2017 preselio u sam PutFields
         //SetSifrarAndAutocomplete<Artikl>(null, VvSQL.SorterType.None);

         if(ZXC.IsSvDUH && (this is URA_SVD_DUC || this is NRD_SVD_DUC))
         {
            UGOfakturListForURA = new List<Faktur>();
         }

         if(ZXC.IsSvDUH && this is UGODUC)
         {
            SVD_UGO_ostvarenoOGbyART_KCRP_SUM = 0; // Tu nuliramo, a sumira se u PutDgvLineFields1 
            SVD_UGO_ostvarenoOGbyART_KOL_SUM  = 0; // Tu nuliramo, a sumira se u PutDgvLineFields1 
            SVD_UGO_datZadByART               = DateTime.MinValue; 
         }

         // D - Izdano i zatvoreno        
         // N - Odobrena i čeka izdavanje 
         if(ZXC.IsSvDUH && (this is ZAH_SVD_DUC) && (faktur_rec.StatusCD == "D" || faktur_rec.StatusCD == "N"))
         {
            IZDfromZAHlinkedRtransList = RtransDao.GetRtransList_TT_V1tt_V1ttNum_KupdobCD/*_DokDateOD*/(TheDbConnection, Faktur.TT_IZD, faktur_rec.TT, faktur_rec.TtNum, faktur_rec.KupdobCD/*, faktur_rec.DokDate*/);
         }

         //1.4.2011: zbog RISK_ToggleKnDeviza() 
         //foreach(Rtrans rtrans_rec in faktur_rec.Transes)  // 'exists safe': PutCell vodi brigu da li col uopce postoji 
         foreach(Rtrans rtrans_rec in rtransList        )  // 'exists safe': PutCell vodi brigu da li col uopce postoji 
         {
            TheG.Rows.Add();

            rowIdx = TheG.RowCount - idxCorrector;

            PutDgvLineFields1(rtrans_rec, rowIdx, false);

            rtrans_rec.CalcTransResults(null/*faktur_rec*/);

            PutDgvLineResultsFields1(rowIdx, rtrans_rec, false);
         }
      }
      TheG.RowsAdded   += new DataGridViewRowsAddedEventHandler  (grid_RowsAdded  );
      TheG.RowsRemoved += new DataGridViewRowsRemovedEventHandler(grid_RowsRemoved);

      RenumerateLineNumbers(TheG, 0);

      UpdateLineCount(TheG);

      PutDgvTransSumFields1();

      CalcLocationHamperBeloWGrid(); // mora ovdje kad se napuni grid onda se (ne)pojavi scrol koji onda sve poseremeti tt 03.02.2011.
   }

   private List<Faktur> UGOfakturListForURA;
   private List<Rtrans> IZDfromZAHlinkedRtransList;

   public override void PutDgvLineFields1(VvTransRecord trans_rec, int rowIdx, bool skipRecID_andSerial_Columns)
   {
      Rtrans rtrans_rec = (Rtrans)trans_rec;

      if(ZXC.IsSvDUH && (this is URA_SVD_DUC || this is NRD_SVD_DUC))
      {
         Faktur UGOfaktur_rec = new Faktur();
         Rtrans UGOrtrans_rec = new Rtrans();

         bool UGOrtransFound = FakturDao.SetMeLastUGOrtransForURArtrans(TheDbConnection, UGOrtrans_rec, rtrans_rec);

         if(UGOrtransFound)
         {
            rtrans_rec.R_utilUint = UGOrtrans_rec.T_ttNum;
            TheG.PutCell(ci.iT_utilUint, rowIdx, rtrans_rec.R_utilUint);

            bool UGOfakturFound = FakturDao.SetMeFaktur(TheDbConnection, UGOfaktur_rec, Faktur.TT_UGO, UGOrtrans_rec.T_ttNum, false);
            if(UGOfakturFound)
            {
               string YYaddition = "";
               string UGO_YYYY   = ZXC.ValOrEmpty_YyyyDateTime_AsText(UGOfaktur_rec.DokDate);

               if(UGOfaktur_rec.VezniDok.TrimEnd(' ').EndsWith(UGO_YYYY) == false)
               {
                  YYaddition = " / " + UGO_YYYY;
               }
               rtrans_rec.R_utilString = UGOfaktur_rec.VezniDok + YYaddition;
               TheG.PutCell(ci.iT_utilString, rowIdx, rtrans_rec.R_utilString);
               UGOfakturListForURA.Add(UGOfaktur_rec);
            }
         }
      }

      // 30.08.2022: 
      if(ZXC.IsSvDUH && (this is ZAH_SVD_DUC) && IZDfromZAHlinkedRtransList != null)
      {
         Rtrans IZDrtrans_rec = IZDfromZAHlinkedRtransList./*First*/LastOrDefault(rtr => rtr.T_artiklCD == rtrans_rec.T_artiklCD);

         if(IZDrtrans_rec != null)
         {
            TheG.PutCell(ci.iT_utilUint, rowIdx, IZDrtrans_rec.T_ttNum);
         }
      }

      if(skipRecID_andSerial_Columns == false)
      {
         TheG.PutCell(ci.iT_recID, rowIdx, rtrans_rec.T_recID);
         TheG.PutCell(ci.iT_serial, rowIdx, rtrans_rec.T_serial);
         TheG.PutCell(ci.iT_twinID, rowIdx, rtrans_rec.T_twinID);
      }

      // 6.6.2011: 
      Artikl artikl_rec = ArtiklSifrar.SingleOrDefault(artikl => artikl.ArtiklCD == rtrans_rec.T_artiklCD);
      if(artikl_rec != null) TheG.PutCell(ci.iT_artiklTS, rowIdx, artikl_rec.TS);
      if(artikl_rec != null) TheG.PutCell(ci.iT_barCode1, rowIdx, artikl_rec.BarCode1);

      TheG.PutCell(ci.iT_artiklCD  , rowIdx,            rtrans_rec.T_artiklCD);
      TheG.PutCell(ci.iT_artiklName, rowIdx,            rtrans_rec.T_artiklName);
      TheG.PutCell(ci.iT_jedMj     , rowIdx,            rtrans_rec.T_jedMj);
      TheG.PutCell(ci.iT_konto     , rowIdx,            rtrans_rec.T_konto);
      TheG.PutCell(ci.iT_kol       , rowIdx,            rtrans_rec.T_kol);
      TheG.PutCell(ci.iT_cij       , rowIdx, VvCurrency(rtrans_rec.T_cij));
      TheG.PutCell(ci.iT_pdvSt     , rowIdx,            rtrans_rec.T_pdvSt);
      TheG.PutCell(ci.iT_rbt1St    , rowIdx,            rtrans_rec.T_rbt1St);
      TheG.PutCell(ci.iT_rbt2St    , rowIdx,            rtrans_rec.T_rbt2St);
      //TheG.PutCell(ci.iT_mrzSt   , rowIdx,            rtrans_rec.T_wanted);
      TheG.PutCell(ci.iT_doCijMal  , rowIdx, VvCurrency(rtrans_rec.T_doCijMal));
      TheG.PutCell(ci.iT_noCijMal  , rowIdx, VvCurrency(rtrans_rec.T_noCijMal));
      TheG.PutCell(ci.iT_pdvKolTip , rowIdx, GetOneLetter4PdvKolTip(rtrans_rec.T_pdvColTip));
      TheG.PutCell(ci.iT_ztr       , rowIdx, VvCurrency(rtrans_rec.T_ztr));
      TheG.PutCell(ci.iT_kol2      , rowIdx,            rtrans_rec.T_kol2);
      TheG.PutCell(ci.iR_grName    , rowIdx,            rtrans_rec.R_grName);
      if(rtrans_rec.NeedsPpmvOr_kolOPvalues)
      {
         TheG.PutCell(ci.iT_ppmvOsn, rowIdx, rtrans_rec.T_ppmvOsn);
      }
      TheG.PutCell(ci.iT_ppmvSt1i2 , rowIdx,            rtrans_rec.T_ppmvSt1i2);
      TheG.PutCell(ci.iT_pnpSt     , rowIdx,            rtrans_rec.T_pnpSt);
      TheG.PutCell(ci.iT_mtros_cd  , rowIdx,            rtrans_rec.T_mtrosCD);
      TheG.PutCell(ci.iT_serlot    , rowIdx,            rtrans_rec.T_serlot);

      if(HasRtrans_SkladCD_Exposed)
      {
         TheG.PutCell(ci.iT_skladCD, rowIdx, rtrans_rec.T_skladCD);
      }

      if(artikl_rec != null && artikl_rec.TS == ZXC.PCK_TS)
      {
         TheG.PutCell(ci.iT_ramKlasa, rowIdx, artikl_rec.Grupa2CD);
         TheG.PutCell(ci.iT_hddKlasa, rowIdx, artikl_rec.Grupa3CD);
      }

      Kupdob kupdobSifrar_rec = KupdobSifrar.SingleOrDefault(vvDR => vvDR.KupdobCD == rtrans_rec.T_mtrosCD);

      if(kupdobSifrar_rec != null) TheG.PutCell(ci.iT_mtros_tk, rowIdx, kupdobSifrar_rec.Ticker);
      else                         TheG.PutCell(ci.iT_mtros_tk, rowIdx, "");


      TheG.PutCell(ci.iT_isIrmUsluga, rowIdx, VvCheckBox.GetString4Bool(rtrans_rec.T_isIrmUsluga));

      // 13.07.2015: 
      //if(                            faktur_rec.TtInfo.HasSplitTT)
      if(faktur_rec.TT.NotEmpty() && faktur_rec.TtInfo.HasSplitTT)
      {
         TheG.PutCell(ci.iT_isProductLine, rowIdx, VvCheckBox.GetString4Bool(rtrans_rec.T_TT == faktur_rec.TtInfo.SplitTT));
      }
      // else dodan 26.10.2015: bio bug kada kopiras proizvodnjuDUC (PIX, PIX, TRI)
      else if(rtrans_rec.TtInfo.IsSplitProizvodnjaULAZ)
      {
         TheG.PutCell(ci.iT_isProductLine, rowIdx, VvCheckBox.GetString4Bool(true));
      }

      // 15.02.2017: 
      if(this is RNMDUC)
      {
         decimal diffKol = GetDiffKol_PlanVsRealizacijaPIPR(rtrans_rec.T_artiklCD, (this as IVvRealizableFakturDUC).RealizRtrList_AllYears, rtrans_rec.T_kol);

         TheG.PutCell(ci.iT_piprDiffKol, rowIdx, diffKol);
      }

      if(HasOrgBopCop) // SvDUH URA_SVD_DUC, NRD_SVD_DUC 
      {
       //decimal r_BOP = ZXC.DivSafe(rtrans_rec.T_kol , rtrans_rec.T_doCijMal);
       //decimal r_COP =             rtrans_rec.T_cij * rtrans_rec.T_doCijMal ;
       //
       //TheG.PutCell(ci.iT_bop, rowIdx, r_BOP);
       //TheG.PutCell(ci.iT_cop, rowIdx, r_COP);

         TheG.PutCell(ci.iT_bop, rowIdx, rtrans_rec.R_BOP);
         TheG.PutCell(ci.iT_cop, rowIdx, rtrans_rec.R_COP);

      }

      if(ZXC.IsSvDUH && this is UGODUC)
      {
         if(artikl_rec != null) TheG.PutCell(ci.iT_artiklLongOpis, rowIdx, artikl_rec.LongOpis);

         #region puse
         //decimal SVD_UGO_ostvarenoOGbyART = RtransDao.Get_UGO_Ostvareno_For_Artikl_inTHISyear(TheDbConnection, 
         //   rtrans_rec.T_artiklCD                 , // artiklCD 
         //   rtrans_rec.T_kupdobCD                 , // kupdobCD 
         //   /*Fld_DokDate*/ZXC.projectYearFirstDay, // dateOD   
         //   (this as UGODUC).Fld_DospDate        ); // dateDO   !? 
         //

         //DateTime datZadByART = RtransDao.Get_URA_MaxDate_For_UGO_Artikl(TheDbConnection,
         //   rtrans_rec.T_artiklCD                 , // artiklCD 
         //   rtrans_rec.T_kupdobCD                 , // kupdobCD 
         //   /*Fld_DokDate*/ZXC.projectYearFirstDay, // dateOD   
         //   (this as UGODUC).Fld_DospDate        ); // dateDO   !? 
         #endregion puse

         decimal  this_UGO_rtrans_ostvarenoOGbyART_KCRP =                0M;
         decimal  this_UGO_rtrans_ostvarenoOGbyART_kol  =                0M;
         DateTime datZadByART                           = DateTime.MinValue;

         List<Rtrans> rtransList_For_UGO_Artikl = (this as IVvRealizableFakturDUC).RealizRtrList_AllYears.Where(rtr => rtr.T_artiklCD == rtrans_rec.T_artiklCD).ToList();

         // PUSE: 
         //rtransList_For_UGO_Artikl = RtransDao.Get_URA_RtransList_For_UGO_Artikl(TheDbConnection, Faktur.TT_URA,
         //   rtrans_rec.T_artiklCD                 , // artiklCD 
         //   rtrans_rec.T_kupdobCD                 , // kupdobCD 
         //     Fld_DokDate/*ZXC.prevYearFirstDay*/ , // dateOD   ... prosla i ova godina! 
         //   (this as UGODUC).Fld_DospDate        ); // dateDO   !? 

         if(rtransList_For_UGO_Artikl.NotEmpty())
         { 
            this_UGO_rtrans_ostvarenoOGbyART_KCRP = rtransList_For_UGO_Artikl.Sum(rtr => rtr.R_KCRP     );
            this_UGO_rtrans_ostvarenoOGbyART_kol  = rtransList_For_UGO_Artikl.Sum(rtr => rtr.R_kol      );
            datZadByART                           = rtransList_For_UGO_Artikl.Max(rtr => rtr.T_skladDate);
         }

         TheG.PutCell(ci.iT_SVDartRealizOG   , rowIdx, this_UGO_rtrans_ostvarenoOGbyART_KCRP);
         TheG.PutCell(ci.iT_SVDartRealizOGkol, rowIdx, this_UGO_rtrans_ostvarenoOGbyART_kol ); 

         SVD_UGO_ostvarenoOGbyART_KCRP_SUM += this_UGO_rtrans_ostvarenoOGbyART_KCRP; // !!! 
         SVD_UGO_ostvarenoOGbyART_KOL_SUM  += this_UGO_rtrans_ostvarenoOGbyART_kol ; // !!! 

         if(datZadByART > SVD_UGO_datZadByART) SVD_UGO_datZadByART = datZadByART; // !!! 
      }

      if(this is MOD_PTG_DUC)
      {
         TheG.PutCell(ci.iT_TT, rowIdx, rtrans_rec.T_TT);

         foreach(DataGridViewTextBoxCell tbxCell in TheG.Rows[rowIdx].Cells)
         {
            switch(rtrans_rec.T_TT)
            {
               case Faktur.TT_MOS: tbxCell.Style.BackColor = ZXC.vvColors.clr_PCK_PTG; break;
               case Faktur.TT_MOI: tbxCell.Style.BackColor = Color.FromArgb(204, 255, 204); break;
               case Faktur.TT_MOU: tbxCell.Style.BackColor = Color.FromArgb(204, 230, 255); break;
               case Faktur.TT_MOC: tbxCell.Style.BackColor = Color.FromArgb(255, 204, 153); break;

               default: tbxCell.Style.BackColor = ZXC.vvColors.dataGridCellReadOnly_True_BackColor; break;
            }
         }
      }

   }

   public static decimal GetDiffKol_PlanVsRealizacijaPIPR(string artiklCD, List<Rtrans> realizacijaRtransList, decimal planKol)
   {
      decimal realizKol = realizacijaRtransList.Where(rtr => rtr.T_artiklCD == artiklCD).Sum(r => r.T_kol);

      decimal diffKol   = realizKol - planKol;

      return diffKol;
   }

   public override void PutDgvLineResultsFields1(int rowIdx, VvTransRecord trans_rec, bool passPtrResultsToZaglavljeTranses)
   {
      Rtrans rtrans_rec = trans_rec as Rtrans;

      if(passPtrResultsToZaglavljeTranses == true)
      {
         // NotaBene: bez ove provjere za Deleted bi ti se kada pobrises npr drugi (kao zadnji) row pa ga ponovno dodas i izazoves CalcTranses() skoci 
         // Exception da {"Sequence contains more than one matching element"}
         // u PutDgvLineResultsFields1():       if(passPtrResultsToZaglavljeTranses == true)... jerbo uprkos deletanju DGV row-a u biznisu deletani trans ostane! 
         Rtrans rtransInFakturBusiness_rec = faktur_rec.Transes.SingleOrDefault(rtr =>
            rtr.T_serial == rtrans_rec.T_serial &&
            rtr.SaveTransesWriteMode != ZXC.WriteMode.Delete &&
            rtr.T_recID == rtrans_rec.T_recID);

         rtransInFakturBusiness_rec.RtrResults = rtrans_rec.RtrResults;
         // Spec za ovaj FackturDUC, T_ztr je malo result / malo dataLayer podatak... tj. T_ztr je result filed koji se usnimava u data layer.
         rtransInFakturBusiness_rec.T_ztr = rtrans_rec.T_ztr;
      }

      TheG.PutCell(ci.iT_kc      , rowIdx, VvCurrency(rtrans_rec.R_KC));
      TheG.PutCell(ci.iT_rbt1    , rowIdx, VvCurrency(rtrans_rec.R_rbt1));
      TheG.PutCell(ci.iT_rbt2    , rowIdx, VvCurrency(rtrans_rec.R_rbt2));
      TheG.PutCell(ci.iT_kcr     , rowIdx, VvCurrency(rtrans_rec.R_KCR));
      TheG.PutCell(ci.iT_ztr     , rowIdx, VvCurrency(rtrans_rec./*R*/T_ztr));
      TheG.PutCell(ci.iT_mrz     , rowIdx, VvCurrency(rtrans_rec.R_mrz));
      TheG.PutCell(ci.iT_mrzSt   , rowIdx,            rtrans_rec.R_mrzSt);
      TheG.PutCell(ci.iT_pdv     , rowIdx, VvCurrency(rtrans_rec.R_pdv));
      TheG.PutCell(ci.iT_kcrm    , rowIdx, VvCurrency(rtrans_rec.R_KCRM));
      TheG.PutCell(ci.iT_kcrp    , rowIdx, VvCurrency(rtrans_rec.R_KCRP));
      TheG.PutCell(ci.iT_cij_kcr , rowIdx, VvCurrency(rtrans_rec.R_CIJ_KCR));
      TheG.PutCell(ci.iT_cij_kcrm, rowIdx, VvCurrency(rtrans_rec.R_CIJ_KCRM));
      TheG.PutCell(ci.iT_cij_kcrp, rowIdx, VvCurrency(rtrans_rec.R_CIJ_KCRP));

      TheG.PutCell(ci.iT_mskPdv  , rowIdx, VvCurrency(rtrans_rec.R_mskPdv));
      TheG.PutCell(ci.iT_cij_MSK , rowIdx, VvCurrency(rtrans_rec.R_CIJ_MSK));
      TheG.PutCell(ci.iT_MSK     , rowIdx, VvCurrency(rtrans_rec.R_MSK));

      TheG.PutCell(ci.iT_ruc     , rowIdx, VvCurrency(rtrans_rec.R_Ira_RUC));
      TheG.PutCell(ci.iT_ruv     , rowIdx, VvCurrency(rtrans_rec.R_Ira_RUV));
      TheG.PutCell(ci.iT_nv      , rowIdx, VvCurrency(rtrans_rec.R_Ira_NV));
      TheG.PutCell(ci.iT_nc      , rowIdx, VvCurrency(rtrans_rec.R_Ira_NC));

      if(rtrans_rec.NeedsPpmvOr_kolOPvalues)
      {
         TheG.PutCell(ci.iT_kolOP   , rowIdx,           (rtrans_rec.R_kolOP));
         TheG.PutCell(ci.iT_cijOP   , rowIdx, VvCurrency(rtrans_rec.R_cijOP));
      }
      // 27.09.2013: 
      if(TheVvTabPage.WriteMode == ZXC.WriteMode.None && faktur_rec.IsUMJETNINA && faktur_rec.TtInfo.IsIzlazniPdvTT)
      {
         if(ZXC.AlmostEqual(rtrans_rec.R_Ira_NC, rtrans_rec.T_ppmvOsn, 0.02M) == false)
         {
            ZXC.aim_emsg(MessageBoxIcon.Error, "GREŠKA!\n\nNabavna cijena u trenutku stvaranja ovoga dokumenta {0}kn\n\nje različita od trenutne cijene po kalkulaciji [{2}] {1}kn\n\nPosljedica je da je PDV na UMJETNINU krivo obračunat!",
               rtrans_rec.T_ppmvOsn.ToStringVv(), rtrans_rec.R_Ira_NC.ToStringVv(), rtrans_rec.TheAsEx.DateZadUlaz.ToString(ZXC.VvDateFormat));
         }
      }

      TheG.PutCell(ci.iT_ppmvIzn, rowIdx, VvCurrency(rtrans_rec.R_ppmvIzn));


      if(ZXC.TtInfo(Fld_TT).IsNivelacijaZPC)
      {
         TheG.PutCell(ci.iT_noCijMal, rowIdx, VvCurrency(rtrans_rec.T_noCijMal));
      }

      TheG.PutCell(ci.iT_kiz_KC  , rowIdx, VvCurrency(rtrans_rec.Rkiz_KC));
      TheG.PutCell(ci.iT_kiz_KCR , rowIdx, VvCurrency(rtrans_rec.Rkiz_KCR));
      TheG.PutCell(ci.iT_kiz_rbt1, rowIdx, VvCurrency(rtrans_rec.Rkiz_rbt1));

   }

   public override void PutDgvTransSumFields1()
   {
      TheSumGrid.PutCell(ci.iT_kol      , 0,            faktur_rec.TrnSum_K       );
      TheSumGrid.PutCell(ci.iT_kol2     , 0,            faktur_rec.TrnSum_K2      );
      TheSumGrid.PutCell(ci.iT_kc       , 0, VvCurrency(faktur_rec.TrnSum_KC)     );
      TheSumGrid.PutCell(ci.iT_rbt1     , 0, VvCurrency(faktur_rec.TrnSum_Rbt1)   );
      TheSumGrid.PutCell(ci.iT_rbt2     , 0, VvCurrency(faktur_rec.TrnSum_Rbt2)   );
      TheSumGrid.PutCell(ci.iT_kcr      , 0, VvCurrency(faktur_rec.TrnSum_KCR)    );
      TheSumGrid.PutCell(ci.iT_ztr      , 0, VvCurrency(faktur_rec.TrnSum_Ztr)    );
      TheSumGrid.PutCell(ci.iT_mrz      , 0, VvCurrency(faktur_rec.TrnSum_Mrz)    );
      TheSumGrid.PutCell(ci.iT_pdv      , 0, VvCurrency(faktur_rec.TrnSum_Pdv)    );
      TheSumGrid.PutCell(ci.iT_kcrm     , 0, VvCurrency(faktur_rec.TrnSum_KCRM)   );
      TheSumGrid.PutCell(ci.iT_kcrp     , 0, VvCurrency(faktur_rec.TrnSum_KCRP)   );
      TheSumGrid.PutCell(ci.iT_ruv      , 0, VvCurrency(faktur_rec.TrnSum_Ira_RUV));
      TheSumGrid.PutCell(ci.iT_ruc      , 0, VvCurrency(faktur_rec.TrnSum_Ira_RUC));
      TheSumGrid.PutCell(ci.iT_nv       , 0, VvCurrency(faktur_rec.TrnSum_Ira_NV) );

      TheSumGrid.PutCell(ci.iT_MSK      , 0, VvCurrency(faktur_rec.TrnSum_MSK)   );
      TheSumGrid.PutCell(ci.iT_mskPdv   , 0, VvCurrency(faktur_rec.TrnSum_MskPdv));

      TheSumGrid.PutCell(ci.iT_ppmvOsn  , 0, VvCurrency(faktur_rec.FirstTrn_PpmvOsn));
      TheSumGrid.PutCell(ci.iT_ppmvSt1i2, 0,           (faktur_rec.FirstTrn_PpmvSt1i2));
      TheSumGrid.PutCell(ci.iT_ppmvIzn  , 0, VvCurrency(faktur_rec.FirstTrn_PpmvIzn));

      TheSumGrid.PutCell(ci.iT_kolOP    , 0,           (faktur_rec.TrnSum_R_kolOP)); 

      //if(faktur_rec.TtInfo.HasSplitTT && ZXC.RISK_PULXPIZX_Calc_InProgress == false) PutProduktCijenaAndIznos_OR_CheckKOLbalance(); // 08.04.2013: ovo je KLJUČNA stvar za PIZ/PIX logiku 
      if(this.NeedsProizvodCIJ && ZXC.RISK_PULXPIZX_Calc_InProgress == false) PutProduktCijenaAndIznos_OR_CheckKOLbalance(); // 08.04.2013: ovo je KLJUČNA stvar za PIZ/PIX logiku 

      if(ZXC.IsSvDUH && this is UGODUC)
      {
         #region plavi hamper

         FakturExtDUC theDUC = this as FakturExtDUC;

         List<Faktur> URA_FakturList_For_UGOVOR = RtransDao.Get_SVD_URA_FakturList_For_UGOVOR(TheDbConnection, Faktur.Set_TT_And_TtNum(Fld_TT, Fld_TtNum));

         SVD_UGO_ostvarenoOGbyURA = URA_FakturList_For_UGOVOR.Sum(fak => fak.S_ukKCRP); // Ostvareno u ovoj godini po URA-ma         

         //SVD_UGO_ostvarenoOGbyART_SUM = 0; // Tu nuliramo, a sumira se u PutDgvLineFields1 ... NE: nuliramo na pocetku PutDgvFields1, prije petlje 

         decimal  ostvarenoPG      = faktur_rec.SomeMoney                                    ; // UGO Ostvarenu u proslim godinama 
         decimal  iznUgovora       = faktur_rec.S_ukKCRP                                     ; // UGO ug uk sa  PDV-om             
         decimal  iznBezPdv        = faktur_rec.S_ukKCRM                                     ; // UGO ug uk bez PDV-a              
       //decimal  ostvarenoUK      = ostvarenoPG + SVD_UGO_ostvarenoOGbyURA                  ; // Ostvareno sveukupno              
         decimal  ostvarenoUK      =               SVD_UGO_ostvarenoOGbyART_KCRP_SUM         ; // Ostvareno sveukupno              
         decimal  ostatak          = iznUgovora  - ostvarenoUK                               ; // Ostatak                          
         decimal  indeksOstv       = ZXC.StopaRealizacije(iznUgovora, ostvarenoUK)           ; // Indeks ostvarenosti              
         DateTime datZadByURA      = URA_FakturList_For_UGOVOR.IsEmpty() ? DateTime.MinValue : 
                                     URA_FakturList_For_UGOVOR.Max(ura => ura.DokDate)       ; // Konačni Datum izvršenja by URA   
         DateTime datZadByART      = SVD_UGO_datZadByART                                     ; // Konačni Datum izvršenja by ART   

       //theDUC.Fld_OstvarenoOG = SVD_UGO_ostvarenoOGbyURA         ;
       //theDUC.Fld_OstvarenoOG = SVD_UGO_ostvarenoOGbyART_KCRP_SUM;
         theDUC.Fld_OstvarenoUK = ostvarenoUK                      ;
         theDUC.Fld_Ostatak     = ostatak                          ;
         theDUC.Fld_IndeksOstv  = indeksOstv                       ;
       //theDUC.Fld_DatZadOstv  = datZadByURA                      ;
         theDUC.Fld_DatZadOstv  = datZadByART                      ;

         #region UGO specific PutDgvTransSumFields1

         TheSumGrid.PutCell(ci.iT_SVDartRealizOG   , 0, (SVD_UGO_ostvarenoOGbyART_KCRP_SUM));
         TheSumGrid.PutCell(ci.iT_SVDartRealizOGkol, 0, (SVD_UGO_ostvarenoOGbyART_KOL_SUM ));

         #endregion UGO specific PutDgvTransSumFields1

         #endregion plavi hamper

         // TODO SVD: da li i kada javljati?! 
         if(false /*SVD_UGO_ostvarenoOGbyURA != SVD_UGO_ostvarenoOGbyART_SUM*/)
            ZXC.aim_emsg(MessageBoxIcon.Warning, "Ostvareno u ovoj godini po URA nije jednako Ostvareno u ovoj godini po artiklima!\n\nURA sum: {0}\n\nART sum: {1}",
               SVD_UGO_ostvarenoOGbyURA.ToStringVv(), SVD_UGO_ostvarenoOGbyART_KCRP_SUM.ToStringVv());
      }
   }

   /// <summary>
   /// !!! Ovdje se poziva 'GetLineFlds_CalcTrans_PutLineFlds_PutSumFlds_FOR_ALL_ROWS()'
   /// </summary>
   /*private*/
   internal void PutProduktCijenaAndIznos_OR_CheckKOLbalance()
   {
      ZXC.RISK_PULXPIZX_Calc_InProgress = true;

      // 26.11.2015: 
      //if(TheVvTabPage.WriteMode != ZXC.WriteMode.None) // u 'žutome'        izracunaj cijenu produkta - zeleni redci 
      if(ZXC.RISK_SaveVvDataRecord_inProgress) // samo kod sejvanj! izracunaj cijenu produkta - zeleni redci 
      {
         decimal t_kol;

         bool isPIP = faktur_rec.TtInfo.IsRadNalPUcijTT;

         // 24.08.2015: pokusaj ubrzavanja proizvodnja DUCa (TRI, PIZ, PIX)
         //GetLineFlds_CalcTrans_PutLineFlds_PutSumFlds_FOR_ALL_ROWS();

         decimal ukFinIzlaz    = faktur_rec.TrnSum_KCR;
         decimal ukFinIzlazMPC = faktur_rec.TrnSum_KCRP;
         decimal ukKolUlaz     = faktur_rec.TrnSum_K_PULX_ALL;

         decimal ncPerUlKol = ZXC.DivSafe(ukFinIzlaz, ukKolUlaz).Ron(4); // TH TRI abrakadabra 
         decimal mcPerUlKol = ZXC.DivSafe(ukFinIzlazMPC, ukKolUlaz).Ron(4);

         // 25.02.2016: gumiflex - PIP - ulazna cijena proizvoda via RNM batch 
         decimal ncPerUlKolOP=0M;
         if(isPIP)
         {
            // 26.01.2017: 
#if OldPIP_2016
            ncPerUlKol   = SetPIP_ncPerUlKol  (faktur_rec); // puse - PIP 2016 
#endif

            if(ZXC.projectYearFirstDay.Year != 2017)
            {
               ncPerUlKolOP = SetPIP_ncPerUlKolKg(faktur_rec);
            }
            else  // WAR_PIP_2017 
            {
               ncPerUlKolOP = 0M;
            }

            //ncPerUlKol = ncPerUlKolOP * kurac; ... krivo 
         }

         Artikl artikl_rec = null; string artiklCD;

         // 27.10.2014: missing artstat 4 rtrans SAMO ZA IsProizvCijByArtGr ___ start 
         #region Bad(Missing)Cache Manager

         // 09.2016: ! BIG NEWS ! po rtransovu grupu ne idemo vise u TheAsEx nego u rtrans_rec.R_grName 

         //if(/*ZXC.RRD.Dsc_IsProizvCijByArtGr*/ Faktur.IsProizvCijByArtGr(Fld_TT))
         //{
         //   // TrnNonDel pass 
         //   // 09.12.2016: 
