         //   int badCacheCount = faktur_rec.TrnNonDel.Count(rtr => rtr.TheAsEx == null || rtr.TheAsEx.IsNullFromReader);
         //
         //   if(badCacheCount.IsPositive())
         //   {
         //      var handicapedIzlazRtranses = faktur_rec.TrnNonDel.Where(rtr => rtr.TheAsEx == null || rtr.TheAsEx.IsNullFromReader);
         //
         //      foreach(Rtrans rtrans_rec in handicapedIzlazRtranses)
         //      {
