         //   // 09.12.2016: 
         // //badCacheCount = faktur_rec.TrnNonDel_PULX_ALL.Count(rtr =>                        rtr.TheAsEx.IsNullFromReader);
         //   badCacheCount = faktur_rec.TrnNonDel_PULX_ALL.Count(rtr => rtr.TheAsEx == null || rtr.TheAsEx.IsNullFromReader);
         //
         //   if(badCacheCount.IsPositive())
         //   {
         //      var handicapedIzlazRtranses = faktur_rec.TrnNonDel_PULX_ALL.Where(rtr => rtr.TheAsEx == null || rtr.TheAsEx.IsNullFromReader);
         //
         //      foreach(Rtrans rtrans_rec in handicapedIzlazRtranses)
         //      {
         //         if(rtrans_rec.T_artiklCD.NotEmpty() && rtrans_rec.T_skladCD.NotEmpty()) ArtiklDao.RepareMissingArtstat(TheDbConnection, rtrans_rec);
         //      }
         //   }
         //}

         #endregion Bad(Missing)Cache Manager
         // 27.10.2014: missing artstat 4 rtrans ___ end 

         bool touched = false;
         for(int rIdx = 0; rIdx < TheG.RowCount - 1; ++rIdx)
         {
            // 25.02.2016: gumiflex - PIP - ulazna cijena proizvoda via RNM batch 
            //if(                                              VvCheckBox.GetBool4String(TheG.GetStringCell(ci.iT_isProductLine, rIdx, false)) == false) continue;
            if(isPIP == false && VvCheckBox.GetBool4String(TheG.GetStringCell(ci.iT_isProductLine, rIdx, false)) == false) continue;

            // 09.2016: ! BIG NEWS ! po rtransovu grupu ne idemo vise u TheAsEx nego u rtrans_rec.R_grName 
            if(VvUserControl.ArtiklSifrar == null) SetSifrarAndAutocomplete<Artikl>(null, VvSQL.SorterType.Code);
            Rtrans.SetRtransArtiklGrupa1CD(faktur_rec.TrnNonDel         , VvUserControl.ArtiklSifrar);
            Rtrans.SetRtransArtiklGrupa1CD(faktur_rec.TrnNonDel_PULX_ALL, VvUserControl.ArtiklSifrar);

          //befBIG_NEWS: // 09.12.2014:
          //befBIG_NEWS: if(faktur_rec.TrnNonDel         .Any(rtr => rtr.TheAsEx == null)) { ZXC.aim_emsg(MessageBoxIcon.Error, "faktur_rec.TrnNonDel         .Any: TheAsEx == null"); continue; }
          //befBIG_NEWS: if(faktur_rec.TrnNonDel_PULX_ALL.Any(rtr => rtr.TheAsEx == null)) { ZXC.aim_emsg(MessageBoxIcon.Error, "faktur_rec.TrnNonDel_PULX_ALL.Any: TheAsEx == null"); continue; }

            artiklCD = TheG.GetStringCell(ci.iT_artiklCD, rIdx, /*false*/true);
            if(artiklCD.IsEmpty()) continue;
            artikl_rec = Get_Artikl_FromVvUcSifrar(artiklCD);

            #region IsProizvCijByArtGr

            // 24.10.2014: 
            if(/*ZXC.RRD.Dsc_IsProizvCijByArtGr*/ Faktur.IsProizvCijByArtGr(Fld_TT))
            {
               // 26.01.2017: izvadio prije if-a jer treba i za PIP 
             //artiklCD = TheG.GetStringCell(ci.iT_artiklCD, rIdx, /*false*/true);
             //if(artiklCD.IsEmpty()) continue;
             //artikl_rec = Get_Artikl_FromVvUcSifrar(artiklCD);

               if(artikl_rec == null)
               {
                  ZXC.aim_emsg(MessageBoxIcon.Error, "Nema artikla [{0}]", artiklCD);
               }
               else
               {
                //ukFinIzlaz    = faktur_rec.TrnNonDel         .Where(r => r.A_ArtGrCd1 == artikl_rec.Grupa1CD).Sum(rtrn => rtrn.R_KCR );
                //ukFinIzlazMPC = faktur_rec.TrnNonDel         .Where(r => r.A_ArtGrCd1 == artikl_rec.Grupa1CD).Sum(rtrn => rtrn.R_KCRP);
                //ukKolUlaz     = faktur_rec.TrnNonDel_PULX_ALL.Where(r => r.A_ArtGrCd1 == artikl_rec.Grupa1CD).Sum(rtrn => rtrn.T_kol );
                  ukFinIzlaz    = faktur_rec.TrnNonDel         .Where(r => r.R_grName   == artikl_rec.Grupa1CD).Sum(rtrn => rtrn.R_KCR );
                  ukFinIzlazMPC = faktur_rec.TrnNonDel         .Where(r => r.R_grName   == artikl_rec.Grupa1CD).Sum(rtrn => rtrn.R_KCRP);
                  ukKolUlaz     = faktur_rec.TrnNonDel_PULX_ALL.Where(r => r.R_grName   == artikl_rec.Grupa1CD).Sum(rtrn => rtrn.T_kol );

                  ncPerUlKol = ZXC.DivSafe(ukFinIzlaz   , ukKolUlaz).Ron(4);
                  mcPerUlKol = ZXC.DivSafe(ukFinIzlazMPC, ukKolUlaz).Ron(4);

               }
            }

            #endregion IsProizvCijByArtGr

            if(/*ZXC.RRD.Dsc_IsProizvCijByArtGr*/ Faktur.IsProizvCijByArtGr(Fld_TT) && ukFinIzlaz.IsZero())
            {
               ZXC.aim_emsg(MessageBoxIcon.Warning, "UPOZORENJE!\n\nNema financijskog fonda za artikle kategorije\n\n{0}", artikl_rec.Grupa1CD);
            }
            else
            {
               t_kol = TheG.GetDecimalCell(ci.iT_kol, rIdx, false);

               // 26.01.2017: 
               // PIP 2017 
#if !OldPIP_2016
               if(isPIP) ncPerUlKol = ncPerUlKolOP * artikl_rec.R_orgPak;
#endif
               TheG.PutCell(ci.iT_cij, rIdx, VvCurrency(        ncPerUlKol));
               TheG.PutCell(ci.iT_kc , rIdx, VvCurrency(t_kol * ncPerUlKol));

               //// 20.12.2013: 
               //if(faktur_rec.TT == Faktur.TT_PIM)
               //{
               //   TheG.PutCell(ci.iT_cij_MSK, rIdx, VvCurrency(mcPerUlKol));
               //}
               touched = true;
            }

         } // for(int rIdx = 0; rIdx < TheG.RowCount - 1; ++rIdx) 

         if(touched)
         {
            GetLineFlds_CalcTrans_PutLineFlds_PutSumFlds_FOR_ALL_ROWS();
         }
         //} // if(TheVvTabPage.WriteMode != ZXC.WriteMode.None) // u 'žutome'        izracunaj cijenu produkta - zeleni redci 
      } // if(ZXC.RISK_SaveVvDataRecord_inProgress        ) // samo kod sejvanj! izracunaj cijenu produkta - zeleni redci 
      //else                                                  // u 'bijelome' provjeri ravnotezu kolicina 
      else if(TheVvTabPage.WriteMode == ZXC.WriteMode.None) // u 'bijelome' provjeri ravnotezu kolicina 
      {
         if(this is PIZpDUC && (ZXC.VvDeploymentSite == ZXC.VektorSiteEnum.PPUKAN || ZXC.CURR_prjkt_rec.Ticker == "PPUKAN" || ZXC.CURR_prjkt_rec.Ticker == "TESTIS") &&
            //faktur_rec.TrnSum_K_PIZX_PULX_DIFF_ALL.NotZero())
            Math.Abs(faktur_rec.TrnSum_K_PIZX_PULX_DIFF_ALL) > 0.0015M)
         {
            ZXC.aim_emsg(MessageBoxIcon.Error, "ulazKol:\t{0}\nizlazKol:\t{1}\nRAZLIKA:\t{2} ", faktur_rec.TrnSum_K_PULX_ALL.ToStringVvKolDecimalPlaces(3), faktur_rec.TrnSum_K_PIZX.ToStringVvKolDecimalPlaces(3), faktur_rec.TrnSum_K_PIZX_PULX_DIFF_ALL.ToStringVvKolDecimalPlaces(3));
         }
      }

      ZXC.RISK_PULXPIZX_Calc_InProgress = false;
   }

   // PIP 2016 
   private decimal SetPIP_ncPerUlKol/*_BEF_2017*/(Faktur faktur_rec)
   {
      // TODO: po rtransList_ForProjektCD bi trebalo ici i u prethodne godine! za radne naloge koji se protezu kroz vise godina 
      List<Rtrans> rtransList_ForProjektCD = RtransDao.GetRtransList_ForProjektCD(TheDbConnection, faktur_rec.ProjektCD, Rtrans.artiklOrderBy_ASC);

      rtransList_ForProjektCD.RemoveAll(rtr => rtr.TtAndTtNum == faktur_rec.TT_And_TtNum);

      rtransList_ForProjektCD.AddRange(faktur_rec.TrnNonDel);

      decimal ukFinIzlaz = rtransList_ForProjektCD.Where(rtr => rtr.T_TT == Faktur.TT_PPR).Sum(rtr => rtr.R_KC ); // PIZ: faktur_rec.TrnSum_KCR       ; 
      decimal ukKolUlaz  = rtransList_ForProjektCD.Where(rtr => rtr.T_TT == Faktur.TT_PIP).Sum(rtr => rtr.T_kol); // PIZ: faktur_rec.TrnSum_K_PULX_ALL; 

      decimal ncPerUlKol = ZXC.DivSafe(ukFinIzlaz, ukKolUlaz).Ron(4);

      return ncPerUlKol;
   }

   // PIP 2017 
   private decimal SetPIP_ncPerUlKolKg/*_2017*/(Faktur pipFaktur_rec)
   {
      List<Rtrans> ppr_pip_RtransListOG = RtransDao.GetRtransList_ForProjektCD(TheDbConnection, pipFaktur_rec.ProjektCD, Rtrans.artiklOrderBy_ASC);

      ppr_pip_RtransListOG.RemoveAll(rtr => rtr.TtAndTtNum == pipFaktur_rec.TT_And_TtNum || rtr.R_utilBool == true);

      ppr_pip_RtransListOG.AddRange(pipFaktur_rec.TrnNonDel);

      Faktur rnmFaktur_rec    = new Faktur();
      bool   projektFound     = RtransDao.GetProjektFaktur_ForProjektCD(TheDbConnection, rnmFaktur_rec, pipFaktur_rec.ProjektCD);
      if(projektFound)
      {
         rnmFaktur_rec.VvDao.LoadTranses(TheDbConnection, rnmFaktur_rec, false);
      }

      RNMstatus theRNMstatus = new RNMstatus(rnmFaktur_rec, rnmFaktur_rec.Transes.Where(rtr => rtr.T_TT == Faktur.TT_RNU).ToList(), ppr_pip_RtransListOG);

      return theRNMstatus.ncPerUlKolKg; // VOILA! 
   }

