   #region IVvHasSumInDataLayerDocumentRecord Members

   public void PutTransSumToDocumentSumFields()
   {
      GetDgvFields1(false); // da digne MarkTransesToDelete (trebalo bi to i gore u PutDgvTransSumFields1 ali oni se poprave pri CellEndEdit)
      // ovdje ti se stalno vrti jedan te isti problem: Kada u 'ispravi' pobrises neki redak ili zamijenis/preimenujes artikl na stavci (znaci stari rtrans treba biti DEL a novi ADD)
      // tada ti je u faktur_rec.Transes chuspayz jer tek MarkTransesToDelete u GetDgvFields-u sredi faktur_rec.Transes da adekvatni dobe SaveTransesWriteMode - DELETE,
      // do tada u Transes imas i stare i nove sa nekorektnim 'SaveTransesWriteMode' vrijednostima 

      if(CtrlOK(tbx_S_ukCount)) Fld_S_ukCount = (faktur_rec.TrnSum_Count);

      if(CtrlOK(tbx_S_ukK )) Fld_S_ukK  =           (faktur_rec.TrnSum_K );
      if(CtrlOK(tbx_S_ukK2)) Fld_S_ukK2 =           (faktur_rec.TrnSum_K2);
      if(CtrlOK(tbx_S_ukKC)) Fld_S_ukKC = VvCurrency(faktur_rec.TrnSum_KC);

      if(faktur_rec.IsExtendable) PutTransSumToDocumentSumFields_Ext();

      if(CtrlOK(tbx_twinS_ukKC)) Fld_TwinS_ukKC = VvCurrency(faktur_rec.TrnSum_KC);

   }

