   private void GetDgvFields(bool dirtyFlagging)
   {
      GetDgvFields1(dirtyFlagging);
      GetDgvFields2(dirtyFlagging);
      GetDgvFields3(dirtyFlagging);
   }

   internal decimal Get_S_KC_fromScreen()
   {
      decimal s_KC = 0.00M, t_cij, t_kol;

      for(int rIdx = 0; rIdx < TheG.RowCount - 1; ++rIdx)
      {
         t_cij = TheG.GetDecimalCell(ci.iT_cij, rIdx, false);
         t_kol = TheG.GetDecimalCell(ci.iT_kol, rIdx, false);
         s_KC += (t_kol * t_cij);
      }

      return s_KC;
   }

   internal decimal Get_S_OrgPakKol_fromScreen()
   {
      decimal s_KOP = 0.00M, art_orgPak, t_kol;
      string t_artiklCD;
      Artikl artikl_rec;

      for(int rIdx = 0; rIdx < TheG.RowCount - 1; ++rIdx)
      {
         //t_cij      = TheG.GetDecimalCell(ci.iT_cij     , rIdx, false);
         t_kol = TheG.GetDecimalCell(ci.iT_kol, rIdx, false);
         t_artiklCD = TheG.GetStringCell(ci.iT_artiklCD, rIdx, false);

         artikl_rec = ArtiklSifrar.SingleOrDefault(art => art.ArtiklCD == t_artiklCD);

         if(artikl_rec != null) art_orgPak = artikl_rec.R_orgPak;
         else art_orgPak = 1.00M;

         s_KOP += (t_kol * art_orgPak);
      }

      return s_KOP;
   }

   /*private !!! */
   public void GetDgvFields1(bool dirtyFlagging)
   {
      uint[] recIDtable;
      int rIdx;

      if(dirtyFlagging && ThePolyGridTabControl.SelectedTab.Title != TabPageTitle1) return;

      if(dirtyFlagging == true && ZXC.TheVvForm.VvFlag_RowsAreAddingOrDeletingOrBoth == false)
      {
         // 26.11.2015: 
       //if((TheG.CurrentCell != null && TheG.CurrentCell.IsInEditMode) || (ZXC.TheVvForm.VvFlag_PretendDgvCurrentCellIsInEditMode                            )) 
         if((TheG.CurrentCell != null && TheG.CurrentCell.IsInEditMode) || (ZXC.TheVvForm.VvFlag_PretendDgvCurrentCellIsInEditMode && TheG.CurrentCell != null))
         {
            GetDgvLineFields1(TheG.CurrentRow.Index, dirtyFlagging, null);

            ZXC.TheVvForm.VvFlag_PretendDgvCurrentCellIsInEditMode = false;
         }

         return;
      }

      if(TheG.RowCount > 0) recIDtable = new uint[TheG.RowCount - 1];
      else recIDtable = null;

      faktur_rec.DiscardPreviouslyAddedTranses();

      for(rIdx = 0; rIdx < TheG.RowCount - 1; ++rIdx)
      {
         // 09.08.2011: da zabranim zadnji prazan redak 
         if(dirtyFlagging == false && rIdx == (TheG.RowCount - 1 - 1) && CheckIfLastRowIsEmpty(rIdx))
         {
            // 14.12.2012: remarckirao jer se na KLD_DUC-u kod sejvanja javlja fantomski novododani prazni red pa ova poruka iritira 
            //ZXC.aim_emsg(MessageBoxIcon.Warning, "Zadnji 'prazan' redak koji je bez artikla, neće biti usnimljen.");
            break;
         }

         GetDgvLineFields1(rIdx, dirtyFlagging, recIDtable);
      }

      MarkTransesToDelete(recIDtable);

   }

   private bool CheckIfLastRowIsEmpty(int lastRowIdx)
   {
      string artiklCD1 = "", artiklName1 = "";
      string artiklCD2 = "", artiklName2 = "";

      // morasu u duplo (dirtyFlagging true / false), jer tu dolazis u jednom trenutku sa df true a u biti je false... ma, vjeruj mi, pusti 'vako 
      if(TheG.CI_OK(ci.iT_artiklCD))
      {
         artiklCD1 = TheG.GetStringCell(ci.iT_artiklCD, lastRowIdx, false);
         artiklCD2 = TheG.GetStringCell(ci.iT_artiklCD, lastRowIdx, true);
      }
      if(TheG.CI_OK(ci.iT_artiklName))
      {
         artiklName1 = TheG.GetStringCell(ci.iT_artiklName, lastRowIdx, false);
         artiklName2 = TheG.GetStringCell(ci.iT_artiklName, lastRowIdx, true);
      }

      return (artiklCD1 + artiklName1 + artiklCD2 + artiklName2).Trim().IsEmpty();
   }

   public override VvTransRecord GetDgvLineFields1(int rIdx, bool dirtyFlagging, uint[] recIDtable)
   {
      uint recID;
      bool DB_RWT;
      Rtrans db_rec;

      // dgvAtrans_rec: buffer za GetField iz DataGridWievRow-a                                        
      // db_rec : pointer na existing row u DB-u kojega ako je EditedHasChanges treba RWTREC-ati 

      recID = TheG.GetUint32Cell(ci.iT_recID, rIdx, dirtyFlagging);

      if(recIDtable != null) recIDtable[rIdx] = recID;

      dgvRtrans_rec = new Rtrans();

      if(recID > 0) // Postojeci redak 
      {
         db_rec = faktur_rec.Transes.SingleOrDefault(vvDR => vvDR.VirtualRecID == recID);
      }
      else // novododani redak 
      {
         db_rec = null;
      }

      DB_RWT = (db_rec != null);

      dgvRtrans_rec.T_recID = recID;

      dgvRtrans_rec.T_parentID = faktur_rec.RecID;

      #region GetColumns

      bool isProductLineChecked = VvCheckBox.GetBool4String(TheG.GetStringCell(ci.iT_isProductLine, rIdx, dirtyFlagging));

          dgvRtrans_rec.T_serial = (ushort)(rIdx + 1);
      if(DB_RWT) db_rec.T_serial = dgvRtrans_rec.T_serial;

          dgvRtrans_rec.T_dokNum = faktur_rec.DokNum;
      if(DB_RWT) db_rec.T_dokNum = dgvRtrans_rec.T_dokNum;

      // 19.04.2023: isplivalo je da je cijela ova ovdje upotreba faktur_rec-a dubiozna, u nekim slucajevima je on prazan (vidi CalcTrans_MALOP_Results_IZLAZ)      
      // ako se grid podaci vade iz grid fldova, zasto se i 'zaglavlje' podaci Rtrans-a ne vade iz fldova zaglavlja?!                                               
    //if(faktur_rec.TtInfo.IsSkladDateTT) dgvRtrans_rec.T_skladDate =                                   faktur_rec.SkladDate                                       ;
    //else                                dgvRtrans_rec.T_skladDate =                                   faktur_rec.DokDate                                         ;
      if(faktur_rec.TtInfo.IsSkladDateTT) {
         FakturExtDUC theExtDUC = (this as FakturExtDUC);
           dgvRtrans_rec.T_skladDate = faktur_rec.SkladDate.NotEmpty() ? faktur_rec.SkladDate : CtrlOK(theExtDUC.tbx_SkladDate) ? theExtDUC.Fld_SkladDate : Fld_DokDate; }
      else dgvRtrans_rec.T_skladDate = faktur_rec.DokDate  .NotEmpty() ? faktur_rec.DokDate   :                                                             Fld_DokDate;

            // 29.10.2014: 
      if(DoesSkl_2_exists &&
         CtrlOK(tbx_DokDate2) &&
         //faktur_rec.TtInfo.IsDokDate2TT && 
         faktur_rec.TtInfo.HasSplitTT)
      {
         dgvRtrans_rec.T_skladDate = faktur_rec.DokDate2Safe;
      }

      if(DB_RWT) db_rec.T_skladDate = dgvRtrans_rec.T_skladDate;

      if(faktur_rec.IsExtendable)
      {
             dgvRtrans_rec.T_kupdobCD = faktur_rec.KupdobCD;
         if(DB_RWT) db_rec.T_kupdobCD = dgvRtrans_rec.T_kupdobCD;
      }

      if(faktur_rec.TtInfo.HasSplitTT == false) // Classic case 
      {
         // PTG news 
       //dgvRtrans_rec.T_TT = faktur_rec.TT;
         if(IsRtransTT_MOD_kindDependable) // MOD / MOU / MOI 
         {
            dgvRtrans_rec.T_TT = faktur_rec.TT;

            #region Set MOD / MOU / MOI 

            string artiklCD = TheG.GetStringCell(ci.iT_artiklCD, rIdx, dirtyFlagging);

            Artikl artikl_rec = Get_Artikl_FromVvUcSifrar(artiklCD);

            if(artikl_rec != null)
            {
               if(artikl_rec.TS == ZXC.PCK_TS)
               {
                  dgvRtrans_rec.T_TT = Faktur.TT_MOD;
               }
               else
               {
                  bool isUlaz = IsMODulaz(rIdx, dirtyFlagging); // !!! TODO

                  if(isUlaz) dgvRtrans_rec.T_TT = Faktur.TT_MOU; // ULAZ  
                  else       dgvRtrans_rec.T_TT = Faktur.TT_MOI; // IZLAZ 
               }
            }

            #endregion Set MOD / MOU / MOI 

         }
         else // Classic case 
         { 
            dgvRtrans_rec.T_TT = faktur_rec.TT;
         }
      }
      else
      {
         if(isProductLineChecked) dgvRtrans_rec.T_TT = faktur_rec.TtInfo.SplitTT;
         else                     dgvRtrans_rec.T_TT = faktur_rec.TT;
      }

      if(DB_RWT) db_rec.T_TT = dgvRtrans_rec.T_TT;

                                  dgvRtrans_rec.T_ttNum = faktur_rec.TtNum;
      if(DB_RWT) db_rec.T_ttNum = dgvRtrans_rec.T_ttNum;

                                   dgvRtrans_rec.T_ttSort = faktur_rec.TtSort;
      if(DB_RWT) db_rec.T_ttSort = dgvRtrans_rec.T_ttSort;

      if(faktur_rec.TtInfo.HasSplitTT == false) // Classic case 
      {
         dgvRtrans_rec.T_skladCD = faktur_rec.SkladCD;

         // PTG news 
         if(HasRtrans_SkladCD_Exposed)
         {
            dgvRtrans_rec.T_skladCD = TheG.GetStringCell(ci.iT_skladCD, rIdx, dirtyFlagging);
         }
      }
      else
      {
         if(isProductLineChecked) dgvRtrans_rec.T_skladCD = faktur_rec.SkladCD2;
         else                     dgvRtrans_rec.T_skladCD = faktur_rec.SkladCD;
      }
      if(DB_RWT)  db_rec.T_skladCD = dgvRtrans_rec.T_skladCD;

      if(TheG.CI_OK(ci.iT_artiklCD))
      {
                                        dgvRtrans_rec.T_artiklCD = TheG.GetStringCell(ci.iT_artiklCD, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_artiklCD = dgvRtrans_rec.T_artiklCD;
      }
      if(TheG.CI_OK(ci.iT_artiklName))
      {
                                          dgvRtrans_rec.T_artiklName = TheG.GetStringCell(ci.iT_artiklName, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_artiklName = dgvRtrans_rec.T_artiklName;
      }
      if(TheG.CI_OK(ci.iT_jedMj))
      {
                                     dgvRtrans_rec.T_jedMj = TheG.GetStringCell(ci.iT_jedMj, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_jedMj = dgvRtrans_rec.T_jedMj;
      }
      if(TheG.CI_OK(ci.iT_konto))
      {
                                     dgvRtrans_rec.T_konto = TheG.GetStringCell(ci.iT_konto, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_konto = dgvRtrans_rec.T_konto;
      }
      if(TheG.CI_OK(ci.iT_cij))
      {
                                   dgvRtrans_rec.T_cij = TheG.GetDecimalCell(ci.iT_cij, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_cij = dgvRtrans_rec.T_cij;
      }
      if(TheG.CI_OK(ci.iT_kol))
      {
                                   dgvRtrans_rec.T_kol = TheG.GetDecimalCell(ci.iT_kol, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_kol = dgvRtrans_rec.T_kol;

         /* !!!!!! */
         //dgvRtrans_rec.T_ztr = Rtrans.GetZtrCut(faktur_rec.S_ukZavisni, faktur_rec.TrnSum_KC, dgvRtrans_rec.T_kol * dgvRtrans_rec.T_cij);
                                   dgvRtrans_rec.T_ztr = TheG.GetDecimalCell(ci.iT_ztr, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_ztr = dgvRtrans_rec.T_ztr;

      }
      if(TheG.CI_OK(ci.iT_pdvSt))
      {
                                     dgvRtrans_rec.T_pdvSt = TheG.GetDecimalCell(ci.iT_pdvSt, rIdx, dirtyFlagging, true);
         if(DB_RWT) db_rec.T_pdvSt = dgvRtrans_rec.T_pdvSt;
      }
      if(TheG.CI_OK(ci.iT_rbt1St))
      {
                                      dgvRtrans_rec.T_rbt1St = TheG.GetDecimalCell(ci.iT_rbt1St, rIdx, dirtyFlagging, true);
         if(DB_RWT) db_rec.T_rbt1St = dgvRtrans_rec.T_rbt1St;
      }
      if(TheG.CI_OK(ci.iT_rbt2St))
      {
                                      dgvRtrans_rec.T_rbt2St = TheG.GetDecimalCell(ci.iT_rbt2St, rIdx, dirtyFlagging, true);
         if(DB_RWT) db_rec.T_rbt2St = dgvRtrans_rec.T_rbt2St;
      }
      if(CtrlOK(rbt_stMarze))
      {
                                         dgvRtrans_rec.T_mCalcKind = Fld_MalopCalcKind;
         if(DB_RWT) db_rec.T_mCalcKind = dgvRtrans_rec.T_mCalcKind;
      }
      // 27.10.2014: jerbo neki DUC, npr. Transform nema vidljivi iT_mrzSt nego samo iT_cij_MSK 
      //if(TheG.CI_OK(ci.iT_mrzSt)                             ) // T_wanted !!! 
      if(TheG.CI_OK(ci.iT_mrzSt) || TheG.CI_OK(ci.iT_cij_MSK)) // T_wanted !!! 
      {
         switch(Fld_MalopCalcKind)
         {
            case ZXC.MalopCalcKind.By_MARZA: dgvRtrans_rec.T_wanted = TheG.GetDecimalCell(ci.iT_mrzSt   , rIdx, dirtyFlagging, true); break;
            case ZXC.MalopCalcKind.By_VPC  : dgvRtrans_rec.T_wanted = TheG.GetDecimalCell(ci.iT_cij_kcrm, rIdx, dirtyFlagging, true); break;
            case ZXC.MalopCalcKind.By_MPC  : dgvRtrans_rec.T_wanted = TheG.GetDecimalCell(ci.iT_cij_MSK , rIdx, dirtyFlagging, true); break;
         }
         if(DB_RWT) db_rec.T_wanted = dgvRtrans_rec.T_wanted;
      }
      if(TheG.CI_OK(ci.iT_doCijMal))
      {
                                        dgvRtrans_rec.T_doCijMal = TheG.GetDecimalCell(ci.iT_doCijMal, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_doCijMal = dgvRtrans_rec.T_doCijMal;
      }
      if(TheG.CI_OK(ci.iT_noCijMal))
      {
                                        dgvRtrans_rec.T_noCijMal = TheG.GetDecimalCell(ci.iT_noCijMal, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_noCijMal = dgvRtrans_rec.T_noCijMal;
      }
      if(TheG.CI_OK(ci.iT_pdvKolTip))
      {
                                         dgvRtrans_rec.T_pdvColTip = GetPdvKolTipEnumFromFirstLetter(TheG.GetStringCell(ci.iT_pdvKolTip, rIdx, dirtyFlagging));
         if(DB_RWT) db_rec.T_pdvColTip = dgvRtrans_rec.T_pdvColTip;
      }
      if(TheG.CI_OK(ci.iT_twinID))
      {
                                      dgvRtrans_rec.T_twinID = TheG.GetUint32Cell(ci.iT_twinID, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_twinID = dgvRtrans_rec.T_twinID;
      }
      if(TheG.CI_OK(ci.iT_kol2))
      {
                                    dgvRtrans_rec.T_kol2 = TheG.GetDecimalCell(ci.iT_kol2, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_kol2 = dgvRtrans_rec.T_kol2;
      }

      if(TheG.CI_OK(ci.iT_isIrmUsluga))
      {
                                           dgvRtrans_rec.T_isIrmUsluga = VvCheckBox.GetBool4String(TheG.GetStringCell(ci.iT_isIrmUsluga, rIdx, dirtyFlagging));
         if(DB_RWT) db_rec.T_isIrmUsluga = dgvRtrans_rec.T_isIrmUsluga;
      }

      if(TheG.CI_OK(ci.iR_grName))
      {
                                      dgvRtrans_rec.R_grName = TheG.GetStringCell(ci.iR_grName, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.R_grName = dgvRtrans_rec.R_grName;
      }

      if(TheG.CI_OK(ci.iT_ppmvOsn))
      {
                                       dgvRtrans_rec.T_ppmvOsn = TheG.GetDecimalCell(ci.iT_ppmvOsn, rIdx, dirtyFlagging, true);
         if(DB_RWT) db_rec.T_ppmvOsn = dgvRtrans_rec.T_ppmvOsn;
      }
      if(TheG.CI_OK(ci.iT_ppmvSt1i2))
      {
                                         dgvRtrans_rec.T_ppmvSt1i2 = TheG.GetDecimalCell(ci.iT_ppmvSt1i2, rIdx, dirtyFlagging, true);
         if(DB_RWT) db_rec.T_ppmvSt1i2 = dgvRtrans_rec.T_ppmvSt1i2;
      }

      if(TheG.CI_OK(ci.iT_pnpSt))
      {
                                     dgvRtrans_rec.T_pnpSt = TheG.GetDecimalCell(ci.iT_pnpSt, rIdx, dirtyFlagging, true);
         if(DB_RWT) db_rec.T_pnpSt = dgvRtrans_rec.T_pnpSt;
      }
      if(TheG.CI_OK(ci.iT_mtros_cd))
      {
                                       dgvRtrans_rec.T_mtrosCD = TheG.GetUint32Cell(ci.iT_mtros_cd, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_mtrosCD = dgvRtrans_rec.T_mtrosCD;
      }
      if(TheG.CI_OK(ci.iT_serlot))
      {
                                      dgvRtrans_rec.T_serlot = TheG.GetStringCell(ci.iT_serlot, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_serlot = dgvRtrans_rec.T_serlot;
      }

      #endregion GetColumns

      if(dgvRtrans_rec.T_recID == 0) // ADDED NEW, FRESH Ftrans             
      {
         faktur_rec.InvokeTransRemove(dgvRtrans_rec);

         dgvRtrans_rec.SaveTransesWriteMode = ZXC.WriteMode.Add;

         dgvRtrans_rec.CalcTransResults(null /*faktur_rec*/);

         faktur_rec.Transes.Add(dgvRtrans_rec);
      }
      // 09.05.2016: !!! BIG NEWS !!! 
    //else if(                  db_rec.EditedHasChanges()) // TU SE POVREMENO DIZE Exception 'db_rec is null'!!! 
      else if(db_rec != null && db_rec.EditedHasChanges()) 
      {
         db_rec.SaveTransesWriteMode = ZXC.WriteMode.Edit;
      }
      else
      {
         // 09.05.2016: !!! BIG NEWS !!! 
         if(db_rec != null)
         db_rec.SaveTransesWriteMode = ZXC.WriteMode.None;
      }

      return dgvRtrans_rec;

   } // GetDgvLineFields1 

