   public override VvReport CreateVvRecordReport(string reportName, VvRptFilter vvRptFilter)
   {
      FakturDocFilter fakturFilter = (FakturDocFilter)vvRptFilter;

      if(this is FakturExtDUC)
      {
         if(this is URMDUC             ||
            this is KalkulacijaMpDUC   ||
            this is URMDUC_2           ||
            this is URMDUC_Dev         ||
            this is PocetnoStanjeMPDUC ||
            this is KalkulacijaMpDUC_2)
         {
          //return new RptR_IRA(new Vektor.Reports.RIZ.CR_KLK_MP()         , reportName, fakturFilter);
          //07.09.2020. //03.11.20 dodan ZTR
                 if(this.TheFakturDocFilterUC.IsKlkUrm_Etiketa == true)  return new RptR_IRA(new Vektor.Reports.RIZ.CR_Etikete()   , reportName, fakturFilter);
            else if(this.TheFakturDocFilterUC.IsKlkUrm_Ztr     == true)  return new RptR_IRA(new Vektor.Reports.RIZ.CR_KLK_MP_Ztr(), reportName, fakturFilter);
            else                                                         return new RptR_IRA(new Vektor.Reports.RIZ.CR_KLK_MP()    , reportName, fakturFilter);
         }
         else if(this is KKMDUC)                                         return new RptR_IRA(new Vektor.Reports.RIZ.CR_KLK_MP_Skarceno(), reportName, fakturFilter);
         else if(this is PovratDobMalDUC && this.faktur_rec.IsUMJETNINA) return new RptR_IRA(new Vektor.Reports.RIZ.CR_UPM_Umjetnina()  , reportName, fakturFilter);
         else if(this is PIZpDUC)                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_Proizvodnja_PIX(), reportName, fakturFilter);
         else if(this is TransformDUC)                                   return new RptR_IRA(new Vektor.Reports.RIZ.CR_TransformDUC()   , reportName, fakturFilter);
         else if(this is MedjuSkladMVIDUC  || this is MedjuSkladMVI2DUC) return new RptR_IRA(new Vektor.Reports.RIZ.CR_MVI_DUC()        , reportName, fakturFilter);
         else if(this is MedjuSkladVMIuDUC || this is MedjuSkladVMI2DUC) return new RptR_IRA(new Vektor.Reports.RIZ.CR_VMI_DUC()        , reportName, fakturFilter);
         else if(this is NivelacijaDUC)                                  return new RptR_IRA(new Vektor.Reports.RIZ.CR_ZPC()            , reportName, fakturFilter);
         else if(this is BlgIsplatDUC    || this is BlgUplatDUC ||
                 this is BlgIsplat_M_DUC || this is BlgUplat_M_DUC)      return new RptR_IRA(new Vektor.Reports.RIZ.CR_UplIspl()        , reportName, fakturFilter);
         else if(this is IRPDUC)
         {
                 if(this.TheFakturDocFilterUC.IsRtrnoOtpr      == true)  return new RptR_IRA(new Vektor.Reports.RIZ.CR_RtranoOtpr_grArtiklCD() , reportName, fakturFilter);
            else if(this.TheFakturDocFilterUC.IsRtrnoOtpr_m2   == true)  return new RptR_IRA(new Vektor.Reports.RIZ.CR_RtranoOtpr_grPaletaNo() , reportName, fakturFilter);
            else if(this.TheFakturDocFilterUC.IsRtrnoOtpr_dimZ == true)  return new RptR_IRA(new Vektor.Reports.RIZ.CR_RtranoOtpr_grDebljina() , reportName, fakturFilter);
            else if(this.TheFakturDocFilterUC.IsRtrno4PIX      == true)  return new RptR_IRA(new Vektor.Reports.RIZ.CR_RtranoRekap4PIX()       , reportName, fakturFilter);
            else                                                         return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrnManyFak_ArtiklLight(), reportName, fakturFilter);
         }
         else if(this.faktur_rec.IsPPMV == true && this is IRMDUC_2)
         {
            this.TheFakturDocFilterUC.hamp_ppmvPrilog1.Visible = true;
            if(this.TheFakturDocFilterUC.IsPPMV_Prilog1 == true)        return new RptR_IRA(new Vektor.Reports.RIZ.CR_Ppmv_Prilog1()          , reportName, fakturFilter);
            else                                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrnManyFak_ArtiklLight(), reportName, fakturFilter);
         }
         //else if(this is PrimkaDevDUC) 
         else if(this is PrimkaVpDUC)
         {
                 if(this.TheFakturDocFilterUC.IsPri_Kalk     == true)   return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrimkaKalkulacija()     , reportName, fakturFilter);
            else if(this.TheFakturDocFilterUC.IsBarCodePrint == true)   return new RptR_IRA(new Vektor.Reports.RIZ.CR_BarCodeNaljepnice()     , reportName, fakturFilter);
            else                                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrnManyFak_ArtiklLight(), reportName, fakturFilter);
         }
         else if(this is InventuraMPDUC)
         {
                                                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_FaktInterna(), reportName, fakturFilter);
         }
         else if(this is KIZDUC)
         {
            //                                                          return new RptR_IRA(new Vektor.Reports.RIZ.CR_KIZ()                   , reportName, fakturFilter);
            if(this.TheFakturDocFilterUC.IsPri_Kalk == true)            return new RptR_IRA(new Vektor.Reports.RIZ.CR_KIZ()                   , reportName, fakturFilter);
            else                                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrnManyFak_ArtiklLight(), reportName, fakturFilter);
         }
         else if(this is RNPDUC) // 15.04.2015: 
         {
                                                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_AnalizaRNP(), reportName, fakturFilter);
         }
         else if(this is ProizvodnjaDUC)                                return new RptR_IRA(new Vektor.Reports.RIZ.CR_ProizvodnjaDUC(), reportName, fakturFilter);
         else if(this is RNMDUC)
         {
            if(ThePolyGridTabControl.SelectedTab.Title == "Realizacija") return new RptR_IRA(new Vektor.Reports.RIZ.CR_RNM_Realizacija(), reportName, fakturFilter);
            else                                                         return new RptR_IRA(new Vektor.Reports.RIZ.CR_RNM_Nalog(), reportName, fakturFilter);
         }
         else if(this is RNZDUC)
         {
                                                                         return new RptR_IRA(new Vektor.Reports.RIZ.CR_RNZ_Nalog(), reportName, fakturFilter);
         }
       //else if(this is IZD_SVD_DUC)                                    return new RptR_IRA(new Vektor.Reports.RIZ.CR_IZD_SVD(), reportName, fakturFilter);
         else if(this is IZD_SVD_DUC || this is ZAH_SVD_DUC)             return new RptR_IRA(new Vektor.Reports.RIZ.CR_IZD_SVD(), reportName, fakturFilter);
         else if(this is NRD_SVD_DUC || this is URA_SVD_DUC)             return new RptR_IRA(new Vektor.Reports.RIZ.CR_SVD_NRD(), reportName, fakturFilter);
         else if(this is UGODUC )                                        return new RptR_IRA(new Vektor.Reports.RIZ.CR_SVD_UGO(), reportName, fakturFilter);
         else if(this is UGNorAUN_PTG_DUC)
         {
               if(ThePolyGridTabControl.SelectedTab.Title == ptgOpl_TabPageName) return new RptR_IRA(new Vektor.Reports.RIZ.CR_MVI_DUC()/*CR_PTG_OPL() */, reportName, fakturFilter);
          else if(ThePolyGridTabControl.SelectedTab.Title == ptgDod_TabPageName) return new RptR_IRA(new Vektor.Reports.RIZ.CR_MVI_DUC()/*CR_PTG_DOD() */, reportName, fakturFilter);
          else                                                                   return new RptR_IRA(new Vektor.Reports.RIZ.CR_VMI_DUC()/*CR_PTG_UGAN()*/, reportName, fakturFilter);
         }

         else
         {
            //if(                                       this.TheFakturDocFilter.PFD.Dsc_OcuPosPrint == true) return new RptR_IRA(new Vektor.Reports.RIZ.CR_posFaktura(), reportName, fakturFilter);
            if(this.TheFakturDocFilter.PFD != null && this.TheFakturDocFilter.PFD.Dsc_OcuPosPrint == true)
            {
               if     (ZXC.TheVvForm.VvPref.fakturIRMDUC.posPrintKind == VvPref.POSprinterKind.BIXOLON01) return new RptR_IRA(new Vektor.Reports.RIZ.CR_POSfaktura_Bixolon(), reportName, fakturFilter);
               else if(ZXC.TheVvForm.VvPref.fakturIRMDUC.posPrintKind == VvPref.POSprinterKind.BIXOLON02) return new RptR_IRA(new Vektor.Reports.RIZ.CR_POSfaktura_Bixolon2(), reportName, fakturFilter);
               else if(ZXC.TheVvForm.VvPref.fakturIRMDUC.posPrintKind == VvPref.POSprinterKind.POS80)     return new RptR_IRA(new Vektor.Reports.RIZ.CR_POSfaktur_POS80(), reportName, fakturFilter);
               else if(ZXC.TheVvForm.VvPref.fakturIRMDUC.posPrintKind == VvPref.POSprinterKind.EPSON01)   return new RptR_IRA(new Vektor.Reports.RIZ.CR_POSfakture_Epson01(), reportName, fakturFilter);
               else if(ZXC.TheVvForm.VvPref.fakturIRMDUC.posPrintKind == VvPref.POSprinterKind.EPSON02)   return new RptR_IRA(new Vektor.Reports.RIZ.CR_POSfakturaEpson02(), reportName, fakturFilter);
               else return new RptR_IRA(new Vektor.Reports.RIZ.CR_posFaktura(), reportName, fakturFilter);

            }


            else return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrnManyFak_ArtiklLight(), reportName, fakturFilter);
         }

         //else return new RptR_IRA(new Vektor.Reports.RIZ.CR_PrnManyFak_ArtiklLight(), reportName, fakturFilter);
      }
      else
      {
         if((this is MedjuSkladDUC || this is MedjuSklad2DUC) && this.TheFakturDocFilterUC.IsPri_Kalk == true) return new RptR_IRA(new Vektor.Reports.RIZ.CR_MSI_Amb_OnlyKol(), reportName, fakturFilter);
         else                                                                                                  return new RptR_IRA(new Vektor.Reports.RIZ.CR_FaktInterna()    , reportName, fakturFilter);
      }

   }

