   #region CreateFakturDokumentPrintUC

   protected void CreateFakturDokumentPrintUC(VvUserControl vvUC)
   {
      this.TheFakturDocFilter = new FakturDocFilter(this);

      TheFakturDocFilterUC = new FakturDocFilterUC(vvUC);
      TheFakturDocFilterUC.Parent = ThePanelForFilterUC_PrintTemplateUC;
      // veza VVForm_Q PrintPreviewMenu_Button_OnClick jer nemaju tj. PFD == null
    //07.09.2020. za printanje naljepnica na KLK i URM treba filter za izbor
    //if(this is URMDUC            || this is KalkulacijaMpDUC   || this is KKMDUC            ||
    //   this is URMDUC_2          || this is KalkulacijaMpDUC_2 || this is URMDUC_Dev        ||
    //   this is MedjuSkladVMIuDUC || this is PocetnoStanjeMPDUC || this is MedjuSkladVMI2DUC ||
    //   this is MedjuSkladMVIDUC  || this is TransformDUC       || this is PIZpDUC           ||
    //   this is ProizvodnjaDUC    || this is MedjuSkladMVI2DUC  || this is RNMDUC            || 
    //   this is RNZDUC            ||
    //   this is URA_SVD_DUC       || this is IZD_SVD_DUC        || this is NRD_SVD_DUC       ||
    //   this is UGODUC                                                                ) ThePanelForFilterUC_PrintTemplateUC.Width = 0;
    //else                                                                               ThePanelForFilterUC_PrintTemplateUC.Width = TheFakturDocFilterUC.Width;

      if(this is KKMDUC            ||
         this is MedjuSkladVMIuDUC || this is PocetnoStanjeMPDUC || this is MedjuSkladVMI2DUC ||
         this is MedjuSkladMVIDUC  || this is TransformDUC       || this is PIZpDUC           ||
         this is ProizvodnjaDUC    || this is MedjuSkladMVI2DUC  || this is RNMDUC            || 
         this is RNZDUC            ||
         this is URA_SVD_DUC       || this is IZD_SVD_DUC        || this is NRD_SVD_DUC       ||
         this is UGODUC            || this is ZAH_SVD_DUC                                       )  ThePanelForFilterUC_PrintTemplateUC.Width = 0;
      else if(this is URMDUC     || this is KalkulacijaMpDUC     ||
              this is URMDUC_2   || this is KalkulacijaMpDUC_2   || 
              this is URMDUC_Dev || this is KalkulacijaMpDUC_Dev                                ) ThePanelForFilterUC_PrintTemplateUC.Width = TheFakturDocFilterUC.Width; //tamo mu se postavlja sirina 
      else if(this is UGNorAUN_PTG_DUC) ThePanelForFilterUC_PrintTemplateUC.Width = TheFakturDocFilterUC.Width; //tamo mu se postavlja sirina 
      else                              ThePanelForFilterUC_PrintTemplateUC.Width = TheFakturDocFilterUC.Width;
   }

