   public string GetOneLetter4PdvKolTip(ZXC.PdvKolTipEnum pdvKolTipEnum)
   {
      switch(pdvKolTipEnum)
      {
         case ZXC.PdvKolTipEnum.MOZE        : return "M";
         case ZXC.PdvKolTipEnum.NEMOZE      : return "N";
         case ZXC.PdvKolTipEnum.PROLAZ      : return "P";
         case ZXC.PdvKolTipEnum.KOL07       : return "7";
         case ZXC.PdvKolTipEnum.KOL08       : return "8";
         case ZXC.PdvKolTipEnum.KOL09       : return "9";
         case ZXC.PdvKolTipEnum.KOL10       : return "0";
         case ZXC.PdvKolTipEnum.KOL11       : return "1";
         case ZXC.PdvKolTipEnum.KOL12       : return "2";
         case ZXC.PdvKolTipEnum.KOL13       : return "3";
         case ZXC.PdvKolTipEnum.KOL14       : return "4";
         case ZXC.PdvKolTipEnum.KOL15       : return "5";
         case ZXC.PdvKolTipEnum.KOL16       : return "6";
         case ZXC.PdvKolTipEnum.UMJETN      : return "U";
         case ZXC.PdvKolTipEnum.AVANS_STORNO: return "A";
         case ZXC.PdvKolTipEnum.GlassOnIRM  : return "G";

         default: return "";
      }
