         case "M": return ZXC.PdvKolTipEnum.MOZE;
         case "N": return ZXC.PdvKolTipEnum.NEMOZE;
         case "P": return ZXC.PdvKolTipEnum.PROLAZ;
         case "7": return ZXC.PdvKolTipEnum.KOL07;
         case "8": return ZXC.PdvKolTipEnum.KOL08;
         case "9": return ZXC.PdvKolTipEnum.KOL09;
         case "0": return ZXC.PdvKolTipEnum.KOL10;
         case "1": return ZXC.PdvKolTipEnum.KOL11;
         case "2": return ZXC.PdvKolTipEnum.KOL12;
         case "3": return ZXC.PdvKolTipEnum.KOL13;
         case "4": return ZXC.PdvKolTipEnum.KOL14;
         case "5": return ZXC.PdvKolTipEnum.KOL15;
         case "6": return ZXC.PdvKolTipEnum.KOL16;
         case "U": return ZXC.PdvKolTipEnum.UMJETN;
         case "A": return ZXC.PdvKolTipEnum.AVANS_STORNO;
         case "G": return ZXC.PdvKolTipEnum.GlassOnIRM;

         default: return ZXC.PdvKolTipEnum.NIJE;
