   #region AllHampersLocations

   public void SetLocationToHamperDeda()
   {

      hamp_dokDate .Location = new Point(0, 0);
      hamp_dokNum  .Location = new Point(hamp_dokDate.Right - ZXC.Qun2, 0);
      hamp_napomena.Location = new Point(0, hamp_dokDate.Bottom - ZXC.Qun4);
      hamp_projekt .Location = new Point(0, hamp_napomena.Bottom - ZXC.Qun4);

      hamp_v1TT.Location = new Point(hamp_napomena.Right - ZXC.QUN, 0);
      hamp_v2TT.Location = new Point(hamp_napomena.Right - ZXC.QUN, hamp_v1TT.Bottom - ZXC.Qun4);

      hamp_tt      .Location = new Point(hamp_v1TT.Right - ZXC.Qun4, 0);
      hamp_skladCd .Location = new Point(hamp_v1TT.Right - ZXC.Qun4, hamp_tt.Bottom - ZXC.Qun4);
      hamp_sklad2Cd.Location = new Point(hamp_v1TT.Right - ZXC.Qun4, hamp_skladCd.Bottom - ZXC.Qun4);


      hamp_konto.Location = new Point(hamp_napomena.Right - ZXC.Qun4, hamp_v2TT.Bottom - ZXC.Qun4);

      if(this is PredatUProizDUC || this is PovratInterDUC || this is PIPDUC)
      {
         hamp_vezniDok.Location = new Point(0, hamp_dokDate.Bottom - ZXC.Qun4);
         hamp_napomena.Location = new Point(0, hamp_vezniDok.Bottom - ZXC.Qun4);
         hamp_projekt .Location = new Point(hamp_napomena.Right - ZXC.QUN, hamp_vezniDok.Bottom - ZXC.Qun4);
         hamp_prjIdent.Location = new Point(0, hamp_projekt.Bottom - ZXC.Qun8);
         hamp_opis    .Location = new Point(0, hamp_prjIdent.Bottom);
         hamp_napomena.BringToFront();
         hamp_osobaX  .Location = new Point(hamp_v1TT.Right - ZXC.Qun4, hamp_skladCd.Bottom - ZXC.Qun4);
         //hamp_prjIdent.Location = new Point(hamp_v1TT.Right - ZXC.Qun4, hamp_projekt.Bottom - ZXC.Qun4);

         tbx_DokDate  .TabIndex = 0;
         tbx_VezniDok .TabIndex = 1;
         tbx_Napomena .TabIndex = 2;
         tbx_ProjektCD.TabIndex = 3;
         tbx_osobaX   .TabIndex = 4;
         tbx_Opis     .TabIndex = 5;

      }
      else if(this is CjenikDUC)
      {
         hamp_napomena.Location = new Point(0, hamp_dokDate.Bottom - ZXC.Qun4);
         hamp_opis    .Location = new Point(0, hamp_napomena.Bottom);
         hamp_projekt .Location = new Point(hamp_opis.Right + ZXC.Qun2 + ZXC.Qun8, hamp_napomena.Bottom - ZXC.Qun4);
         hamp_vezniDok.Location = new Point(hamp_napomena.Right - hamp_vezniDok.Width, hamp_dokNum.Bottom - ZXC.Qun4);
      }
      else if(this is MedjuSkladVMIuDUC || this is MedjuSkladVMI2DUC || this is MedjuSkladMVIDUC || this is MedjuSkladMVI2DUC || 
              this is MedjuSkladMMIDUC  || this is MedjuSkladDUC     || this is TransformDUC     || this is MSI_PTG_DUC)
      {
         hamp_dokNum.Location = new Point(hamp_projekt.Right - hamp_dokNum.Width - ZXC.QUN + ZXC.Qun8, 0);

         hamp_v1TT.Location = new Point(hamp_projekt.Right - ZXC.Qun8, 0);
         hamp_v2TT.Location = new Point(hamp_projekt.Right - ZXC.Qun8, hamp_v1TT.Bottom - ZXC.Qun4);

         hamp_napomena.Location = new Point(0, hamp_v2TT.Bottom - ZXC.Qun4);

         hamp_tt     .Location = new Point(hamp_v1TT.Right - ZXC.Qun4, 0);
         hamp_skladCd.Location = new Point(hamp_v1TT.Right - ZXC.Qun4, hamp_tt.Bottom - ZXC.Qun4);
         hamp_sklad2Cd.Location = new Point(hamp_v1TT.Right - ZXC.Qun4, hamp_skladCd.Bottom - ZXC.Qun4);

         hamp_dokDate2.Location = new Point(0, hamp_dokDate.Bottom - ZXC.Qun4);
      }
      else
      {
         hamp_napomena.Location = new Point(0, hamp_dokDate.Bottom - ZXC.Qun4);
         hamp_projekt .Location = new Point(0, hamp_napomena.Bottom - ZXC.Qun4);
         hamp_opis    .Location = new Point(0, hamp_napomena.Bottom);
         hamp_vezniDok.Location = new Point(hamp_napomena.Right - hamp_vezniDok.Width, hamp_dokNum.Bottom - ZXC.Qun4);
      }

      nextY = hamp_opis.Bottom;
   }

   public void SetParentOfHamperLeftHampers()
   {
      foreach(VvHamper hamper in hamperLeft)
      {
         if(hamper.IsDUMMY) continue;

         hamper.Parent = TheTabControl.TabPages[0];
      }
      if(hamperNoMigLeftRight != null)
      {
         panel_NoMigratorsRight = new Panel();
         panel_NoMigratorsRight.Parent = TheTabControl.TabPages[2];
         panel_NoMigratorsRight.Name = "panel_NoMigratorsRight";

         foreach(VvHamper hamper in hamperNoMigLeftRight)
         {
            hamper.Parent = panel_NoMigratorsRight;
         }
      }
   }

   private void CalcLocationHamperBeloWGrid()
   {
      if(this is FakturExtDUC)
      {
         hamp_twin.Location = new Point(TheSumGrid.Right - hamp_twin.Width + ZXC.Qun4, TheSumGrid.Bottom);
         hamp_twin.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;

         if(this is PIZpDUC || this is TransformDUC || this is ProizvodnjaDUC)
         {
            hamp_twin_pix.Location = new Point(TheSumGrid.Right - hamp_twin_pix.Width + ZXC.Qun4, TheSumGrid.Bottom);
            hamp_twin_pix.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
         }

         //30.01.2017.
         if(this is RNMDUC)
         {
            hamp_sumeRNM.Location = new Point(TheSumGrid.Right - hamp_sumeRNM.Width + ZXC.Qun4, TheSumGrid.Bottom);
            hamp_sumeRNM.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
         }

         if(this is UGNorAUN_PTG_DUC )
         {
            hamp_SumUGAN_PTG.Location = new Point(TheSumGrid.Right - hamp_SumUGAN_PTG.Width + ZXC.Qun4, TheSumGrid.Bottom);
            hamp_SumUGAN_PTG.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
         }


      }
      else
      {
         hamp_SukKC_K.Location = new Point(TheSumGrid.Right - hamp_SukKC_K.Width + ZXC.Qun4, TheSumGrid.Bottom);
         hamp_SukKC_K.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
      }
   }

