   public void SetUpColor(Color clrTampHeader, Color lblCrta, Color tabPagePoly)
   {

      // 14.02.2022: za potrebe 'FakturList_To_PDF' 
      if(TheVvTabPage == null) return;

      if(!clrTampHeader.IsEmpty) TheVvTabPage.tbx_col1.Tag = TheVvTabPage.tbx_col2.Tag = TheVvTabPage.tbx_col3.Tag = clrTampHeader;

      //if(!lblCrta.IsEmpty) ZXC.vvColors.tamponPanel_Crta = lblCrta;
      //else                 ZXC.vvColors.tamponPanel_Crta = Color.White;

      if(!lblCrta.IsEmpty) TheVvTabPage.labTamPanCrta.Tag = lblCrta;    // mora ovako jer mjenamo boje ovisno > crvena-sklad, narandjasta-mp, bijela - nesklad
      else TheVvTabPage.labTamPanCrta.Tag = Color.White;

      if(!tabPagePoly.IsEmpty)
      {
         ThePolyGridTabControl.TabPages[TabPageTitle1].Tag = tabPagePoly;
         ThePolyGridTabControl.TabPages[TabPageTitle2].Tag = tabPagePoly;
      }

      VvHamper.ApplyVVColorAndStyleTabCntrolChange(this);
      VvHamper.ApplyVVColorAndStyleTabCntrolChange(TheVvTabPage.labTamPanCrta);
   }

