   private void GridLocationAndSize_OPLgrid(VvDataGridViewFind theGrid, VvHamper hamperAboveDgv)
   {
      int heihgHamp = hamperAboveDgv.Height;

    //hamperAboveDgv.Location = new Point(theGrid.Left, ZXC.Qun4);
      hamperAboveDgv.Location = new Point(theGrid.Left, ZXC.Qun4);
      hamperAboveDgv.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right;

      theGrid.Location      = new Point(ZXC.QunMrgn, ZXC.QunMrgn + heihgHamp);
      theGrid.Parent.Size   = new Size(this.Width, this.Height);
      theGrid.Parent.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
      theGrid.Size          = new Size(this.Width - 2 * ZXC.QunMrgn, this.Height - ZXC.Q2un - heihgHamp);
      theGrid.Anchor        = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;

      //hamperAboveDgv.Location = new Point(theGrid.Left, ZXC.Qun4);
      //hamperAboveDgv.Anchor = AnchorStyles.Top | AnchorStyles.Left |AnchorStyles.Right;

   }

   private void GridLocationAndSize(VvDataGridViewFind rOnlygrid)
   {
      rOnlygrid.Dock = DockStyle.Fill;
      rOnlygrid.Location      = new Point(ZXC.QunMrgn, ZXC.QunMrgn                  );
      rOnlygrid.Parent.Size   = new Size(this.Width, this.Height);
      rOnlygrid.Parent.Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
      rOnlygrid.Size          = new Size(this.Width - 2 * ZXC.QunMrgn, this.Height - ZXC.Q2un                  );
      rOnlygrid.Anchor        = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom;
   }

   private void GridLocationAndSize_PTG_OplAndDodGrids(VvDataGridViewFind theGrid, int hapmBelowHeight)
   {
      DataGridView theSumGrid   = theGrid.TheLinkedGrid_Sum;

      theGrid.Height      = this.Height - ZXC.Q2un - theSumGrid.Height - hapmBelowHeight;

      theSumGrid.Width    = this.Width - 2 * ZXC.QunMrgn;
      theSumGrid.Location = new Point(theGrid.Location.X, theGrid.Bottom + ZXC.Qun12);
      theSumGrid.Anchor   = AnchorStyles.Bottom | AnchorStyles.Left | AnchorStyles.Right;

      theGrid.Scroll += new ScrollEventHandler(PTG_OplDodGridtheGrid_VScroll);
   }

