   #region Load OPL or DOD or UNA List and PutDgvFields

   public void Load_PTG_OPLlist_And_PutDgvFields()
   {
      int rowIdx, idxCorrector, colIdx;

      decimal sumaRata = 0.00M, sumaUGAN=0.00M, sumaDOD= 0.00M;

      PTG_Ugovor ugan_rec = new PTG_Ugovor(faktur_rec);

      PTG_OplLoaded = true;
      PTG_OplGrid.Rows.Clear();
      idxCorrector = GetDGVsIdxCorrrector(PTG_OplGrid);

      ugan_rec.LoadOtplatniPlan(TheDbConnection);

      ugan_rec.TheOtplatniPlan.GetAllRate_IFA_TtNum(TheDbConnection);

      foreach(PTG_Rata ptgRata in ugan_rec.TheOtplatniPlan.UGAN_RateList)
      {
         PTG_OplGrid.Rows.Add();

         rowIdx = PTG_OplGrid.RowCount - idxCorrector;

         colIdx = 0;

         //PTG_OplGrid[ 0, rowIdx].Value = rtrans_rec.T_recID     ;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.KOPfakStop ? "X" : "";
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.RataRbr;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.RataDate.ToString(ZXC.VvDateFormat);
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.RataMoney;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.UGANrataMoney;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.UkDODrataMoney;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.SomeInfo;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.RataKoef;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.RataSastav;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.DatumOd.ToString(ZXC.VvDateFormat);
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.DatumDo.ToString(ZXC.VvDateFormat);
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.RataDani;
       //PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.IsFirstRata ? "X" : "";
       //PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.IsLastRata  ? "X" : "";
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.IFA_TtNum.IsZero() ? "" : "IFA-" + ptgRata.IFA_TtNum.ToString();
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.KOPxtransNapomena;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.KOPxtransDate.Equals(DateTime.MinValue) ? "" : ptgRata.KOPxtransDate.ToString(ZXC.VvDateFormat);
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.KOPxtransAdduid;
         PTG_OplGrid[colIdx++, rowIdx].Value = ptgRata.HasKOP ? "X" : "";

         PTG_OplGrid.Rows[rowIdx].HeaderCell.Value = (rowIdx + 1).ToString();

         if(ptgRata.HasKOP              ) PTG_OplGrid.Rows[rowIdx].DefaultCellStyle.BackColor = Color.FromArgb(250, 227, 227);  
         if(ptgRata.RataRbr.IsNegative()) PTG_OplGrid.Rows[rowIdx].DefaultCellStyle.ForeColor = Color.DarkViolet;

         if(ptgRata.KOPfakStop          ) PTG_OplGrid.Rows[rowIdx].DefaultCellStyle.BackColor = Color.FromArgb(255, 164, 164);

         if(ptgRata.RataDate.Year < ZXC.projectYearAsInt && ptgRata.IFA_TtNum.NotZero()) PTG_OplGrid.Columns["IFA broj"].DataGridView.Rows[rowIdx].DefaultCellStyle.ForeColor = Color.Gray;


         sumaRata += ptgRata.RataMoney;
         sumaUGAN += ptgRata.UGANrataMoney;
         sumaDOD  += ptgRata.UkDODrataMoney;
      }

      int sumaRata_CI = PTG_OplGrid.IdxForColumn("Rata Iznos");
      int sumaUGAN_CI = PTG_OplGrid.IdxForColumn("UG Iznos");
      int sumaDOD_CI  = PTG_OplGrid.IdxForColumn("DOD Iznos");

      PTG_OplGrid_SumGrid[sumaRata_CI, 0].Value = sumaRata;
      PTG_OplGrid_SumGrid[sumaUGAN_CI, 0].Value = sumaUGAN;
      PTG_OplGrid_SumGrid[sumaDOD_CI , 0].Value = sumaDOD;

      UGNorAUN_PTG_DUC ptgDUC = this as UGNorAUN_PTG_DUC;
      ptgDUC.Fld_NumOf_OtPlan_Rows_UK          = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_UK         ;
      ptgDUC.Fld_NumOf_OtPlan_Rows_UgPredRata  = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_UgPredRata ;
      ptgDUC.Fld_NumOf_OtPlan_Rows_UgBrojRata  = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_UgBrojRata ;
      ptgDUC.Fld_NumOf_OtPlan_Rows_DodPredRata = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_DodPredRata;
      ptgDUC.Fld_NumOf_OtPlan_Rows_KorekRata   = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_KorekRata  ;
      ptgDUC.Fld_NumOf_OtPlan_Rows_OtkupRata   = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_OtkupRata  ;
      ptgDUC.Fld_NumOf_OtPlan_Rows_OsnovRate   = ugan_rec.TheOtplatniPlan.NumOf_OtPlan_Rows_OsnovRate  ;
   }

