   List<Ftrans> saldaKonti_ftransList;
   public override void LoadRecordList_AND_PutTransDgvFields()
   {
      int rowIdx, idxCorrector;

      if(saldaKonti_ftransList == null) saldaKonti_ftransList = new List<Ftrans>();
      else                              saldaKonti_ftransList.Clear();

      VvDaoBase.LoadGenericVvDataRecordList<Ftrans>(TheDbConnection, saldaKonti_ftransList, SetFilterMembers4LoadFtranses(faktur_rec/*.RecID*/), "t_dokDate ASC, t_dokNum ASC, t_serial ASC");

      ftransesLoaded = true;

      ftransGrid.Rows.Clear();

      idxCorrector = GetDGVsIdxCorrrector(ftransGrid);

      decimal ukRac = 0.00M, ukUpl = 0.00M, ukDug = 0.00M;

      foreach(Ftrans ftrans_rec in saldaKonti_ftransList)
      {
         ftransGrid.Rows.Add();

         rowIdx = ftransGrid.RowCount - idxCorrector;

         if(faktur_rec.TtInfo.IsUlazniPdvTT) // URA, ... 
         {
            if(ftrans_rec.T_otsKind == ZXC.OtsKindEnum.OTVARANJE) { ukRac = ftrans_rec.T_pot - ftrans_rec.T_dug; ukUpl = 0.00M;                               }
            else                                                  { ukRac = 0.00M;                               ukUpl = ftrans_rec.T_dug - ftrans_rec.T_pot; }
         }
         else // IRA, ... 
         {
            if(ftrans_rec.T_otsKind == ZXC.OtsKindEnum.OTVARANJE) { ukRac = ftrans_rec.T_dug - ftrans_rec.T_pot; ukUpl = 0.00M;                               }
            else                                                  { ukRac = 0.00M;                               ukUpl = ftrans_rec.T_pot - ftrans_rec.T_dug; }
         }

         ukDug += ukRac - ukUpl;

         ftransGrid[0, rowIdx].Value = ftrans_rec.T_parentID;
         ftransGrid[1, rowIdx].Value = ftrans_rec.T_dokDate;
         ftransGrid[2, rowIdx].Value = ftrans_rec.T_dokNum;
         ftransGrid[3, rowIdx].Value = ftrans_rec.T_serial;
         ftransGrid[4, rowIdx].Value = ftrans_rec.T_TT;
         ftransGrid[5, rowIdx].Value = ftrans_rec.T_opis;
         ftransGrid[6, rowIdx].Value = /* RACUN; */ ukRac;
         ftransGrid[7, rowIdx].Value = /* UPLATA */ ukUpl;
         ftransGrid[8, rowIdx].Value = /* STANJE */ ukDug;

         ftransGrid.Rows[rowIdx].HeaderCell.Value = (rowIdx + 1).ToString();
      }

   }

   private List<VvSqlFilterMember> SetFilterMembers4LoadFtranses(Faktur faktur_rec)
   {
      List<VvSqlFilterMember> filterMembers = new List<VvSqlFilterMember>(2);

      uint fakturRecID = faktur_rec.RecID;

      filterMembers.Add(new VvSqlFilterMember(ZXC.FtransSchemaRows[ZXC.FtrCI.t_fakRecID], false, "", fakturRecID, "", "", " = ", ""));
    //filterMembers.Add(new VvSqlFilterMember(ZXC.FtransSchemaRows[ZXC.FtrCI.t_konto]   , false, "", fakturRecID, "", "", " = ", ""));

      if(faktur_rec.TtInfo.IsExtendableTT == true &&
         faktur_rec.TtInfo.IsBlagajnaTT == false)
      {
         filterMembers.Add(new VvSqlFilterMember("SUBSTRING(t_konto, 1, 2)", "('12', '22')", " IN "));
      }

      return filterMembers;
   }

   public /*override*/ void Load_Realizac_RtransList_AND_PutTransDgvFields() // RNM & UGO 
   {
      bool isRNM = this is RNMDUC; // !!! 

      int rowIdx, idxCorrector, colIdx;

      IVvRealizableFakturDUC realizableFakturDUC = this as IVvRealizableFakturDUC;

      if(isRNM)
      {
         realizableFakturDUC.RealizRtrList_AllYears = RtransDao.GetRtransList_ForProjektCD(TheDbConnection, faktur_rec.ProjektCD, "t_tt DESC, " + Rtrans.artiklOrderBy_ASC);
      }
      else // isUGO 
      {
         realizableFakturDUC.RealizRtrList_AllYears = new List<Rtrans>();

         List<Rtrans> rtransList_For_UGO_Artikl;

         foreach(Rtrans rtrans in faktur_rec.Transes)
         {
            rtransList_For_UGO_Artikl = RtransDao.Get_RtransList_For_TT_Artikl_Kupdob_Dates(TheDbConnection, Faktur.TT_URA,
               rtrans.T_artiklCD, // artiklCD 
               rtrans.T_kupdobCD, // kupdobCD 
                 Fld_DokDate/*ZXC.prevYearFirstDay*/ , // dateOD   ... prosla i ova godina! 
               (this as UGODUC).Fld_DospDate); // dateDO   !? 

            realizableFakturDUC.RealizRtrList_AllYears.AddRange(rtransList_For_UGO_Artikl);
         }
      }

      realizableFakturDUC.RealizRtrList_ThisYear = new List<Rtrans>(realizableFakturDUC.RealizRtrList_AllYears.Where(rtr => rtr.R_utilBool == false));

      #region PutTransDgvFields()

      realizacRrtransesLoaded = true;

      RealizacGrid.Rows.Clear();

      idxCorrector = GetDGVsIdxCorrrector(RealizacGrid);

      foreach(Rtrans rtrans_rec in realizableFakturDUC.RealizRtrList_AllYears)
      {
         RealizacGrid.Rows.Add();

         rowIdx = RealizacGrid.RowCount - idxCorrector;

         colIdx = 0;

       //RNM_Grid[ 0, rowIdx].Value = rtrans_rec.T_recID     ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_parentID  ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_TT        ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_ttNum     ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_serial    ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_skladDate ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_skladCD   ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_artiklCD  ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_artiklName;
if(isRNM)RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_serlot    ;
         RealizacGrid[ colIdx++, rowIdx].Value = rtrans_rec.T_kol       ;
         if(isRNM && rtrans_rec.NeedsPpmvOr_kolOPvalues)
         {
            RealizacGrid[colIdx++, rowIdx].Value = rtrans_rec.T_ppmvOsn;  // dodano 27.01.2017.
            RealizacGrid[colIdx++, rowIdx].Value = rtrans_rec.R_kolOP  ;  // dodano 27.01.2017.
            RealizacGrid[colIdx++, rowIdx].Value = rtrans_rec.R_cijOP  ;  // dodano 27.01.2017.
         }
         RealizacGrid[colIdx++, rowIdx].Value = rtrans_rec.T_cij       ;
         RealizacGrid[colIdx++, rowIdx].Value = rtrans_rec.R_KCR       ;

         RealizacGrid.Rows[rowIdx].HeaderCell.Value = (rowIdx + 1).ToString();

         if(rtrans_rec.TtInfo.IsRadNalPUcijTT)
         {
            RealizacGrid.Rows[rowIdx].DefaultCellStyle.BackColor = Color.PaleGreen;
         }
         if(rtrans_rec.R_utilBool) // PG rtrans 
         {
            RealizacGrid.Rows[rowIdx].DefaultCellStyle.ForeColor = Color.FromArgb(122, 145, 158);
         }
      }

      #endregion PutTransDgvFields()

      // 01/10.2018: 
      if(isRNM == false) return; // !!! ... dole su stvari koje idu samo na RNM-ovu realizaciju 

      RNMstatus theRNMstatus = new RNMstatus(faktur_rec, faktur_rec.Transes, /* ppr_pip_RtransListOG */ realizableFakturDUC.RealizRtrList_ThisYear);

      RNMDUC theRNMDUC = this as RNMDUC;

      // 07.03.2017: 
      decimal RI_razd = FtransDao.Get_RI_razd_ForProjektCD(TheDbConnection, faktur_rec.ProjektCD, ZXC.projectYearFirstDay, ZXC.projectYearLastDay, ZXC.KSD);
      theRNMDUC.Fld_AIndir           = RI_razd                      ; // (Aindir)            VOILA! 

      theRNMDUC.Fld_ukFinIzlazUK     = theRNMstatus.ukFinIzlazUK    ; // Auk                        
      theRNMDUC.Fld_ukFinUlazOG      = theRNMstatus.ukFinUlazOG     ; // Cog                        
      theRNMDUC.Fld_ukKolUlazOG      = theRNMstatus.ukKolUlazOG     ; // za ncPerUlKol              
      theRNMDUC.Fld_finDiff          = theRNMstatus.finDiff         ; // (Cog-Auk)                  
      theRNMDUC.Fld_ukKolKgUlazOG    = theRNMstatus.ukKolKgUlazOG   ; // Bog                        
      theRNMDUC.Fld_ukFinIzlazPG     = theRNMstatus.ukFinIzlazPG    ; // ApgUk                      
      theRNMDUC.Fld_ukKolKgUlazPG    = theRNMstatus.ukKolKgUlazPG   ; // Bpg                        
      theRNMDUC.Fld_ukFinNedovrIzlPG = theRNMstatus.ukFinNedovrIzlPG; // Apg                        
      theRNMDUC.Fld_ukFinIzlazOG     = theRNMstatus.ukFinIzlazOG    ; // Aog                        
      theRNMDUC.Fld_ncPerUlKol       = theRNMstatus.ncPerUlKol      ; // (Auk / ukKolUlazOG)        
      theRNMDUC.Fld_ncPerUlKolKg     = theRNMstatus.ncPerUlKolKg    ; // (Auk / Bog)         VOILA! 

      #region Check Descrepancies

      bool hasArtiklDescrepancy   = Get_hasArtiklDescrepancy  (faktur_rec.Transes, ((IVvRealizableFakturDUC)this).RealizRtrList_AllYears.Where(rtr => rtr.T_TT == Faktur.TT_PPR || rtr.T_TT == Faktur.TT_PIP));
      bool hasKolicinaDescrepancy = Get_hasKolicinaDescrepancy(faktur_rec.Transes, ((IVvRealizableFakturDUC)this).RealizRtrList_AllYears.Where(rtr => rtr.T_TT == Faktur.TT_PPR || rtr.T_TT == Faktur.TT_PIP));
      bool hasSerlotDescrepancy   = Get_hasSerlotDescrepancy  (faktur_rec.Transes, ((IVvRealizableFakturDUC)this).RealizRtrList_AllYears.Where(rtr => rtr.T_TT == Faktur.TT_PPR || rtr.T_TT == Faktur.TT_PIP));
                                                                                   
      bool hasDescrepancy = hasArtiklDescrepancy || hasKolicinaDescrepancy || hasSerlotDescrepancy;

      ((RNMDUC)this).tbx_diffAKS.JAM_BackColor = ZXC.vvColors.vvTBoxReadOnly_True_BackColor;
      ((RNMDUC)this).tbx_diffAKS.Text = "";

      if(hasDescrepancy)
      {
         ((RNMDUC)this).tbx_diffAKS.JAM_BackColor = Color.Red;
         if(hasArtiklDescrepancy  ) ((RNMDUC)this).tbx_diffAKS.Text += "A";
         if(hasKolicinaDescrepancy) ((RNMDUC)this).tbx_diffAKS.Text += "K";
         if(hasSerlotDescrepancy  ) ((RNMDUC)this).tbx_diffAKS.Text += "S";

      }
      //else
      //{
      //   ((RNMDUC)this).tbx_diffAKS.JAM_BackColor = ZXC.vvColors.vvTBoxReadOnly_True_BackColor;
      //   ((RNMDUC)this).tbx_diffAKS.Text = "";
      //}
     
      VvHamper.ApplyVVColorAndStyleTabCntrolChange(((RNMDUC)this).tbx_diffAKS);

      #endregion Check Descrepancies

      theRNMDUC.Fld_RNM_StupanjDovrsenostiPG                                                  = 100M * theRNMstatus.koefDovrsPG    ; // Spg      
      theRNMDUC.Fld_RNM_StupanjDovrsenostiOG                                                  = 100M * theRNMstatus.koefDovrsOG    ; // Sog      
      theRNMDUC.Fld_RNM_StupanjDovrsenosti     = theRNMDUC.Fld_RNM_StupanjDovrsenostiTwin     = 100M * theRNMstatus.koefDovrsUK    ; // Suk      
      theRNMDUC.Fld_RNM_RealStupanjDovrsenosti = theRNMDUC.Fld_RNM_RealStupanjDovrsenostiTwin = 100M * theRNMstatus.koefDovrsUKreal; // Suk Real 

      //theRNMDUC.lbl_donosPG      .Visible =
      //theRNMDUC.lbl_ukFinIzlazPG .Visible =
      //theRNMDUC.lbl_ukKolOpUlazPG.Visible =
      //theRNMDUC.tbx_ukFinIzlazPG .Visible =
      //theRNMDUC.tbx_ukKolOpUlazPG.Visible = this.Fld_DokDate < ZXC.projectYearFirstDay;

      bool isPg = this.Fld_DokDate < ZXC.projectYearFirstDay;
      theRNMDUC.hamp_pg                     .Visible = isPg;
      theRNMDUC.lbl_aog                     .Visible = isPg;
      theRNMDUC.lbl_sog                     .Visible = isPg;
      theRNMDUC.tbx_ukFinIzlazOG            .Visible = isPg;
      theRNMDUC.tbx_RNM_StupanjDovrsenostiOG.Visible = isPg;

      theRNMDUC.lbl_auk.Text = isPg ? "PPR FinUk(Auk=(Apg+Aog)*Sog):"                      : "PPR FinUk(A):"                                  ;
      theRNMDUC.lbl_bog.Text = isPg ? "PIP " + ZXC.RRD.Dsc_OrgPakText + "(Bog):"           : "PIP " + ZXC.RRD.Dsc_OrgPakText + "(B):"         ;
      theRNMDUC.lbl_cog.Text = isPg ? "PIP Fin(Cog):"                                      : "PIP Fin(C):"                                    ;
      theRNMDUC.lbl_aB .Text = isPg ? "PIP Cij po " + ZXC.RRD.Dsc_OrgPakText + "(Auk/Bog):": "PIP Cij po " + ZXC.RRD.Dsc_OrgPakText + "(A/B):";
      theRNMDUC.lbl_cA .Text = isPg ? "Razlika(Cog-Auk):"                                  : "Razlika(C-A):"                                  ;



   }

   public /*override*/ void Load_FakLink_fakturList_AND_PutFakturDgvFields()
   {
      int rowIdx, idxCorrector;

      List<Faktur> fakLinkFakturList = RtransDao.GetFakturList_ByVezaTtAndTtNumOrProjektCD(TheDbConnection, faktur_rec);

      if(ZXC.IsSvDUH && (this is URA_SVD_DUC || this is NRD_SVD_DUC))
      {
         fakLinkFakturList.AddRange(UGOfakturListForURA.Distinct().ToList());
      }

      fakLinkLoaded = true;

      fakLinkGrid.Rows.Clear();

      idxCorrector = GetDGVsIdxCorrrector(fakLinkGrid);

      foreach(Faktur linkedFaktur_rec in fakLinkFakturList)
      {
         fakLinkGrid.Rows.Add();

         rowIdx = fakLinkGrid.RowCount - idxCorrector;

         fakLinkGrid[ 0, rowIdx].Value = linkedFaktur_rec.RecID     ;
         fakLinkGrid[ 1, rowIdx].Value = linkedFaktur_rec.TT        ;
         fakLinkGrid[ 2, rowIdx].Value = linkedFaktur_rec.TtNum     ;
         fakLinkGrid[ 3, rowIdx].Value = linkedFaktur_rec.DokDate   ;
         fakLinkGrid[ 4, rowIdx].Value = linkedFaktur_rec.KupdobName;
         fakLinkGrid[ 5, rowIdx].Value = linkedFaktur_rec.VezniDok  ;

         fakLinkGrid[ 6, rowIdx].Value = linkedFaktur_rec.ProjektCD                                                ; if(faktur_rec.ProjektCD    == linkedFaktur_rec.ProjektCD && faktur_rec.ProjektCD.NotEmpty())              BoldThisCell(rowIdx, 6);
         fakLinkGrid[ 7, rowIdx].Value = Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V1_tt, linkedFaktur_rec.V1_ttNum); if(faktur_rec.TT_And_TtNum == Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V1_tt, linkedFaktur_rec.V1_ttNum)) BoldThisCell(rowIdx, 7);
         fakLinkGrid[ 8, rowIdx].Value = Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V2_tt, linkedFaktur_rec.V2_ttNum); if(faktur_rec.TT_And_TtNum == Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V2_tt, linkedFaktur_rec.V2_ttNum)) BoldThisCell(rowIdx, 8);
         fakLinkGrid[ 9, rowIdx].Value = Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V3_tt, linkedFaktur_rec.V3_ttNum); if(faktur_rec.TT_And_TtNum == Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V3_tt, linkedFaktur_rec.V3_ttNum)) BoldThisCell(rowIdx, 9);
         fakLinkGrid[10, rowIdx].Value = Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V4_tt, linkedFaktur_rec.V4_ttNum); if(faktur_rec.TT_And_TtNum == Faktur.Set_TT_And_TtNum(linkedFaktur_rec.V4_tt, linkedFaktur_rec.V4_ttNum)) BoldThisCell(rowIdx,10);

         fakLinkGrid[11, rowIdx].Value = linkedFaktur_rec.Napomena        ;
         fakLinkGrid[12, rowIdx].Value = linkedFaktur_rec.S_ukKC_OR_ukKCRP;
         
         fakLinkGrid.Rows[rowIdx].HeaderCell.Value = (rowIdx + 1).ToString();
      }

   }

   private void BoldThisCell(int rowIdx, int colIdx)
   {
      fakLinkGrid[colIdx, rowIdx].Style.BackColor = Color.LightBlue;
   }

   private bool Get_hasArtiklDescrepancy(List<Rtrans> rtransesRNM, IEnumerable<Rtrans> rtransesPIPR)
   {
      var RNMartiklCDs  = rtransesRNM .Select(rtr => rtr.T_artiklCD).Distinct();
      var PIPRartiklCDs = rtransesPIPR.Select(rtr => rtr.T_artiklCD).Distinct();
      var intersect     = RNMartiklCDs.Intersect(PIPRartiklCDs);

      if(RNMartiklCDs .Count() != intersect.Count() ||
         PIPRartiklCDs.Count() != intersect.Count())
      {
         return true;
      }
      return false;
   }

   private bool Get_hasKolicinaDescrepancy(List<Rtrans> rtransesRNM, IEnumerable<Rtrans> rtransesPIPR)
   {
      if(ZXC.AlmostEqual(rtransesRNM.Sum(rtr => rtr.T_kol), rtransesPIPR.Sum(rtr => rtr.T_kol), 0.01M) == false) return true ;
      else                                                                                                       return false;
   }

   private bool Get_hasSerlotDescrepancy(List<Rtrans> rtransesRNM, IEnumerable<Rtrans> rtransesPIPR)
   {
      var RNMserlots = rtransesRNM .Select(rtr => rtr.T_serlot).Distinct();
      var PIPserlots = rtransesPIPR.Select(rtr => rtr.T_serlot).Distinct();
      var intersect  = RNMserlots.Intersect(PIPserlots);

      if(RNMserlots.Count() != intersect.Count() ||
         PIPserlots.Count() != intersect.Count())
      {
         return true;
      }
      return false;
   }                   

   #endregion Put Ftrans & RNM DGV Fileds
   
}

