   private void AddTabPagesResultProsireno()
   {
      //02.02.2022. na UGAN i DOD ne trebaju tabovi Sume i Prošitreno
      bool ovajDucNetrebaSumeProsireno = this is KUG_PTG_DUC || this is A1_KUG_PTG_DUC || this is UGNorAUN_PTG_DUC || this is DOD_PTG_DUC || this is PRN_DOD_PTG_DUC || this is MOD_PTG_DUC;

      if(!ovajDucNetrebaSumeProsireno)
      {
         TheTabControl.TabPages.Add(CreateVvInnerTabPages("Sume"     , "Sume"     , ZXC.VvInnerTabPageKindEnum.ReadWrite_TabPage));
         TheTabControl.TabPages.Add(CreateVvInnerTabPages("Prošireno", "Prosireno", ZXC.VvInnerTabPageKindEnum.ReadWrite_TabPage));
      }

      TheTabControl.TabPages.Add(CreateVvInnerTabPages("Zoom", "Zoom", ZXC.VvInnerTabPageKindEnum.ReadWrite_TabPage));


      if(this is UFADUC || this is URADUC || this is URPDUC || this is OdobrDobavDUC || this is PovratKupcaDUC ||
         this is IFADUC || this is IRADUC || this is IRPDUC || this is OdobrKupcuDUC || this is PovratDobaDUC ||
         this is IRMDUC || this is IRMDUC_2 || this is URMDUC || this is UFMDUC ||
         this is BlgIsplatDUC || this is BlgUplatDUC || this is BlgIsplat_M_DUC || this is BlgUplat_M_DUC || this is WYRNDUC)
         TheTabControl.TabPages.Add(CreateVvInnerTabPages(ftrans_TabPageName, ftrans_TabPageName, ZXC.VvInnerTabPageKindEnum.TransGrid_TabPage));

      // 22.04.2016. veze
      //07.02.2022. za UGAN i DOD dodan if
      if(!ovajDucNetrebaSumeProsireno)
      {
         TheTabControl.TabPages.Add(CreateVvInnerTabPages(fakLink_TabPageName, fakLink_TabPageName, ZXC.VvInnerTabPageKindEnum.TransGrid_TabPage));
      }

      TheTabControl.SelectionChanged += new Crownwood.DotNetMagic.Controls.SelectTabHandler(TheTabControl_SelectionChanged_OsnovnoResult);
   }

   private void TheTabControl_SelectionChanged_OsnovnoResult(Crownwood.DotNetMagic.Controls.TabControl sender, Crownwood.DotNetMagic.Controls.TabPage oldPage, Crownwood.DotNetMagic.Controls.TabPage newPage)
   {
      if(TheVvTabPage != null && TheVvTabPage.IsArhivaTabPage) return;

      if(TheVvTabPage != null && ((VvInnerTabPage)newPage) != null && ((VvInnerTabPage)newPage).TheInnerTabPageKindEnum == ZXC.VvInnerTabPageKindEnum.ReportViewer_TabPage) return;
      if(TheVvTabPage != null && ((VvInnerTabPage)newPage) != null && ((VvInnerTabPage)newPage).TheInnerTabPageKindEnum == ZXC.VvInnerTabPageKindEnum.TransGrid_TabPage)
      {
         ThePanelForFilterUC_PrintTemplateUC.Visible = false;
         ftransGrid.TabStop = false;
         ftransGrid.ClearSelection();
         return;
      }

      if(newPage.Name == "Zoom")
      {
         ThePolyGridTabControl.Parent = (VvInnerTabPage)newPage;
         ControlUnderMigLeftParentA.Location = Point.Empty;
         CalcLocationSizeAnchor_ThePolyGridTabControl(ThePolyGridTabControl.Parent, nextX, 0);
      }
      else if(newPage.Name == "Prosireno" && (this is IRMDUC || this is KIZDUC || this is PIKDUC)) // ovo je zato sto oni nemaju grid na prosirenom jer imaju hamp sa osnovno
      {
      }
      else
      {
         ThePolyGridTabControl.Parent = (VvInnerTabPage)newPage;
         if(newPage.Name == "Osnovno") CalcLocationSizeAnchor_ThePolyGridTabControl(ThePolyGridTabControl.Parent, nextX, CalcRazmakZaPolyGridTabControl());
         else if(newPage.Name == "Sume") CalcLocationSizeAnchor_ThePolyGridTabControl(ThePolyGridTabControl.Parent, nextX, CalcRazmakZaPolyGridTabControl_Sume());
         else if(newPage.Name == "Prosireno") CalcLocationSizeAnchor_ThePolyGridTabControl(ThePolyGridTabControl.Parent, nextX, CalcRazmakZaPolyGridTabControl_Prosireno());
      }

      if(newPage.Name == "Osnovno" && (this is PocetnoStanjeMPDUC || this is InventuraMPDUC || this is NivelacijaDUC ||
                                       this is MedjuSkladVMIuDUC || this is MedjuSkladMVIDUC || this is MedjuSkladMMIDUC || this is MedjuSkladVMI2DUC ||
                                       this is PIZpDUC || this is TransformDUC || this is ProizvodnjaDUC || this is MedjuSkladMVI2DUC
                                       )) panel_MigratorsLeftB.SendToBack();


   }
