   private void InitializeHamper_kupdobNaziv(out VvHamper hamper)
   {
      hamper = new VvHamper(4, 1, "", null, false);

           if(this is ZAH_SVD_DUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q3un - ZXC.Qun2, ZXC.Q3un - ZXC.Qun4, ZXC.Q10un * 2 + ZXC.Qun8 + 3 * faBefCol + faBefFirstCol +ZXC.Q3un};
      else if(this is MOD_PTG_DUC) hamper.VvColWdt = new int[] { labelWidth, ZXC.Q3un - ZXC.Qun2, ZXC.Q3un - ZXC.Qun4, ZXC.Q10un + ZXC.Q4un - ZXC.Qun4 - ZXC.Qun12 };
      else                         hamper.VvColWdt = new int[] { labelWidth, ZXC.Q3un - ZXC.Qun2, ZXC.Q3un - ZXC.Qun4, ZXC.Q10un * 2 + ZXC.Qun8 + 3 * faBefCol + faBefFirstCol };

      hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol, faBefCol, faBefCol };

      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt       = new int[] { ZXC.QUN + ZXC.Qun8 };
      hamper.VvSpcBefRow    = new int[] { ZXC.Qun4 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      string text = "Partner:";

           if(IsRadNalog         ) text = "Nar/Invest:";
      else if(this is IZMDUC_2   ) text = "Gost:";
      else if(this is ZAH_SVD_DUC) text = "Odjel:";
      else                         text = "Partner:";

                       hamper.CreateVvLabel  (0, 0, text, ContentAlignment.MiddleRight);
      tbx_KupdobCd   = hamper.CreateVvTextBox(1, 0, "tbx_kupdobCd", "Sifra partnera", 6);
      tbx_KupdobTk   = hamper.CreateVvTextBox(2, 0, "tbx_kupdobTk", "Ticker partnera", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.kupdobTK));
      tbx_KupdobName = hamper.CreateVvTextBox(3, 0, "tbx_kupdobName", "Naziv partnera", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.kupdobName));

      // 04.12.2015: 
      tbx_KupdobCd.JAM_MustTabOutBeforeSubmit =
      tbx_KupdobTk.JAM_MustTabOutBeforeSubmit =
      tbx_KupdobName.JAM_MustTabOutBeforeSubmit = true;

      tbx_KupdobCd.JAM_CharEdits = ZXC.JAM_CharEdits.DigitsOnly;
      //  tbx_KupdobCd.JAM_FillCharacter = '0';
      tbx_KupdobTk.JAM_CharacterCasing = CharacterCasing.Upper;
      tbx_KupdobName.JAM_Highlighted = true;

      this.ControlForInitialFocus = tbx_KupdobName;

      if(this is KIZDUC || this is PIKDUC)
      {
         tbx_KupdobCd.JAM_SetAutoCompleteData(Kupdob.recordName, Kupdob.sorterKCD.SortType, ZXC.AutoCompleteRestrictor.KID_Komisija_Only, new EventHandler(OnVvTBEnter_SetAutocmplt_Kupdob_sorterSifra), new EventHandler(AnyKupdobTextBoxLeave));
         tbx_KupdobTk.JAM_SetAutoCompleteData(Kupdob.recordName, Kupdob.sorterTicker.SortType, ZXC.AutoCompleteRestrictor.KID_Komisija_Only, new EventHandler(OnVvTBEnter_SetAutocmplt_Kupdob_sorterTicker), new EventHandler(AnyKupdobTextBoxLeave));
         tbx_KupdobName.JAM_SetAutoCompleteData(Kupdob.recordName, Kupdob.sorterNaziv.SortType, ZXC.AutoCompleteRestrictor.KID_Komisija_Only, new EventHandler(OnVvTBEnter_SetAutocmplt_Kupdob_sorterName), new EventHandler(AnyKupdobTextBoxLeave));
      }
      else
      {
         tbx_KupdobCd.JAM_SetAutoCompleteData(Kupdob.recordName, Kupdob.sorterKCD.SortType, new EventHandler(OnVvTBEnter_SetAutocmplt_Kupdob_sorterSifra), new EventHandler(AnyKupdobTextBoxLeave));
         tbx_KupdobTk.JAM_SetAutoCompleteData(Kupdob.recordName, Kupdob.sorterTicker.SortType, new EventHandler(OnVvTBEnter_SetAutocmplt_Kupdob_sorterTicker), new EventHandler(AnyKupdobTextBoxLeave));
         tbx_KupdobName.JAM_SetAutoCompleteData(Kupdob.recordName, Kupdob.sorterNaziv.SortType, new EventHandler(OnVvTBEnter_SetAutocmplt_Kupdob_sorterName), new EventHandler(AnyKupdobTextBoxLeave));
      }

      tbx_KupdobCd.DoubleClick += new EventHandler(AnyKupdobTextBox_DoubleClick);
      tbx_KupdobTk.DoubleClick += new EventHandler(AnyKupdobTextBox_DoubleClick);
      tbx_KupdobName.DoubleClick += new EventHandler(AnyKupdobTextBox_DoubleClick);

      //tbx_KupdobCd  .Font = ZXC.vvFont.LargeFont;
