   private void InitializeHamper_VezniDok2(out VvHamper hamper)
   {
      hamper = new VvHamper(3, 1, "", null, false);

      //03.12.2019.
    //hamper.VvColWdt    = new int[] { labelWidth, ZXC.Q3un, ZXC.Q7un + ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + faBefCol };
