      {
      //hamper.VvColWdt    = new int[] { labelWidth, ZXC.Q3un, ZXC.Q6un};
        hamper.VvColWdt    = new int[] { labelWidth, ZXC.Q4un + ZXC.Qun4- faBefCol, 0 };
      }
      else
      {
         hamper.VvColWdt    = new int[] { labelWidth, ZXC.Q3un, ZXC.Q7un + ZXC.Q2un - ZXC.Qun2 - ZXC.Qun4 + faBefCol };
      }

      hamper.VvSpcBefCol = new int[] { faBefFirstCol, faBefCol, faBefCol };

      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt = new int[] { ZXC.QUN };
      hamper.VvSpcBefRow = new int[] { ZXC.Qun8 };
      hamper.VvBottomMargin = hamper.VvTopMargin;


      string text = IsRadNalog ? "Zahtjev:" : "VezniDok2:";
      if(this is IRPDUC     ) text = "Težina:"   ;
      if(this is WYRNDUC    ) text = "Broj u PG:";
      if(this is RNMDUC     ) text = "Standard:" ;
      if(this is RNZDUC     ) text = "Ugovor:"   ;
      if(this is URA_SVD_DUC) text = "KnjigBr:"  ;

      //KtoShemaDsc KSD = new KtoShemaDsc(ZXC.dscLuiLst_KtoShema);
      KtoShemaDsc KSD = ZXC.KSD;

      // 08.01.2015. ako su WYR dokumenti - dokumenti PG onda tu vise nije bitna pozicija jer su dokumenti proknjizeni u prosloj godini
      //if(ZXC.CURR_prjkt_rec.IsNeprofit == true || KSD.Dsc_IsVisibleColPozicija == true)
      if((ZXC.CURR_prjkt_rec.IsNeprofit == true || KSD.Dsc_IsVisibleColPozicija == true) && (this is WYRNDUC == false))
      {
         hamper.CreateVvLabel(0, 0, "Pozicija", ContentAlignment.MiddleRight);
         VvLookUpLista.LoadResultLuiList_PozicijePlana_PLN_or_RLZ(/* isPLN */ false);
         tbx_VezniDok2 = hamper.CreateVvTextBoxLookUp(1, 0, "tbx_VezniDok2", "Pozicija", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.vezniDok2));
         tbx_VezniDok2Opis = hamper.CreateVvTextBox(2, 0, "tbx_VezniDok2Op", "Pozicija opis");
         tbx_VezniDok2.JAM_Set_LookUpTable(ZXC.luiListaPozicijePlanaRLZ, (int)ZXC.Kolona.prva);
         tbx_VezniDok2.JAM_lui_NameTaker_JAM_Name = tbx_VezniDok2Opis.JAM_Name;
      }
      // 15.10.2015. i fomd i neprofit imaju na istoj poziciju a Fond je preseljen na Fco
      //else if(KSD.Dsc_IsVisibleColFond == true)
      //{
      //                       hamper.CreateVvLabel        (0, 0, "Fond", ContentAlignment.MiddleRight);
      //   tbx_VezniDok2     = hamper.CreateVvTextBoxLookUp(1, 0, "tbx_VezniDok2"  , "Fond"     , GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.vezniDok2));
      //   tbx_VezniDok2Opis = hamper.CreateVvTextBox      (2, 0, "tbx_VezniDok2Op", "Fond opis");
      //   tbx_VezniDok2.JAM_Set_LookUpTable(ZXC.luiListaFinFond, (int)ZXC.Kolona.prva);
      //   tbx_VezniDok2.JAM_lui_NameTaker_JAM_Name = tbx_VezniDok2Opis.JAM_Name;
      //}
      else
      {

         hamper.CreateVvLabel(0, 0, text, ContentAlignment.MiddleRight);
         tbx_VezniDok2 = hamper.CreateVvTextBox(1, 0, "tbx_VezniDok2", (this is WYRNDUC) ? "Originalni broj računa iz prošlih godina" : "VezniDok2", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.vezniDok2), 1, 0);
      }
      //if(ZXC.CURR_prjkt_rec.IsNeprofit == true)
      //{

      //   tbx_VezniDok2.JAM_Set_LookUpTable(ZXC.luiListaPozicijePlanaRLZ, (int)ZXC.Kolona.prva);
      //   tbx_VezniDok2.JAM_lui_NameTaker_JAM_Name = tbx_VezniDok2Opis.JAM_Name;
      //}

      if(this is WYRNDUC)
      {
         tbx_VezniDok2.JAM_Highlighted = true;
         tbx_VezniDok2.JAM_ForeColor = Color.DarkBlue;
         tbx_VezniDok2.JAM_ReadOnly = true;
      }

      if(this is RNMDUC) tbx_VezniDok2.JAM_IsSupressTab = false;

      if(this is RNZDUC)
      {
         tbx_VezniDok2.JAM_IsSupressTab = false;
         tbx_VezniDok2.JAM_ReadOnly = true;
      }

      if(this is URA_SVD_DUC) tbx_VezniDok2.JAM_CharEdits = ZXC.JAM_CharEdits.DigitsOnly;

      hamper.Name = "AVezDok2:";

   }
