   public void AnyPersonTextBoxLeave(object sender, EventArgs e)
   {
      if(isPopulatingSifrar) return;

      TextBox tb = sender as TextBox;
      Person person_rec;

      if(tb.Text != this.originalText)
      {
         this.originalText = tb.Text;

         person_rec = PersonSifrar.Find(FoundInSifrar<Person>);

         if(person_rec != null && tb.Text != "")
         {
            Fld_PersonCD   = person_rec.PersonCD/*RecID*/;
            Fld_PersonName = person_rec.PrezimeIme       ;

          // 30.11.2017: premjestila u RNZ da nekom drugom ne pokvari opciB
          //Fld_OpciBlabel = person_rec.Ime              ;
          //Fld_OpciBvalue = person_rec.Prezime          ;

            #region RNZ Additions

            if(this is RNZDUC)
            {

               Fld_OpciBlabel = person_rec.Ime;
               Fld_OpciBvalue = person_rec.Prezime;

               #region Kupdob i Ugovor - via prevRNZfaktur_rec

               // Copy prezimeIme to napomena ... 4 FakturRecListUC 
               Fld_Napomena = person_rec.PrezimeIme;

               Faktur prevRNZfaktur_rec       = new Faktur();
               bool   prevRNZfaktur_rec_found = MixerDao.SetMeLast_FakturRNZ_ByPersonCD(TheDbConnection, prevRNZfaktur_rec, person_rec.PersonCD, true);
               if(prevRNZfaktur_rec_found)
               {
                  #region Kupdob

                  //Fld_KupdobCd   = prevRNZfaktur_rec.KupdobCD  ;
                  //Fld_KupdobTk   = prevRNZfaktur_rec.KupdobTK  ;
                  //Fld_KupdobName = prevRNZfaktur_rec.KupdobName;

                  Kupdob prevKupdob_rec = Get_Kupdob_FromVvUcSifrar(prevRNZfaktur_rec./*KupdobCD*/PosJedCD);

                  PutAllKupdobFields(prevKupdob_rec);

                  #endregion Kupdob

                  #region Ugovor

                  //Fld_VezniDok2 = prevRNZfaktur_rec.VezniDok2;
                  //Fld_Fco       = prevRNZfaktur_rec.Fco      ;

                  Mixer  prevRNZmixer_rec       = new Mixer();
                  bool   prevRNZmixer_rec_found = MixerDao.SetMeLast_MixerUgovor_ByKupdobCD(TheDbConnection, prevRNZmixer_rec, prevRNZfaktur_rec.KupdobCD, true);
                  if(prevRNZmixer_rec_found)
                  {
                     Fld_VezniDok2 = prevRNZmixer_rec.StrF_64;
                     Fld_Fco       = prevRNZmixer_rec.StrH_32;
                  }
                  else
                  {
                     Fld_VezniDok2 = 
                     Fld_Fco       = "";
                  }

                  #endregion Ugovor

               } // if(prevRNZfaktur_rec_found) 
               else
               {
                  ClearAllKupdobFields();
               }

               #endregion Kupdob i Uhovor - via prevRNZfaktur_rec

               #region Radno mjesto - Vrsta RNZ via VvLookupLista

               VvLookUpItem radnoMjestoLUI = ZXC.luiListaRadnoMjesto.GetLuiForThisCd(person_rec.RadMj);
               if(radnoMjestoLUI != null)
               {
                  Fld_VezniDok             = radnoMjestoLUI.Cd     ;
                  Fld_RNZ_RadnoMjesto_Opis = radnoMjestoLUI.Name   ;
                  Fld_RNZ_RadnoMjesto_Broj = radnoMjestoLUI.Integer;
               }
               else
               {
                  Fld_VezniDok             = "";
                  Fld_RNZ_RadnoMjesto_Opis = "";
                  Fld_RNZ_RadnoMjesto_Broj =  0;
               }

               #endregion Radno mjesto - Vrsta RNZ

               #region TtNum

               uint newTtNum = TheVvDao.GetNextTtNum(TheDbConnection, Fld_TT, /*skladCD4_ttNum*/"", /*isCentToCentMSI*/false, Fld_VezniDok, Fld_DokDate.Month);
               Put_NewTT_Num(newTtNum);

               #endregion TtNum

            } // if(this is RNZDUC) 

            #endregion RNZ Additions

         } // if(person_rec != null && tb.Text != "")
         else
         {
            Fld_PersonCdAsTxt = Fld_PersonName = "";

            if(this is RNZDUC)
            {
               Fld_Napomena = "";
            }
         }
      }
   }

