   private void InitializeHamper_Pdv(out VvHamper hamper)
   {
      hamper = new VvHamper(8, 1, "", null, false);

      //hamper.VvColWdt      = new int[] { labelWidth, ZXC.Q4un + ZXC.Qun4, ZXC.Q2un - ZXC.Qun8, ZXC.QUN - ZXC.Qun8, ZXC.QUN + ZXC.Qun4, ZXC.Q2un - ZXC.Qun4 - ZXC.Qun8, ZXC.QUN - ZXC.Qun4 - ZXC.Qun8, ZXC.QUN - ZXC.Qun4 - ZXC.Qun8 };
