      //hamper.VvRightMargin = hamper.VvLeftMargin;

      if(this is URA_SVD_DUC) // 21.03.2018. SVD
      {
         hamper.VvColWdt      = new int[] { labelWidth, ZXC.Q5un,0,0,0,0,0,0};
         hamper.VvSpcBefCol   = new int[] { ZXC.Qun4, faBefCol  ,0,0,0,0,0,0};
      }
      else
      {
         hamper.VvColWdt      = new int[] { labelWidth, ZXC.Q4un + ZXC.Qun4, ZXC.Q2un - ZXC.Qun8, ZXC.QUN - ZXC.Qun8, ZXC.QUN + ZXC.Qun4, ZXC.Q2un - ZXC.Qun4 - ZXC.Qun8, ZXC.QUN - ZXC.Qun4 - ZXC.Qun8, ZXC.QUN - ZXC.Qun4 - ZXC.Qun8 };
         hamper.VvSpcBefCol   = new int[] { ZXC.Qun4, faBefCol, faBefCol, faBefCol, 0, 0, 0, 0 };

      }

      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt = new int[] { ZXC.QUN };
      hamper.VvSpcBefRow = new int[] { ZXC.Qun4 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      Label pdvDat = hamper.CreateVvLabel  (0, 0, "PdvDatum:", ContentAlignment.MiddleRight);
      tbx_PdvDate  = hamper.CreateVvTextBox(1, 0, "tbx_dokDate", "PDV Datum - datum za filtriranje računa u PDV knjige");
      tbx_PdvDate.JAM_IsForDateTimePicker = true;
      dtp_PdvDate  = hamper.CreateVvDateTimePicker(1, 0, "", tbx_PdvDate);
      dtp_PdvDate.Name = "dtp_PdvDate";

      Label knjiga  = hamper.CreateVvLabel  (2, 0, "Knjiga:", ContentAlignment.MiddleRight);
      // 02.10.2018. dodano M za poseban postuak oporezivanja marze: za PDV-MI i PDV-MU
      tbx_PdvKnjiga = hamper.CreateVvTextBox(3, 0, "tbx_PdvKnjiga", 
                                "PdvKnjiga ' 'prazno - BEZ KNJIGE(za PdvGEO = E, T, B), " +
                                "R - Redovna knjiga URA/IRA, "    +
                                "P - Knjiga predujmova URA/IRA, " +
                                "U - Knjiga uvoza robe URA,   "   +
                                "S - Knjiga uvoza usluga URA"     +
                                "M - PDV-MI i PDV-MU"             , GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.pdvKnjiga));
      tbx_PdvKnjiga.JAM_CharacterCasing = CharacterCasing.Upper;
      tbx_PdvKnjiga.JAM_AllowedInputCharacters = "RUPSM";
      tbx_PdvKnjiga.TextAlign = HorizontalAlignment.Center;

      Label r    = hamper.CreateVvLabel  (6, 0, "R:", ContentAlignment.MiddleRight);
      tbx_PdvR12 = hamper.CreateVvTextBox(7, 0, "tbx_PdvR12", "Oznaka računa 1-R1, 2-R2", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.pdvR12));
      tbx_PdvR12.JAM_AllowedInputCharacters = "12";
      tbx_PdvR12.TextAlign = HorizontalAlignment.Center;
      tbx_PdvR12.JAM_FieldExitMethod = new EventHandler(PdvR12_ExitMethod);

      tbx_PdvDate  .JAM_ForeColor =
      tbx_PdvKnjiga.JAM_ForeColor =
      tbx_PdvR12   .JAM_ForeColor = Color.RoyalBlue;

      tbx_PdvDate  .JAM_IsSupressTab = true;
      tbx_PdvKnjiga.JAM_IsSupressTab = true;
      tbx_PdvR12   .JAM_IsSupressTab = true;

      pdvDat       .Visible = 
      tbx_PdvDate  .Visible = 
      knjiga       .Visible = 
      tbx_PdvKnjiga.Visible = 
      r            .Visible = 
      tbx_PdvR12   .Visible = !(this is URA_SVD_DUC);

      if(this is URA_SVD_DUC)
      {
         hamper.CreateVvLabel(0, 0, "Narudžb:", ContentAlignment.MiddleRight);
         tbx_pdvRbr = hamper.CreateVvTextBox(1, 0, "tbx_pdvRbr", "", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.pdvNum));
         tbx_pdvRbr.JAM_CharEdits = ZXC.JAM_CharEdits.DigitsOnly;
         tbx_pdvRbr.JAM_IsSupressTab = false;
      }
      else
      {
         hamper.CreateVvLabel(4, 0, "Rbr:", ContentAlignment.MiddleRight);
         tbx_pdvRbr = hamper.CreateVvTextBox(5, 0, "tbx_pdvRbr", "");
         tbx_pdvRbr.JAM_ReadOnly = true;
         tbx_pdvRbr.Font = ZXC.vvFont.SmallFont;
         tbx_pdvRbr.TextAlign = HorizontalAlignment.Right;
      }

   }

   public void PdvR12_ExitMethod(object sender, EventArgs e)
   {
      if(TheVvTabPage.WriteMode == ZXC.WriteMode.None) return;

      if(Fld_PdvR12 == ZXC.PdvR12Enum.R2) Fld_PdvDate = DateTimePicker.MinimumDateTime;
      else Fld_PdvDate = Fld_DokDate;
   }

