   private void CreateHameprTwinsOnPolyTabControl()
   {
      hamp_twin = new VvHamper(10, 2, "", ThePolyGridTabControl.TabPages[0], false);

      hamp_twin.VvColWdt      = new int[] { labelWidth, ZXC.Q4un, labelWidth, ZXC.Q4un, labelWidth, ZXC.Q4un, labelWidth, ZXC.Q4un, labelWidth, ZXC.Q4un, };
      hamp_twin.VvSpcBefCol   = new int[] { faBefFirstCol, faBefCol, faBefFirstCol, faBefCol, faBefFirstCol, faBefCol, faBefFirstCol, faBefCol, faBefFirstCol, faBefCol, };
      hamp_twin.VvRightMargin = hamp_twin.VvLeftMargin;

      hamp_twin.VvRowHgt       = new int[] { ZXC.QUN , this is IRMDUC ? ZXC.Qun2:0};
      hamp_twin.VvSpcBefRow    = new int[] { ZXC.Qun4,       0  };
      hamp_twin.VvBottomMargin = hamp_twin.VvTopMargin;

      Label lbl0 = hamp_twin.CreateVvLabel(0, 0, "Kol x Cij:", ContentAlignment.MiddleRight);
      Label lbl1 = hamp_twin.CreateVvLabel(2, 0, "Rabat:"    , ContentAlignment.MiddleRight);
      Label lbl2 = hamp_twin.CreateVvLabel(4, 0, "Bez Pdv-a:", ContentAlignment.MiddleRight);
      Label lbl3 = hamp_twin.CreateVvLabel(6, 0, "Pdv:"      , ContentAlignment.MiddleRight);
      Label lbl4 = hamp_twin.CreateVvLabel(8, 0, "Ukupno:"   ,  0, this is IRMDUC ? 1:0, ContentAlignment.MiddleRight);

      tbx_twinS_ukKC    = hamp_twin.CreateVvTextBox(1, 0, "tbx_twinS_ukKC"  , "", 12);
      tbx_twinS_ukRbt12 = hamp_twin.CreateVvTextBox(3, 0, "tbx_twinS_ukRbt1", "", 12);
      tbx_twinS_ukKCR   = hamp_twin.CreateVvTextBox(5, 0, "tbx_twinS_ukKCR" , "", 12);
      tbx_twinS_ukKCRM  = hamp_twin.CreateVvTextBox(5, 0, "tbx_twinS_ukKCRM", "", 12);
      tbx_twinS_ukPdv   = hamp_twin.CreateVvTextBox(7, 0, "tbx_twinS_ukPdv" , "", 12);
      tbx_twinS_ukKCRP  = hamp_twin.CreateVvTextBox(9, 0, "tbx_twinS_ukKCRP", "", 12, 0, this is IRMDUC ? 1:0);
      tbx_twinS_ukKCRP.JAM_Highlighted = true;
      

      tbx_S_ukKC  .JAM_PairThisWithTwin(tbx_twinS_ukKC  );
      tbx_S_ukKCR .JAM_PairThisWithTwin(tbx_twinS_ukKCR );
      tbx_S_ukKCRM.JAM_PairThisWithTwin(tbx_twinS_ukKCRM);
      tbx_S_ukPdv .JAM_PairThisWithTwin(tbx_twinS_ukPdv );
      tbx_S_ukKCRP.JAM_PairThisWithTwin(tbx_twinS_ukKCRP);

      tbx_twinS_ukKC   .JAM_ReadOnly = true;
      tbx_twinS_ukRbt12.JAM_ReadOnly = true;
      tbx_twinS_ukKCR  .JAM_ReadOnly = true;
      tbx_twinS_ukKCRM .JAM_ReadOnly = true;
      tbx_twinS_ukPdv  .JAM_ReadOnly = true;
      tbx_twinS_ukKCRP .JAM_ReadOnly = true;

      tbx_twinS_ukKC   .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_twinS_ukRbt12.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_twinS_ukKCR  .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_twinS_ukKCRM .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_twinS_ukPdv  .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_twinS_ukKCRP .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);

    //if(HasOrgBopCop                  ) 11.05.2018.     
      if(HasOrgBopCop || this is UGODUC)
      {
         tbx_twinS_ukKCRM.Visible = true;
         tbx_twinS_ukKCR.Visible = false;
      }
      else
      {
         tbx_twinS_ukKCRM.Visible = false;
         tbx_twinS_ukKCR .Visible = true ;
      }


      if(this is BlgIsplatDUC     || this is BlgUplatDUC        || this is BlgIsplat_M_DUC  || this is BlgUplat_M_DUC   ||
         this is NarudzbaDobavDUC || this is NarudzDobUslugaDUC || this is NarudzDobUvozDUC || this is NarudzbaKupcaDUC || 
         IsRadNalog == true       || this is PrimkaBcDUC        || this is IZD_SVD_DUC      || this is ZAH_SVD_DUC)
      {
         lbl0.Visible =
         lbl1.Visible =
         lbl2.Visible =
         lbl3.Visible =
         tbx_twinS_ukKC.Visible =
         tbx_twinS_ukRbt12.Visible =
         tbx_twinS_ukKCR.Visible =
         tbx_twinS_ukPdv.Visible = false;
      }

      if(/*this is NarudzbaDobavDUC ||*/ this is NarudzbaKupcaDUC || IsRadNalog || this is PrimkaBcDUC) lbl4.Visible = tbx_twinS_ukKCRP.Visible = false;
      
      if(this is PIZpDUC || this is TransformDUC || this is ProizvodnjaDUC || this is RNZDUC) hamp_twin.Visible = false;
   }

   private void OnExitSetPrimPlat(object sender, EventArgs e)
   {
      VvTextBox vvtb = sender as VvTextBox;

      if(vvtb.EditedHasChanges() == false) return;

      VvLookUpItem lui = ZXC.luiListaRiskVrstaPl.GetLuiForThisCd(vvtb.Text);
      if(lui != null) Fld_PrimPlatCD = (uint)lui.Integer;

      if(Fld_PrimPlatCD.IsZero())
      {
         Fld_PrimPlatCDAsTxt = Fld_PrimPlatTK = Fld_PrimPlatName = "";
      }
      else
      {
         OnVvTBEnter_SetAutocmplt_Kupdob_sorterSifra(null, e);

         AnyPrimPlatTextBoxLeave(tbx_PrimPlatCD, e);
      }
   }

