   protected void Set_KPN_Out_labelsEnabledState(VvHamper hamper, bool enabled, Color color)
   {
      lbl_kpnOut1    .Enabled =
      lbl_kpnOut2    .Enabled =
      lbl_kpnOut3    .Enabled =
    //lbl_kpnOut4    .Enabled =
      lbl_kpnOut5    .Enabled =
    //lbl_kpnOut6    .Enabled =
