      hamper.BackColor = color;
   }

   protected void ClearKPNfieldz()
   {
      cbx_isKpnOUT.Checked = false;

      Fld_someMoney   =
      Fld_somePercent = 0M;
    //Fld_RokIspDate  = DateTime.MinValue;
      Fld_RokIspDate  = DateTimePicker.MinimumDateTime;
      Fld_PonudDate   = DateTimePicker.MinimumDateTime;
   }

   protected void PutLastUsedKPNfieldz(IRMDUC theIRMDUC, bool kpnCbxIsJustChecked)
   {
      if(kpnCbxIsJustChecked == false) cbx_isKpnOUT.Checked = theIRMDUC.KPN_isOn;

      if(cbx_isKpnOUT.Checked == false) return; // nemoj pokazivati sto je bilo dok je bilo 

      Fld_someMoney   = theIRMDUC.Kpn_Min      ;
      Fld_somePercent = theIRMDUC.Kpn_OUT_RbtSt;
      Fld_RokIspDate  = theIRMDUC.Kpn_DateDo   ;
      Fld_PonudDate   = theIRMDUC.Kpn_DateOd   ;
   }

   protected void GetLastUsedKPNfieldz(IRMDUC theIRMDUC)
   {
      theIRMDUC.KPN_isOn      = cbx_isKpnOUT.Checked;
      theIRMDUC.Kpn_Min       = Fld_someMoney       ;
      theIRMDUC.Kpn_OUT_RbtSt = Fld_somePercent     ;
      theIRMDUC.Kpn_DateDo    = Fld_RokIspDate      ;
      theIRMDUC.Kpn_DateOd    = Fld_PonudDate        ;
   }

