   private void Cbx_isKpnOUT_CheckedChanged(object sender, EventArgs e)
   {
      // qKUPON ODGODA 
      //return;

      if(TheVvTabPage.WriteMode == ZXC.WriteMode.None) return;

      CheckBox cBox = sender as CheckBox;
      if(cBox.Checked)
      {
         Set_KPN_Out_labelsEnabledState(hamp_irmKuponOUT, true , Color.FromArgb(233, 183, 244));
         if(TheVvTabPage.WriteMode == ZXC.WriteMode.Add) PutLastUsedKPNfieldz(this as IRMDUC, true);
      }
      else
      {
         Set_KPN_Out_labelsEnabledState(hamp_irmKuponOUT, false, clr_Izlaz                    );
         if(TheVvTabPage.WriteMode == ZXC.WriteMode.Add) ClearKPNfieldz();
      }
   }

