   private string FindTTfromDUC(FakturExtDUC fakturExtDUC)
   {
      if(fakturExtDUC is IFADUC) return Faktur.TT_IFA;
      else if(fakturExtDUC is IRADUC || fakturExtDUC is IRPDUC) return Faktur.TT_IRA;
      else if(fakturExtDUC is IRMDUC || fakturExtDUC is IRMDUC_2) return Faktur.TT_IRM;
      else if(fakturExtDUC is OdobrKupcuDUC) return Faktur.TT_IOD;
      else if(fakturExtDUC is PovratKupcaDUC) return Faktur.TT_IPV;
      else return "";
   }

   private void SetVisibilitiToolstripbuttons(bool isVisible)
   {
      for(int k = 0; k < ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y].Length; k++)
      {
         if(ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y][k].Name == "fisk")
            ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y][k].Visible = isVisible;
         if(ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y][k].Name == "cisStatus")
            ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y][k].Visible = isVisible;
         // 24.03.2017. dodano da se vidi na toolstrupu
         if(ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y][k].Name == "fiskAll")
            ZXC.TheVvForm.atsBtn_SubModulSet[ZXC.TheVvForm.TheVvTabPage.SubModul_xy.X][ZXC.TheVvForm.TheVvTabPage.SubModul_xy.Y][k].Visible = isVisible;
      }
   }


