   private void InitializeHamper_S_ukIRM(out VvHamper hamper)
   {
      hamper = new VvHamper(8, 2, "", null, false);

      hamper.VvColWdt      = new int[] { ZXC.Q7un, ZXC.Q4un, ZXC.Q4un, ZXC.Q4un, ZXC.Q4un, ZXC.Q4un, ZXC.Q4un, ZXC.Q4un };
      hamper.VvSpcBefCol   = new int[] { ZXC.Qun4, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4 };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      for(int i = 0; i < hamper.VvNumOfRows; i++)
      {
         hamper.VvRowHgt[i] = ZXC.QUN;
         hamper.VvSpcBefRow[i] = ZXC.Qun8;
      }
      hamper.VvBottomMargin = hamper.VvTopMargin;

      Label lbl2 = hamper.CreateVvLabel(0, 0, "ROBA/USLUGA:", ContentAlignment.MiddleLeft);
      lbl2.Font = ZXC.vvFont.SmallBoldFont;

      hamper.CreateVvLabel(1, 0, "RobaBezPdv", ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 0, "RobaSaPdv", ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(3, 0, "UslugaBezPdv", ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(4, 0, "UslugeSaPdv", ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(6, 0, "RUV", ContentAlignment.MiddleRight);

      tbx_S_ukKCR_rob  = hamper.CreateVvTextBox(1, 1, "tbx_S_ukKCR_rob", "Ukupno KCR_roba", 12);
      tbx_S_ukKCRP_rob = hamper.CreateVvTextBox(2, 1, "tbx_S_ukKCRP_rob", "Ukupno KCRP_roba", 12);
      tbx_S_ukKCR_usl  = hamper.CreateVvTextBox(3, 1, "tbx_S_ukKCR_usl", "Ukupno KCR_usl", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.s_ukKCR_usl));
      tbx_S_ukKCRP_usl = hamper.CreateVvTextBox(4, 1, "tbx_S_ukKCRP_usl", "Ukupno KCRP_usl", GetDB_ColSize_namedDao(TheVvDaoExt, DB_ciex.s_ukKCRP_usl));
      tbx_R_Ira_RUV    = hamper.CreateVvTextBox(6, 1, "tbx_R_Ira_RUV", "RUV ", 12);

      tbx_S_ukKCR_usl. JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_S_ukKCRP_usl.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_S_ukKCR_rob. JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_S_ukKCRP_rob.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_R_Ira_RUV.   JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);

      tbx_S_ukKCR_usl. JAM_ReadOnly = true;
      tbx_S_ukKCRP_usl.JAM_ReadOnly = true;
      tbx_S_ukKCR_rob. JAM_ReadOnly = true;
      tbx_S_ukKCRP_rob.JAM_ReadOnly = true;
      tbx_R_Ira_RUV.   JAM_ReadOnly = true;

      hamper.BackColor = Color.LavenderBlush;
