      hamp_PDV     .Location = new Point(hamp_kupdobOther.Right - ZXC.Qun4, hamp_DospDate.Bottom - ZXC.Qun4);

      hamp_SkladDate.Location = new Point(hamp_kupdobOther.Right - ZXC.Qun4, hamp_PDV.Bottom - ZXC.Qun4);

      if(this is IFADUC)  hamp_Status.Location = new Point(hamp_kupdobOther.Right - ZXC.Qun4          , hamp_PDV   .Bottom - ZXC.Qun4);
      else                hamp_Status.Location = new Point(hamp_kupdobOther.Right - hamp_Status.Width , hamp_ZiroRn.Bottom - ZXC.Qun4);


      hamp_pdvZPkind.Location  = new Point(hamp_SkladDate.Right - ZXC.Qun4, hamp_PDV.Bottom - ZXC.Qun4);
      hamp_pdvGeokind.Location = new Point(hamp_pdvZPkind.Right - ZXC.Qun4, hamp_PDV.Bottom - ZXC.Qun4);

      if(this is IRMDUC) hamp_Cjenik.Location = new Point(hamp_kupdobOther.Right - hamp_Cjenik.Width + (ZXC.QUN - ZXC.Qun4 - ZXC.Qun10), hamp_kupdobOther.Bottom - hamp_Cjenik.Height);
      else hamp_Cjenik.Location = new Point(hamp_PonudDate.Right - ZXC.Qun4 - ZXC.Qun2, hamp_PDV.Bottom - ZXC.Qun4);

      hamp_tt.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, 0);
      hamp_skladCd.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_tt.Bottom - ZXC.Qun4);
      hamp_v1TT.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_dokDate.Bottom - ZXC.Qun4);
      hamp_v2TT.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_v1TT.Bottom - ZXC.Qun4);
      hamp_v3TT.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_v2TT.Bottom - ZXC.Qun4);
      hamp_v4TT.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_v3TT.Bottom - ZXC.Qun4);


      if(this is KIZDUC/* || this is PIKDUC*/)
      {
         hamp_posJedCd .Location = new Point(hamp_kupdobNaziv.Left                        , hamp_kupdobNaziv.Bottom - ZXC.Qun4);
         hamp_SkladDate.Location = new Point(hamp_kupdobNaziv.Right - hamp_SkladDate.Width, hamp_dokDate.Top);
         hamp_sklad2Cd.Location  = new Point(hamp_skladCd.Left                            , hamp_skladCd.Bottom - ZXC.Qun4);
         hamp_Cjenik  .Location  = new Point(hamp_dokDate.Left + ZXC.Qun2                 , hamp_dokDate.Bottom - ZXC.Qun4);

         hamp_v1TT.Location = new Point(hamp_posJedCd.Left, hamp_posJedCd.Bottom - ZXC.Qun4);
