         hamp_v3TT.Location = new Point(hamp_skladCd.Left, hamp_posJedCd.Bottom - ZXC.Qun4);

      }
      if(/*this is KIZDUC ||*/ this is PIKDUC)
      {
         hamp_posJedCd .Location = new Point(hamp_kupdobNaziv.Left, hamp_kupdobNaziv.Bottom - ZXC.Qun4);
         hamp_SkladDate.Location = new Point(hamp_kupdobNaziv.Right - hamp_SkladDate.Width, hamp_dokDate.Top);
         hamp_skladCd  .Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_tt.Bottom - ZXC.Qun4);
         hamp_sklad2Cd .Location = new Point(hamp_skladCd.Left, hamp_skladCd.Bottom - ZXC.Qun4);
         hamp_Status   .Location = new Point(hamp_dokDate.Left, hamp_dokDate.Bottom - ZXC.Qun4);

         hamp_v1TT.Location = new Point(hamp_posJedCd.Left, hamp_posJedCd.Bottom - ZXC.Qun4);
         hamp_v2TT.Location = new Point(hamp_dokDate.Left, hamp_posJedCd.Bottom - ZXC.Qun4);
         hamp_v3TT.Location = new Point(hamp_sklad2Cd.Left, hamp_posJedCd.Bottom - ZXC.Qun4);

      }

           if(this is IRMDUC)                   hamp_napomena.Location = new Point(hamp_dokDate.Left, hamp_dokDate.Bottom - ZXC.Qun4);
      else if(this is KIZDUC || this is PIKDUC) hamp_napomena.Location = new Point(0, hamp_v3TT.Bottom - ZXC.Qun4);
      else                                      hamp_napomena.Location = new Point(0, hamp_v4TT.Bottom - ZXC.Qun4);

      if(this is IFADUC || this is IRADUC || this is IRPDUC || this is IRMDUC_2 || this is OdobrKupcuDUC || this is PovratKupcaDUC || this is IRMDUC)
      {
         hamp_NacPlac.Location = new Point(0, hamp_napomena.Bottom - ZXC.Qun4);
         hamp_fiskJIR.Location = new Point(hamp_NacPlac.Right - ZXC.Qun4, hamp_napomena.Bottom - ZXC.Qun4);

         nextY = hamp_NacPlac.Bottom;
      }
      else
      {
         nextY = hamp_napomena.Bottom;
      }

      if(this is IRMDUC_2 )
      {
         hamp_prjArtName.Location = new Point(0, hamp_NacPlac.Bottom - ZXC.Qun4);
         nextY = hamp_prjArtName.Bottom;
      }

      panel_MigratorsLeftA.Parent = TheTabControl.TabPages[0];
      panel_MigratorsLeftA.Location = new Point(0, nextY - ZXC.Qun8);
      //panel_MigratorsLeftA.Size = new Size(hamp_v1TT.Right, 0); 21.02.2013. zato kaj nije svima hamp_v1TT skroz desno 
      panel_MigratorsLeftA.Size = new Size(hamp_tt.Right + ZXC.Qun2, 0);

      panel_MigratorsLeftB.Parent = TheTabControl.TabPages[0];
      //panel_MigratorsLeftB.Location  = new Point(hamp_v1TT.Right, 0); 21.02.2013. zato kaj nije svima hamp_v1TT skroz desno 
      panel_MigratorsLeftB.Location = new Point(hamp_tt.Right + ZXC.Qun2, 0);
      panel_MigratorsLeftB.Size = new Size(hamp_opis.Width, hamp_opis.Height);
      panel_MigratorsLeftB.BringToFront();

      panel_MigratorsRightB.BringToFront();

      hamp_SukKC_K  .Parent = TheTabControl.TabPages[1];
      hamp_S_uk     .Parent = TheTabControl.TabPages[1];
      hamp_S_ukPdv  .Parent = TheTabControl.TabPages[1];
      hamp_S_ukMSK  .Parent = TheTabControl.TabPages[1];
      hamp_S_ukIRM  .Parent = TheTabControl.TabPages[1];
      hamp_S_pix    .Parent = TheTabControl.TabPages[1];
      hamp_S_ppmv   .Parent = TheTabControl.TabPages[1];
      hamp_S_pnp_IZL.Parent = TheTabControl.TabPages[1];
      hamp_S_KIZ_cij.Parent = TheTabControl.TabPages[1];

      if(this is BlgIsplatDUC || this is BlgUplatDUC || this is BlgIsplat_M_DUC || this is BlgUplat_M_DUC) BlagajnaHamperLocation();

      if(IsRadNalog) RN_HamperLocation();

      if(this is WYRNDUC)
      {
         hamp_napomena .Location = new Point(hamp_VezniDok2.Right - ZXC.Qun4, hamp_vezniDok.Bottom - ZXC.Qun12);
      }


      if(this is RNZDUC)
      {
         hamp_osobaA     .Location = new Point(0, 0                                      ); // zastitar/cuvar
         hamp_kupdobNaziv.Location = new Point(0, hamp_osobaA     .Bottom /*+ ZXC.Qun8*/ ); // partner       
         hamp_posJedCd   .Location = new Point(0, hamp_kupdobNaziv.Bottom - ZXC.Qun8     ); // lokacija      
         hamp_VezniDok2  .Location = new Point(0, hamp_posJedCd   .Bottom - ZXC.Qun8     ); // ugovor        

         hamp_vezniDok .Location = new Point(hamp_kupdobNaziv.Right - hamp_vezniDok.Width , 0                                 ); // vrsta RNZ
         hamp_dokDate  .Location = new Point(hamp_kupdobNaziv.Right - hamp_dokDate .Width, hamp_kupdobNaziv.Bottom - ZXC.Qun4); // datum OD
         hamp_dokDate2 .Location = new Point(hamp_kupdobNaziv.Right - hamp_dokDate2.Width, hamp_dokDate    .Bottom - ZXC.Qun4); // datum do
         hamp_Fco      .Location = new Point(hamp_kupdobNaziv.Right - hamp_Fco     .Width, hamp_VezniDok2  .Top   );
         hamp_dokNum   .Location = new Point(hamp_kupdobNaziv.Right - hamp_dokNum  .Width, hamp_osobaA     .Bottom /*+ ZXC.Qun8*/);
         
         hamp_napomena2.Location = new Point(0, hamp_VezniDok2.Bottom + ZXC.Qun8);
         hamp_opis     .Location = new Point(0, hamp_napomena2.Bottom /*+ ZXC.Qun8*/);


         hamp_prjIdent.Location = new Point(hamp_tt.Left                      , hamp_tt.Bottom - ZXC.Qun8);
         hamp_projekt .Location = new Point(hamp_tt.Right - hamp_projekt.Width, hamp_tt.Bottom - ZXC.Qun4);

         hamp_napomena.Location = new Point(hamp_tt.Left, hamp_prjIdent.Bottom - ZXC.Qun8);
         hamp_v1TT    .Location = new Point(hamp_tt.Left, hamp_napomena.Bottom - ZXC.Qun8);
         hamp_v2TT    .Location = new Point(hamp_tt.Left, hamp_v1TT    .Bottom - ZXC.Qun4);
         hamp_v3TT    .Location = new Point(hamp_tt.Left, hamp_v2TT    .Bottom - ZXC.Qun4);
       //hamp_v4TT    .Location = new Point(hamp_tt.Left, hamp_v3TT    .Bottom - ZXC.Qun4);

         //tbx_PersonAName.TabIndex = 0;
         //tbx_VezniDok .TabIndex = 1;
