   private void BlagajnaHamperLocation()
   {
      hamp_vezniDok.Location = new Point(0, hamp_kupdobOther.Bottom - ZXC.Qun4);

      hamp_dokDate.Location = new Point(hamp_kupdobOther.Right - ZXC.Qun4         , hamp_kupdobNaziv.Bottom - ZXC.Qun4);
      hamp_dokNum.Location  = new Point(hamp_kupdobNaziv.Right - hamp_dokNum.Width, hamp_kupdobNaziv.Bottom - ZXC.Qun4);
      hamp_Status.Location  = new Point(hamp_dokNum     .Right - hamp_Status.Width, hamp_dokDate    .Bottom - ZXC.Qun4);
      hamp_tt    .Location  = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4         ,                                  0);

      if(this is BlgIsplat_M_DUC || this is BlgUplat_M_DUC)
      {
         hamp_skladCd.Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4          , hamp_tt.Bottom - ZXC.Qun4);
         hamp_projekt.Location = new Point(hamp_dokDate    .Left                      , hamp_dokDate.Bottom - ZXC.Qun4);
         hamp_ValName.Location = new Point(hamp_kupdobOther.Right - hamp_ValName.Width, hamp_kupdobOther.Bottom - hamp_ValName.Height);
         hamp_v1TT   .Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4          , hamp_skladCd.Bottom - ZXC.Qun4);
         hamp_v2TT   .Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4          , hamp_v1TT     .Bottom - ZXC.Qun4);
         hamp_ValName.BringToFront();
         hamp_napomena.Location = new Point(hamp_kupdobOther.Right - ZXC.Qun4, hamp_v1TT.Bottom - ZXC.Qun4);
      }
      else
      {
         hamp_v1TT    .Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_tt.Bottom - ZXC.Qun4);
         hamp_v2TT    .Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_v1TT.Bottom - ZXC.Qun4);
         hamp_v3TT    .Location = new Point(hamp_kupdobNaziv.Right - ZXC.Qun4, hamp_v2TT.Bottom - ZXC.Qun4);
         hamp_napomena.Location = new Point(hamp_kupdobOther.Right - ZXC.Qun4, hamp_v2TT.Bottom - ZXC.Qun4);
      }
   }

   private void RN_HamperLocation()
   {
      bool isRNM = this is RNMDUC;

      /* objekt      */       hamp_prjArtName.Location = new Point(0                                             , hamp_kupdobNaziv.Bottom - ZXC.Qun4);
      /* zahtjev     */       hamp_VezniDok2 .Parent = TheTabControl.TabPages[0];
      /* zahtjev     */       hamp_prjIdent  .Parent = TheTabControl.TabPages[0];

      if(isRNM)
      { 
         hamp_VezniDok2 .Location = new Point(0                  , hamp_kupdobNaziv.Bottom - ZXC.Qun8 );
         hamp_vezniDok  .Location = new Point(0                  , hamp_VezniDok2  .Bottom - ZXC.Qun8 );
         hamp_osobaX    .Location = new Point(0                  , hamp_vezniDok   .Bottom - ZXC.Qun4 );
         hamp_OpciA     .Location = new Point(0                  , hamp_osobaX     .Bottom - ZXC.Qun8 );
