         hamp_OpciA.Location                = new Point(hamp_osobaA.Right + ZXC.QUN, ZXC.Qun4);
         hamp_OpciA.VvInitialHamperLocation = new Point(hamp_osobaA.Right + ZXC.QUN, ZXC.Qun4);
         hampCbxM_OpciA.Location            = new Point(hamp_osobaA.Right          , ZXC.Qun4);
      }

