      }

      hamp_rokIspAndDate.Location                = new Point(hamp_OsobaB.Right + ZXC.QUN, hamp_OpciB.Bottom);
      hamp_rokIspAndDate.VvInitialHamperLocation = new Point(hamp_OsobaB.Right + ZXC.QUN, hamp_OpciB.Bottom);
