         hamp_osobaX.Location                = new Point(hamp_OsobaB.Right + ZXC.QUN, hamp_tipOtpreme.Bottom);
         hamp_osobaX.VvInitialHamperLocation = new Point(hamp_OsobaB.Right + ZXC.QUN, hamp_tipOtpreme.Bottom);
