   public void SetParentOfhampers()
   {
      SetParentOfHamperLeftHampers();

      for(int i = 0; i < hamperMigr.Length; i++)
      {
         if(hamperMigr[i].Name.StartsWith("A"))
         {
            hamperMigr[i].Parent =
            hamperCbx4Migr[i].Parent = panel_MigratorsRightA;
         }
         else if(hamperMigr[i].Name.StartsWith("B"))
         {
            hamperMigr[i].Parent =
            hamperCbx4Migr[i].Parent = panel_MigratorsRightB;
         }
      }
      hamp_konto.BringToFront();
      hamp_Pnb.BringToFront();
      hamp_Cjenik.BringToFront();
      hamp_ValName.BringToFront();
   }

