         if(rbt_nijeCarina.Checked) return ZXC.ShouldFak2NalEnum.Knjizi_NORMALNO;
         else if(rbt_spediter.Checked) return ZXC.ShouldFak2NalEnum.Knjizi_NISTA;
         else if(rbt_carina.Checked) return ZXC.ShouldFak2NalEnum.Knjizi_SamoPDV_i_Carinu;

         else throw new Exception("Fld_CarinaKind: who df is checked?");
      }
      set
      {
         switch(value)
         {
            case ZXC.ShouldFak2NalEnum.Knjizi_NORMALNO: rbt_nijeCarina.Checked = true; break;
            case ZXC.ShouldFak2NalEnum.Knjizi_NISTA: rbt_spediter.Checked = true; break;
            case ZXC.ShouldFak2NalEnum.Knjizi_SamoPDV_i_Carinu: rbt_carina.Checked = true; break;
         }
      }
   }

