#region PutExtFields(), GetExtFields() PutTransSumToDocumentSumFields_Ext()

   protected override void SetDefaulFakExDucFields()
   {
      bool isR2 = false;

      // 11.4.2011: NE! Defaultno neka svugdje dolazi pdvR12 = '1' 
      //if(ZXC.CURR_prjkt_rec.IsObrt) isR2 = true;
      // 8.11.2011. ovisno obrtPDV2 ponasa se kao R2

    // 10.02.2015. za poduzeca po naplati
    //if(ZXC.CURR_prjkt_rec.PdvRTip == ZXC.PdvRTipEnum.OBRT_R2) isR2 = true;
      if(ZXC.CURR_prjkt_rec.PdvRTip == ZXC.PdvRTipEnum.OBRT_R2 || ZXC.CURR_prjkt_rec.PdvRTip == ZXC.PdvRTipEnum.POD_PO_NAPL) isR2 = true;

      if(Fld_TT == Faktur.TT_UFA || Fld_TT == Faktur.TT_UFM || Fld_TT == Faktur.TT_URA || Fld_TT == Faktur.TT_URM ||
         Fld_TT == Faktur.TT_UOD || Fld_TT == Faktur.TT_UPV || Fld_TT == Faktur.TT_UPM)
      {
         // 14.09.2020: ne sjecamo se zasto smo ovo napravili za 'za stroniranje knjige predujma' 
         // a radi priobleme kod kopiraj npr jedne UFA-e u drugu UFA-u, pa gasimo. 
         //if(ZXC.RISK_CopyToOtherDUC_inProgress == true && faktur_rec.PdvKnjiga != ZXC.PdvKnjigaEnum.NIJEDNA) ; // groovy, ha? 
         //else Fld_PdvKnjiga = ZXC.PdvKnjigaEnum.REDOVNA; // za stroniranje knjige predujma 
         //17.09.2020. ovdje dolazimo i kod NEW pa se nije pojavljivala niti jedna knjiga a treba defaultno doci R 
         // a dalje na osnovu partnera dolayi eventualno brisanje knjige. A kod kopiranja je potrebno da ostane kako je bio original
         // pa zato micemo drugi uvijet
     //if(ZXC.RISK_CopyToOtherDUC_inProgress == true   && faktur_rec.PdvKnjiga != ZXC.PdvKnjigaEnum.NIJEDNA  ) ; 
       if(ZXC.RISK_CopyToOtherDUC_inProgress == true /*&& faktur_rec.PdvKnjiga != ZXC.PdvKnjigaEnum.NIJEDNA*/) ; // do nothing 
       else Fld_PdvKnjiga = ZXC.PdvKnjigaEnum.REDOVNA; // za stroniranje knjige predujma 




         //Fld_PdvKolTip = ZXC.PdvKolTipEnum.MOZE; u dgv
         //Fld_PdvUvoz   = ZXC.PdvUvozEnum.NIJEDNO;
         //Fld_PdvR12    = ZXC.PdvR12Enum.R1;
         if(isR2) Fld_PdvR12 = ZXC.PdvR12Enum.R2;
         else     Fld_PdvR12 = ZXC.PdvR12Enum.R1;

      }
      if(Fld_TT == Faktur.TT_IFA || Fld_TT == Faktur.TT_IRA ||
         Fld_TT == Faktur.TT_IOD || Fld_TT == Faktur.TT_IPV ||
         Fld_TT == Faktur.TT_IRM)
      {
         if(ZXC.RISK_CopyToOtherDUC_inProgress == true && faktur_rec.PdvKnjiga != ZXC.PdvKnjigaEnum.NIJEDNA) ; // groovy, ha? 
         else Fld_PdvKnjiga = ZXC.PdvKnjigaEnum.REDOVNA; // za stroniranje knjige predujma 
         //Fld_PdvKolTip = ZXC.PdvKolTipEnum.NIJE;
         //Fld_PdvUvoz   = ZXC.PdvUvozEnum.NIJEDNO;

         if(isR2) Fld_PdvR12 = ZXC.PdvR12Enum.R2;
         else Fld_PdvR12 = ZXC.PdvR12Enum.R1;
      }

      if(Fld_TT == Faktur.TT_IFA || Fld_TT == Faktur.TT_IRA ||
         Fld_TT == Faktur.TT_PON || Fld_TT == Faktur.TT_OPN ||
         Fld_TT == Faktur.TT_IOD || Fld_TT == Faktur.TT_IPV ||
         Fld_TT == Faktur.TT_KIZ)
      {
         Fld_CjenikTT = Faktur.TT_CJ_VP1;
      }
      else if(Fld_TT == Faktur.TT_IRM) Fld_CjenikTT = Faktur.TT_CJ_MP;
      else if(Fld_TT == Faktur.TT_IZM) Fld_CjenikTT = Faktur.TT_CJ_MP;
      else if(Fld_TT == Faktur.TT_PNM) Fld_CjenikTT = Faktur.TT_CJ_MP;
      else if(Fld_TT == Faktur.TT_INM) Fld_CjenikTT = Faktur.TT_CJ_MP;

      VvLookUpLista theDscLuiList = GetDscLuiListForThisTT(faktur_rec.TT, 0 /*subDsc*/ /*theRptFilter.ChoseObrazac*/);
      if(theDscLuiList != null)
      {
         VvLookUpItem luiOpciA = theDscLuiList.SingleOrDefault(lui => lui.Cd == "Dsc_LblOpciA");
         VvLookUpItem luiOpciB = theDscLuiList.SingleOrDefault(lui => lui.Cd == "Dsc_LblOpciB");

       //02.12.2022. SVD
       //if(luiOpciA != null                ) Fld_OpciAlabel = luiOpciA.Name;
       //if(luiOpciB != null                ) Fld_OpciBlabel = luiOpciB.Name;
         if(luiOpciA != null && !ZXC.IsSvDUH) Fld_OpciAlabel = luiOpciA.Name;
         if(luiOpciB != null && !ZXC.IsSvDUH) Fld_OpciBlabel = luiOpciB.Name;
      }

      // 14.09.2011: preselio u VvFrom.NewRecord_OnClick() 
      //if(ZXC.RISK_CopyToOtherDUC_inProgress == true)
      //{
      //   //RokPlExitMethod(null, EventArgs.Empty);
      //   Fld_DospDate = DateTime.Now + new TimeSpan(Fld_RokPlac, 0, 0, 0); // da ispravi Fld_DospDate na osnovi Fld_RokPlac sas orginala 
      //}

      Fld_MalopCalcKind = ZXC.RRD.MalopCalcKind; // RRD - RsikRulesDsc 
      Fld_IsViaRabat = ZXC.RRD.Dsc_IsViaRabat; // RRD - RsikRulesDsc 

      if(faktur_rec.TT == Faktur.TT_IRM && ZXC.RISK_CopyToOtherDUC_inProgress == false) // MALOP IRA 
      {
         decimal maxRabat = ZXC.luiListaRiskVrstaPl.Max(l => l.Number);
         VvLookUpItem lui = ZXC.luiListaRiskVrstaPl.FirstOrDefault(l => l.Number == maxRabat);

         // 19.12.2012: 
         if(ZXC.luiListaRiskVrstaPl.Sum(l => l.Number).IsZero()) // znaci NEMA razvrstanih rabata po NacPlac 
         {
            lui = ZXC.luiListaRiskVrstaPl.FirstOrDefault(l => l.Flag == true); // dakle, daj PRVOGA koji ima IsNacPlacCash 
         }

         if(lui != null)
         {
            Fld_NacPlac = lui.Cd;
            Fld_NacPlacRbt = lui.Number;
            Fld_IsNpCash = lui.Flag;
         }

         PutAllKupdobFields(ZXC.RRD.MalopKupdob_rec);
      }

      // CLEAR eventual FISKAL data 
      Fld_fiskJIR = Fld_fiskZKI = Fld_fiskMsgID = Fld_fiskOibOp = Fld_fiskPrgBr = "";

      if(ZXC.IsSvDUH_ZAHonly && Fld_TT == Faktur.TT_ZAH)
      {
         PutAllKupdobFields(ZXC.SvDUH_ZAHonlyKupdob_rec);

         Fld_StatusCD   = "O"; 
      }
   }

