   protected override void GetExtFields()
   {
      if(CtrlOK(tbx_KupdobCd    )) faktur_rec.KupdobCD     = Fld_KupdobCd;
      if(CtrlOK(tbx_KupdobTk    )) faktur_rec.KupdobTK     = Fld_KupdobTk;
      if(CtrlOK(tbx_KupdobName  )) faktur_rec.KupdobName   = Fld_KupdobName;
      if(CtrlOK(tbx_KupdobUlica )) faktur_rec.KdUlica      = Fld_KupdobUlica;
      if(CtrlOK(tbx_KupdobZip   )) faktur_rec.KdZip        = Fld_KupdobZip;
      if(CtrlOK(tbx_KupdobMjesto)) faktur_rec.KdMjesto     = Fld_KupdobMjesto;
      if(CtrlOK(tbx_KdOib       )) faktur_rec.KdOib        = Fld_KdOib;
      if(CtrlOK(tbx_vatCntryCode)) faktur_rec.VatCntryCode = Fld_VatCntryCode;
      if(CtrlOK(tbx_PosJedCd    )) faktur_rec.PosJedCD     = Fld_PosJedCd;
      if(CtrlOK(tbx_PosJedTk    )) faktur_rec.PosJedTK     = Fld_PosJedTk;
      if(CtrlOK(tbx_PosJedName  )) faktur_rec.PosJedName   = Fld_PosJedName;
      if(CtrlOK(tbx_PosJedUlica )) faktur_rec.PosJedUlica  = Fld_PosJedUlica;
      if(CtrlOK(tbx_PosJedZip   )) faktur_rec.PosJedZip    = Fld_PosJedZip;
      if(CtrlOK(tbx_PosJedMjesto)) faktur_rec.PosJedMjesto = Fld_PosJedMjesto;
      if(CtrlOK(tbx_Napomena2   )) faktur_rec.Napomena2    = Fld_Napomena2;
      if(CtrlOK(tbx_VezniDok2   )) faktur_rec.VezniDok2    = Fld_VezniDok2;
      if(CtrlOK(tbx_Fco         )) faktur_rec.Fco          = Fld_Fco;
      if(CtrlOK(tbx_RokPlac     )) faktur_rec.RokPlac      = Fld_RokPlac;
      if(CtrlOK(tbx_DospDate    )) faktur_rec.DospDate     = Fld_DospDate;
      if(CtrlOK(tbx_SkladDate   ))
      {
         faktur_rec.SkladDate = Fld_SkladDate;

         if(faktur_rec.SkladDate == DateTime.MinValue ||
            faktur_rec.SkladDate == DateTimePicker.MinimumDateTime)

            faktur_rec.SkladDate = faktur_rec.DokDate;
      }
      else
      {
         faktur_rec.SkladDate = faktur_rec.DokDate;
      }

      if(CtrlOK(tbx_PdvDate)) faktur_rec.PdvDate = Fld_PdvDate;
      else                    faktur_rec.PdvDate = Fld_DokDate;

      if(faktur_rec.PdvDate == DateTime.MinValue ||
         faktur_rec.PdvDate == DateTimePicker.MinimumDateTime)
      {
         if(Fld_PdvR12 != ZXC.PdvR12Enum.R2)
         {
            faktur_rec.PdvDate = faktur_rec.DokDate;
         }
      }
      else // dakle, PdvDate NIJE prazan 
      {
         if(Fld_PdvR12 == ZXC.PdvR12Enum.R2)
         {
            faktur_rec.PdvDate = DateTimePicker.MinimumDateTime;
         }
      }

      if(CtrlOK(tbx_NacPlac     )) faktur_rec.NacPlac      = Fld_NacPlac;
      if(CtrlOK(tbx_ZiroRn      )) faktur_rec.ZiroRn       = Fld_ZiroRn;
      if(CtrlOK(tbx_ValName     )) faktur_rec.DevName      = Fld_DevName;
      if(CtrlOK(tbx_PnbM        )) faktur_rec.PnbM         = Fld_PnbM;
      if(CtrlOK(tbx_PnbV        )) faktur_rec.PnbV         = Fld_PnbV;
      if(CtrlOK(tbx_PersonACD   )) faktur_rec.PersonCD     = Fld_PersonCD;
      if(CtrlOK(tbx_PersonAName )) faktur_rec.PersonName   = Fld_PersonName;
      if(CtrlOK(tbx_CjenikTT    )) faktur_rec.CjenikTT     = Fld_CjenikTT;
      if(CtrlOK(tbx_CjenikTTnum )) faktur_rec.CjenTTnum    = Fld_CjenikTTnum;
