         if(CtrlOK(ptgDUC.tbx_DokDate2  )) ptgUgovor_rec.PTG_DatDostave     = ptgDUC.Fld_PTG_DatDostave     ;   
         if(CtrlOK(ptgDUC.tbx_SkladDate )) ptgUgovor_rec.PTG_DatSkidSaSklad = ptgDUC.Fld_PTG_DatSkidSaSklad ; 
