   private void AnyMtrosTextBoxLeave(object sender, EventArgs e)
   {
      if(isPopulatingSifrar) return;

      //if(ZXC.TheVvForm.TheVvTabPage.WriteMode == ZXC.WriteMode.None) return;

      TextBox tb = sender as TextBox;
      Kupdob kupdob_rec;

      if(tb.Text != this.originalText)
      {
         this.originalText = tb.Text;

         kupdob_rec = KupdobSifrar.Find(FoundInSifrar<Kupdob>);

         if(kupdob_rec != null && tb.Text != "")
         {
            Fld_MtrosCD = kupdob_rec.KupdobCD/*RecID*/;
            Fld_MtrosTK = kupdob_rec.Ticker;
            Fld_MtrosName = kupdob_rec.Naziv;
         }
         else
         {
            Fld_MtrosCDAsTxt = Fld_MtrosTK = Fld_MtrosName = "";
         }
      }
   }

   private void AnyPrimPlatTextBoxLeave(object sender, EventArgs e)
   {
      if(isPopulatingSifrar) return;

      //if(ZXC.TheVvForm.TheVvTabPage.WriteMode == ZXC.WriteMode.None) return;

      TextBox tb = sender as TextBox;
      Kupdob kupdob_rec;

      if(tb.Text != this.originalText)
      {
         this.originalText = tb.Text;

         kupdob_rec = KupdobSifrar.Find(FoundInSifrar<Kupdob>);

         if(kupdob_rec != null && tb.Text != "")
         {
            Fld_PrimPlatCD = kupdob_rec.KupdobCD/*RecID*/;
            Fld_PrimPlatTK = kupdob_rec.Ticker;
            Fld_PrimPlatName = kupdob_rec.Naziv;
         }
         else
         {
            Fld_PrimPlatCDAsTxt = Fld_PrimPlatTK = Fld_PrimPlatName = "";
         }
      }
   }

   public void RokPlExitMethod(object sender, EventArgs e)
   {
      if(Fld_RokPlac.NotZero()) Fld_DospDate = Fld_DokDate + new TimeSpan(Fld_RokPlac, 0, 0, 0);
      else                      Fld_DospDate = Fld_DokDate;
   }

   public void DospDateExitMethod(object sender, EventArgs e)
   {
      TimeSpan timeSpan;

      if(Fld_DospDate >= DateTimePicker.MinimumDateTime && Fld_DospDate <= DateTimePicker.MaximumDateTime)
      {
         timeSpan = Fld_DospDate.Date - Fld_DokDate.Date;
         Fld_RokPlac = (int)timeSpan.TotalDays;
      }
      else
      {
         Fld_RokPlac = 0;
      }
   }

   public void RokPonudeExitMethod(object sender, EventArgs e)
   {
      if(Fld_RokPonude.NotZero()) Fld_PonudDate = Fld_DokDate + new TimeSpan(Fld_RokPonude, 0, 0, 0);
      else                        Fld_PonudDate = Fld_DokDate;
   }

   public void RokIspDateExitMethod(object sender, EventArgs e)
   {
      TimeSpan timeSpan;

      if(Fld_RokIspDate > DateTimePicker.MinimumDateTime && Fld_RokIspDate <= DateTimePicker.MaximumDateTime)
      {
         timeSpan = Fld_RokIspDate.Date - Fld_DokDate.Date;
         Fld_RokIsporuke = (int)timeSpan.TotalDays;
      }
      else
      {
         Fld_RokIsporuke = 0;
      }
   }

   public void RokIspoExitMethod(object sender, EventArgs e)
   {
      if(Fld_RokIsporuke.NotZero()) Fld_RokIspDate = Fld_DokDate + new TimeSpan(Fld_RokIsporuke, 0, 0, 0);
      else Fld_RokIspDate = Fld_DokDate;
   }

