   protected override void GetDgvFields2(bool dirtyFlagging)
   {
      if(TheG2 == null) return;

      uint[] recIDtable;
      int rIdx;

      if(dirtyFlagging && ThePolyGridTabControl.SelectedTab.Title != TabPageTitle2) return;

      if(dirtyFlagging == true && ZXC.TheVvForm.VvFlag_RowsAreAddingOrDeletingOrBoth == false)
      {
         if((TheG2.CurrentCell != null && TheG2.CurrentCell.IsInEditMode) || ZXC.TheVvForm.VvFlag_PretendDgvCurrentCellIsInEditMode)
         {
            GetDgvLineFields2(TheG2.CurrentRow.Index, dirtyFlagging, null);

            ZXC.TheVvForm.VvFlag_PretendDgvCurrentCellIsInEditMode = false;
         }

         return;
      }

      if(TheG2.RowCount > 0) recIDtable = new uint[TheG2.RowCount - 1];
      else recIDtable = null;

      faktur_rec.DiscardPreviouslyAddedTranses2();

      for(rIdx = 0; rIdx < TheG2.RowCount - 1; ++rIdx)
      {
         GetDgvLineFields2(rIdx, dirtyFlagging, recIDtable);
      }

      MarkTranses2ToDelete(recIDtable);
   }

   public override VvTransRecord GetDgvLineFields2(int rIdx, bool dirtyFlagging, uint[] recIDtable)
   {
      uint recID;
      bool DB_RWT;
      Rtrano db_rec;

      // dgvAtrans_rec: buffer za GetField iz DataGridWievRow-a                                        
      // db_rec : pointer na existing row u DB-u kojega ako je EditedHasChanges treba RWTREC-ati 

      recID = TheG2.GetUint32Cell(ci2.iT_recID, rIdx, dirtyFlagging);

      if(recIDtable != null) recIDtable[rIdx] = recID;

      dgvRtrano_rec = new Rtrano();

      if(recID > 0) // Postojeci redak 
      {
         db_rec = faktur_rec.Transes2.SingleOrDefault(vvDR => vvDR.VirtualRecID == recID);
      }
      else // novododani redak 
      {
         db_rec = null;
      }

      DB_RWT = (db_rec != null);

      dgvRtrano_rec.T_recID = recID;
      dgvRtrano_rec.T_parentID = faktur_rec.RecID;

      #region GetColumns

      dgvRtrano_rec.T_serial = (ushort)(rIdx + 1);
      if(DB_RWT) db_rec.T_serial = dgvRtrano_rec.T_serial;

      dgvRtrano_rec.T_dokNum = faktur_rec.DokNum;
      if(DB_RWT) db_rec.T_dokNum = dgvRtrano_rec.T_dokNum;

      if(faktur_rec.TtInfo.IsSkladDateTT) dgvRtrano_rec.T_skladDate = faktur_rec.SkladDate;
      else dgvRtrano_rec.T_skladDate = faktur_rec.DokDate;
      if(DB_RWT) db_rec.T_skladDate = dgvRtrano_rec.T_skladDate;


      dgvRtrano_rec.T_TT = faktur_rec.TT;
      // PTG news 
      if(HasRtrano_TT_Exposed)
      {
         //string artiklCD = Fld_PrjArtCD ;
         decimal PCK_RAM = Fld_Decimal01;
         decimal PCK_HDD = Fld_Decimal02;

         // ove GetDecimalCell-ove ovdje preduhitrujemo jer nam trebaju u dgvRtrano_rec-u za Get_MOD_RtranoTT 
         // dole nize ce se oni jos jednom, defaultno ponasanje, pokupiti                                     
         dgvRtrano_rec.T_dimX = TheG2.GetDecimalCell(ci2.iT_dimX, rIdx, dirtyFlagging);
         dgvRtrano_rec.T_dimY = TheG2.GetDecimalCell(ci2.iT_dimY, rIdx, dirtyFlagging);
         dgvRtrano_rec.T_dimZ = TheG2.GetDecimalCell(ci2.iT_dimZ, rIdx, dirtyFlagging);
         dgvRtrano_rec.T_decA = TheG2.GetDecimalCell(ci2.iT_decA, rIdx, dirtyFlagging);
         dgvRtrano_rec.T_decB = TheG2.GetDecimalCell(ci2.iT_decB, rIdx, dirtyFlagging);
         dgvRtrano_rec.T_decC = TheG2.GetDecimalCell(ci2.iT_decC, rIdx, dirtyFlagging);

         bool isPCK = TheG2.GetStringCell(ci2.iT_artiklTS, rIdx, false) == ZXC.PCK_TS;

         bool isMOC_PCK_base = false;
         if(isPCK)
         {
            string oldArtiklCD = TheG2.GetStringCell(ci2.iR_artiklCD_Old, rIdx, false);
            isMOC_PCK_base     = Artikl.Has_equal_PCK_base(Fld_PrjArtCD, oldArtiklCD);
         }

         dgvRtrano_rec.T_TT = Get_MOD_RtranoTT(rIdx, isPCK, dgvRtrano_rec, isMOC_PCK_base, PCK_RAM, PCK_HDD, false);
      }
      if(DB_RWT) db_rec.T_TT = dgvRtrano_rec.T_TT;

      dgvRtrano_rec.T_ttSort = faktur_rec.TtSort;
      // PTG news 
      if(HasRtrano_TT_Exposed)
      {
         dgvRtrano_rec.T_ttSort = ZXC.TtInfo(dgvRtrano_rec.T_TT).TtSort;
      }
      if(DB_RWT) db_rec.T_ttSort = dgvRtrano_rec.T_ttSort;

      // 2023 PTG news ... TT Rtrano-a, ili bilo koje druge medjuskladisnice?!, 
      // treba postati twinTT, tj. 'kasniji' događaj                            
      if(faktur_rec.TtInfo.TwinTT.NotEmpty())
      {
         dgvRtrano_rec.T_TT = faktur_rec.TtInfo.TwinTT;
         if(DB_RWT) db_rec.T_TT = dgvRtrano_rec.T_TT;
      }

      dgvRtrano_rec.T_ttNum = faktur_rec.TtNum;
      if(DB_RWT) db_rec.T_ttNum = dgvRtrano_rec.T_ttNum;

      dgvRtrano_rec.T_skladCD = faktur_rec.SkladCD;
      // PTG news 
      if(HasRtrano_SkladCD_Exposed)
      {
         dgvRtrano_rec.T_skladCD = TheG2.GetStringCell(ci2.iT_skladCD, rIdx, dirtyFlagging);
      }
      if(DB_RWT) db_rec.T_skladCD = dgvRtrano_rec.T_skladCD;

      dgvRtrano_rec.T_kupdobCD = faktur_rec.KupdobCD;
      if(DB_RWT) db_rec.T_kupdobCD = dgvRtrano_rec.T_kupdobCD;

      if(TheG2.CI_OK(ci2.iT_serno))
      {
         dgvRtrano_rec.T_serno = TheG2.GetStringCell(ci2.iT_serno, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_serno = dgvRtrano_rec.T_serno;
      }
      // 20.03.2013. u ptrane se koristi ci a ne ci2 za persona (linija 3663) i kaj da onda tu koristimo a postoji i ci2
      // to je pitanje za artiklCD i artiklName
      // sto je sa ostalim rtrano stvarima
      if(TheG2.CI_OK(ci2.iT_artiklCD))
      {
         dgvRtrano_rec.T_artiklCD = TheG2.GetStringCell(ci2.iT_artiklCD, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_artiklCD = dgvRtrano_rec.T_artiklCD;
      }
      if(TheG2.CI_OK(ci2.iT_artiklName))
      {
         dgvRtrano_rec.T_artiklName = TheG2.GetStringCell(ci2.iT_artiklName, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_artiklName = dgvRtrano_rec.T_artiklName;
      }
      if(TheG2.CI_OK(ci2.iT_paletaNo))
      {
         dgvRtrano_rec.T_paletaNo = TheG2.GetUint32Cell(ci2.iT_paletaNo, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_paletaNo = dgvRtrano_rec.T_paletaNo;
      }
      if(TheG2.CI_OK(ci2.iT_dimX))
      {
         dgvRtrano_rec.T_dimX = TheG2.GetDecimalCell(ci2.iT_dimX, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_dimX = dgvRtrano_rec.T_dimX;
      }
      if(TheG2.CI_OK(ci2.iT_dimY))
      {
         dgvRtrano_rec.T_dimY = TheG2.GetDecimalCell(ci2.iT_dimY, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_dimY = dgvRtrano_rec.T_dimY;
      }
      if(TheG2.CI_OK(ci2.iT_dimZ))
      {
         dgvRtrano_rec.T_dimZ = TheG2.GetDecimalCell(ci2.iT_dimZ, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_dimZ = dgvRtrano_rec.T_dimZ;
      }
      if(TheG2.CI_OK(ci2.iT_komada))
      {
         dgvRtrano_rec.T_komada = TheG2.GetDecimalCell(ci2.iT_komada, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_komada = dgvRtrano_rec.T_komada;
      }

      if(TheG2.CI_OK(ci2.iT_kol))
      {
         dgvRtrano_rec.T_kol = TheG2.GetDecimalCell(ci2.iT_kol, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_kol = dgvRtrano_rec.T_kol;
      }
      if(TheG2.CI_OK(ci2.iT_grCD))
      {
         dgvRtrano_rec.T_grCD = TheG2.GetStringCell(ci2.iT_grCD, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_grCD = dgvRtrano_rec.T_grCD;
      }
      if(TheG2.CI_OK(ci2.iT_isKomDummy))
      {
         //dgvRtrano_rec.T_isKomDummy = TheG2.GetBoolCell(ci2.iT_isKomDummy, rIdx, dirtyFlagging);
         dgvRtrano_rec.T_isKomDummy = VvCheckBox.GetBool4String(TheG2.GetStringCell(ci2.iT_isKomDummy, rIdx, dirtyFlagging));
         if(DB_RWT) db_rec.T_isKomDummy = dgvRtrano_rec.T_isKomDummy;
      }

      if(TheG2.CI_OK(ci2.iT_decA))
      {
         dgvRtrano_rec.T_decA = TheG2.GetDecimalCell(ci2.iT_decA, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_decA = dgvRtrano_rec.T_decA;
      }
      if(TheG2.CI_OK(ci2.iT_decB))
      {
         dgvRtrano_rec.T_decB = TheG2.GetDecimalCell(ci2.iT_decB, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_decB = dgvRtrano_rec.T_decB;
      }
      if(TheG2.CI_OK(ci2.iT_decC))
      {
         dgvRtrano_rec.T_decC = TheG2.GetDecimalCell(ci2.iT_decC, rIdx, dirtyFlagging);
         if(DB_RWT) db_rec.T_decC = dgvRtrano_rec.T_decC;
      }

      #endregion GetColumns

      if(dgvRtrano_rec.T_recID == 0) // ADDED NEW, FRESH Ftrans             
      {
         faktur_rec.InvokeTransRemove2(dgvRtrano_rec);

         //dgvRtrano_rec.CalcTransResults(null/*faktur_rec*/);

         dgvRtrano_rec.SaveTransesWriteMode = ZXC.WriteMode.Add;

         faktur_rec.Transes2.Add(dgvRtrano_rec);
      }
      else if(db_rec.EditedHasChanges())
      {
         db_rec.SaveTransesWriteMode = ZXC.WriteMode.Edit;
      }
      else
      {
         db_rec.SaveTransesWriteMode = ZXC.WriteMode.None;
      }

      return dgvRtrano_rec;
   }

   private void SetColors_MOD_PTG_DUC(string TT, int rowIdx)
   {
    //VvDataGridView dgv = TheG2;

      Color clr_MOC = Color.FromArgb(255, 204, 153);
      Color clr_MOS = ZXC.vvColors.clr_PCK_PTG;
      Color clr_MOI = Color.FromArgb(204, 255, 204);
      Color clr_MOU = Color.FromArgb(204, 230, 255);
      Color clr_old = Color.LightBlue;
      Color clr_new = Color.Lavender;


    //foreach(DataGridViewTextBoxCell tbxCell in dgv  .Rows[rowIdx].Cells)
      foreach(DataGridViewTextBoxCell tbxCell in TheG2.Rows[rowIdx].Cells)
      {
         switch(TT)
         {
            case Faktur.TT_MOC:
               AddColorsToCell_Oth(clr_MOC, rowIdx);
               AddColorsToCell_Old(clr_old, rowIdx);
               AddColorsToCell_New(clr_new, rowIdx);
               break;
            case Faktur.TT_MOS:
               AddColorsToCell_Oth(clr_MOS, rowIdx);
               AddColorsToCell_Old(clr_old, rowIdx);
               AddColorsToCell_New(clr_new, rowIdx);
               break;
            case Faktur.TT_MOI:
               tbxCell.Style.BackColor = clr_MOI;
               break;
            case Faktur.TT_MOU:
               tbxCell.Style.BackColor = clr_MOU;
               break;
      
            default: tbxCell.Style.BackColor = ZXC.vvColors.dataGridCellReadOnly_True_BackColor; break;
         }
      }
   }
   private void AddColorsToCell_Oth(Color clr, int rowIdx)
   { 
      TheG2.Rows[rowIdx].Cells[ci2.iT_TT      ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_serno   ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iR_PCK_baza].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_artiklTS].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_ramKlasa].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_hddKlasa].Style.BackColor = 
    //TheG2.Rows[rowIdx].Cells[ci2.iT_skladCD ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_dimX    ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_dimY    ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_decA    ].Style.BackColor =
      TheG2.Rows[rowIdx].Cells[ci2.iT_decB    ].Style.BackColor = clr;
   }
   private void AddColorsToCell_Old(Color clr, int rowIdx)
   { 
      TheG2.Rows[rowIdx].Cells[ci2.iR_artiklCD_Old].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_kol         ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iR_ramOld      ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iR_hddOld      ].Style.BackColor = clr; 
   }
   private void AddColorsToCell_New(Color clr, int rowIdx)
   { 
      TheG2.Rows[rowIdx].Cells[ci2.iT_artiklCD].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_dimZ    ].Style.BackColor = 
      TheG2.Rows[rowIdx].Cells[ci2.iT_decC    ].Style.BackColor = clr;
      
    //TheG2.Rows[rowIdx].Cells["scrol"        ].Style.BackColor = clr;
   }

