public class VvCopyInNewTTDlg : VvDialog
{
#region Fieldz

   private Button       okButton, cancelButton;
   private VvHamper     hamper;
   private int          dlgWidth, dlgHeight;
   private RadioButton[] aRbtTargetDUC;
   public VvForm.VvSubModul TheVvSubModul { get; set; }

   private VvDocumentRecordUC TheDUC;

#endregion Fieldz

#region Constructor

   public VvCopyInNewTTDlg(VvDocumentRecordUC theDUC)
   {
      TheDUC = theDUC;

      this.StartPosition = FormStartPosition.CenterScreen;
      this.Text          = "Kopiraj u novi dokument novog tipa";

      CreateHamper();

      dlgWidth        = hamper.Right + ZXC.QunMrgn;
      dlgHeight       = hamper.Bottom + /*ZXC.QunMrgn * 2 +*/ ZXC.QunBtnH;
      this.ClientSize = new Size(dlgWidth, dlgHeight);

      AddOkCancelButtons(out okButton, out cancelButton, dlgWidth, dlgHeight);
      okButton.Anchor = cancelButton.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;
      okButton.BringToFront();
      cancelButton.BringToFront();
   }

#endregion Constructor

#region hamper

   private void CreateHamper()
   {
      VvForm.VvSubModul[] aMixerTargetSubModuls = new VvForm.VvSubModul[] // Tu sad samo dodajes ako se pojavi potreba za jos kojim MixerDUC-om 
      { 
         TheDUC.TheVvTabPage.TheVvForm.GetVvSubModulFrom_SubModulEnum(ZXC.VvSubModulEnum.X_ZAH),
         TheDUC.TheVvTabPage.TheVvForm.GetVvSubModulFrom_SubModulEnum(ZXC.VvSubModulEnum.X_ZAH_RNM), // 29.09.2016.????
       //TheDUC.TheVvTabPage.TheVvForm.GetVvSubModulFrom_SubModulEnum(ZXC.VvSubModulEnum.X_URZ), // TODO: DELME!!! 
       //TheDUC.TheVvTabPage.TheVvForm.GetVvSubModulFrom_SubModulEnum(ZXC.VvSubModulEnum.X_VIR), // TODO: DELME!!! 
       //TheDUC.TheVvTabPage.TheVvForm.GetVvSubModulFrom_SubModulEnum(ZXC.VvSubModulEnum.X_SMD), // TODO: DELME!!! 
      };

       // 02.05.2018. 
    //int numOfRiskTargetSubModuls    = ZXC.TheVvForm.aModuli[1].aSubModuls.Length;
      var riskTargetSubModulList      = ZXC.TheVvForm.aModuli[1].aSubModuls.Where(sm => sm.subModulKindEnum == ZXC.VvSubModulKindEnum.DOCUMENT).ToList();
      int riskTargetSubModulListCount = riskTargetSubModulList.Count();

      int numOfMixerTargetSubModuls = aMixerTargetSubModuls.Length;

    // 02.04.2018. za sveti duh posebno jer oni imaju manje ucerControla!!!!!
    //int numOfAllTargetSubModuls =                                             numOfRiskTargetSubModuls + numOfMixerTargetSubModuls ;
      int numOfAllTargetSubModuls = (ZXC.IsSvDUH) ? riskTargetSubModulListCount : (riskTargetSubModulListCount + numOfMixerTargetSubModuls);

      aRbtTargetDUC = new RadioButton[riskTargetSubModulListCount + numOfMixerTargetSubModuls];
    // 02.04.2018. 
    //hamper = new VvHamper(4,                                            numOfRiskTargetSubModuls / 4     , "", this, false);
      // 02.05.2018: 
    //hamper = new VvHamper(4,                                            numOfAllTargetSubModuls  / 4     , "", this, false);
      
      int numberOfRows = (ZXC.IsSvDUH) ? riskTargetSubModulListCount : (int)(Math.Ceiling((decimal)numOfAllTargetSubModuls / (decimal)4));

      hamper = new VvHamper(4, numberOfRows, "", this, false);
      
      hamper.Location    = new Point(ZXC.QunMrgn, ZXC.QUN);
      hamper.VvColWdt    = new int[] { ZXC.Q10un , ZXC.Q10un, (ZXC.IsSvDUH) ? ZXC.Qun2 : (ZXC.Q10un ), (ZXC.IsSvDUH) ? ZXC.Qun2 : (ZXC.Q10un)};
      hamper.VvSpcBefCol = new int[] { ZXC.Qun2 ,  ZXC.Qun2 ,                                         ZXC.Qun2 ,                                         ZXC.Qun2 };
      hamper.VvRightMargin = 0;

    // 02.04.2018. 
    //for(int i = 0; i <                                              numOfRiskTargetSubModuls / 4; i++)
    //for(int i = 0; i < ((ZXC.IsSvDUH) ? numOfRiskTargetSubModuls : (numOfRiskTargetSubModuls / 4)); i++)
    // 20.05.2020.
    //for(int i = 0; i < ((ZXC.IsSvDUH) ? riskTargetSubModulListCount : (numOfAllTargetSubModuls  / 4)); i++)
      for(int i = 0; i < numberOfRows                                                                  ; i++)
      {
         hamper.VvRowHgt[i]    = ZXC.QUN;
         hamper.VvSpcBefRow[i] = ZXC.Qun12;
      }
      hamper.VvBottomMargin = hamper.VvTopMargin;

      VvForm.VvSubModul vvSubModul;
    //int hampRow  = 0;
    //int hampRow2 = 0;
    //int hampRow3 = 0;
    //int hampRow4 = 0;

      int currCol = 0, currRow = 0;

      for(int smIdx = 0; smIdx < numOfAllTargetSubModuls; ++smIdx)
      {
         if(smIdx < riskTargetSubModulListCount) // RISK DUC-evi 
         {
          //vvSubModul = ZXC.TheVvForm.aModuli[1].aSubModuls[smIdx];
            vvSubModul = riskTargetSubModulList[smIdx];
         }
         else // MIXER DUC-evi 
         {
            vvSubModul = aMixerTargetSubModuls[smIdx - riskTargetSubModulListCount];
         }

         if(currRow == numberOfRows)
         {
            currCol++;
            currRow = 0;
         }

         aRbtTargetDUC[smIdx] = hamper.CreateVvRadioButton(currCol, currRow++, new EventHandler(OnRbChecked_SpecifyVvSubModul), vvSubModul.subModul_shortName + " - " + vvSubModul.subModul_name, TextImageRelation.ImageBeforeText);
         aRbtTargetDUC[smIdx].Tag = vvSubModul;

      } // for(int rbRbr = 0; rbRbr < numOfAllTargetSubModuls; ++rbRbr) 

    // 02.04.2018. 
    //hamper.Height =                                                           hampRow3 * (ZXC.QUN + ZXC.Qun4);
      hamper.Height = (ZXC.IsSvDUH) ? numberOfRows * (ZXC.QUN + ZXC.Qun8) + ZXC.QUN : numberOfRows * (ZXC.QUN + ZXC.Qun8) + ZXC.QUN;
      
   }

#endregion hamper

#region Event cancelButton

   void cancelButton_Click(object sender, EventArgs e)
   {
      this.Close();
   }

#endregion Event cancelButton

#region Fld_

#endregion Fld_

   private void OnRbChecked_SpecifyVvSubModul(object sender, EventArgs e)
   {
      RadioButton rbt = sender as RadioButton;

      TheVvSubModul = (VvForm.VvSubModul)rbt.Tag;
   }

}

