      hamper.VvSpcBefRow    = new int[] { ZXC.Qun8,ZXC.Qun8 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

      hamper.CreateVvLabel(0, 0, "Upravo ste započeli akciju povezivanja prikazanog dokumenta sa nekim drugim dokumentom.", ContentAlignment.MiddleCenter);
      hamper.CreateVvLabel(0, 1, "Na ekranu gdje je prikazan taj drugi dokument kliknite 'EndLink'", ContentAlignment.MiddleCenter);
