   public ZXC.Faktur2NalogTimeRuleEnum Fld_Faktur2NalogTime_Ulaz
   {
      get
      {
              if(rbt_odmahU.Checked) return ZXC.Faktur2NalogTimeRuleEnum.DoIt_For_AnyUndone       ;
         else if(rbt_zaSatU.Checked) return ZXC.Faktur2NalogTimeRuleEnum.DoIt_For_AddTS_OneHourOld;
         else if(rbt_sutraU.Checked) return ZXC.Faktur2NalogTimeRuleEnum.DoIt_For_AddTS_NotToday  ;
         else if(rbt_nikadU.Checked) return ZXC.Faktur2NalogTimeRuleEnum.DoIt_NEVER               ;

         else throw new Exception("Fld_Faktur2NalogTime_Ulaz: who df is checked?");
      }
      set
      {
         switch(value)
         {
            case ZXC.Faktur2NalogTimeRuleEnum.DoIt_For_AnyUndone       : rbt_odmahU.Checked = true; break;
            case ZXC.Faktur2NalogTimeRuleEnum.DoIt_For_AddTS_OneHourOld: rbt_zaSatU.Checked = true; break;
            case ZXC.Faktur2NalogTimeRuleEnum.DoIt_For_AddTS_NotToday  : rbt_sutraU.Checked = true; break;
            case ZXC.Faktur2NalogTimeRuleEnum.DoIt_NEVER               : rbt_nikadU.Checked = true; break;
         }
      }
   }
   
