public class FiskalizePoslProstorDlg : VvDialog
{
   private Button   okButton, cancelButton;
   private int      dlgWidth, dlgHeight;

   public FiskalizePoslProstorUC TheUC { get; private set; }

   public FiskalizePoslProstorDlg()
   {

      TheUC = new FiskalizePoslProstorUC();

      SuspendLayout();

      this.Font        = ZXC.vvFont.BaseFont;
      this.Style       = ZXC.vvColors.vvform_VisualStyle;
      this.BackColor   = ZXC.vvColors.userControl_BackColor;

      this.StartPosition = FormStartPosition.CenterScreen;
      this.Text          = "Fiskalizcija Poslovnog Prostora";

      CreateTheUC();

      dlgWidth        = TheUC.Width;
      dlgHeight       = TheUC.Height + ZXC.QunMrgn * 2 + ZXC.QunBtnH;
      this.ClientSize = new Size(dlgWidth, dlgHeight);
      AddOkCancelButtons(out okButton, out cancelButton, dlgWidth, dlgHeight);
      okButton.Anchor = cancelButton.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;

      ResumeLayout();

   }

   private void CreateTheUC()
   {
      TheUC.Parent   = this;
      TheUC.Location = new Point(0, 0);
   }

   void cancelButton_Click(object sender, EventArgs e)
   {
      this.Close();
   }

}

public class FiskalizePoslProstorUC : VvOtherUC
{
#region Fieldz

   private VvHamper  hamper;
   private VvTextBox tbx_oib, tbx_skladCd, tbx_skladName, tbx_skladBr, tbx_ulica, tbx_kbr, tbx_dodKbr, tbx_pb,
                     tbx_naselje, tbx_opcina, tbx_radVrij, tbx_dateStart, tbx_oibSw;
   private VvDateTimePicker dtp_dateStart;

#endregion Fieldz

#region Constructor

   public FiskalizePoslProstorUC()
   {
      SuspendLayout();

      CreateHampers();
      
      VvHamper.Open_Close_Fields_ForWriting(this, ZXC.ZaUpis.Otvoreno, ZXC.ParentControlKind.VvOtherUC);

      this.Size = new Size(hamper.Right + ZXC.QunMrgn, hamper.Bottom);

      ResumeLayout();
   }

#endregion Constructor

#region Hampers 

   private void CreateHampers()
   {
      InitializeHamper(out hamper);
   }

   private void InitializeHamper(out VvHamper hamper)
   {
      hamper = new VvHamper(6, 12, "", this, false, ZXC.QunMrgn, ZXC.QunMrgn, 0);

      hamper.VvColWdt      = new int[] { ZXC.Q3un, ZXC.Q5un, ZXC.Q8un, ZXC.Q2un, ZXC.Q2un, ZXC.Q6un};
      hamper.VvSpcBefCol   = new int[] { ZXC.Qun4, ZXC.Qun4, ZXC.Qun4 , ZXC.Qun4, ZXC.Qun4, ZXC.Qun4};
      hamper.VvRightMargin = hamper.VvLeftMargin;

      for(int i = 0; i < hamper.VvNumOfRows; i++)
      {
         hamper.VvRowHgt[i] = ZXC.QUN;
         hamper.VvSpcBefRow[i] = ZXC.Qun8;
      }
      hamper.VvBottomMargin = hamper.VvTopMargin;

      hamper.CreateVvLabel(2, 0, "Poslovni prostor"           , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 1, "OIB:"                       , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 2, "Oznaka poslovnog prstora:"  , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 3, "Ulica:"                     , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 4, "Kućni broj:"                , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 5, "Dodatak kućnom broju:"      , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 6, "Broj pošte:"                , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 7, "Naselje:"                   , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 8, "Općina:"                    , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2, 9, "Radno vrijeme:"             , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2,10, "Datum početka primjene:"    , ContentAlignment.MiddleRight);
      hamper.CreateVvLabel(2,11, "OIB proizvođača software-a:", ContentAlignment.MiddleRight);

      tbx_oib        = hamper.CreateVvTextBox(3, 1, "tbx_dateSatrt", "Datum pocetka", 11, 1, 0);
      
      tbx_skladCd    = hamper.CreateVvTextBoxLookUp(0, 2, "tbx_SkladCd", "Skladište");
      tbx_skladName  = hamper.CreateVvTextBox      (1, 2, "tbx_SkladOpiS", "");
      tbx_skladBr = hamper.CreateVvTextBox         (3, 2, "tbx_SkladRbr", "");
      tbx_skladCd.JAM_CharacterCasing        = CharacterCasing.Upper;
      tbx_skladCd.JAM_MustTabOutBeforeSubmit = true;
      tbx_skladName.JAM_ReadOnly             = true;
      tbx_skladBr.JAM_ReadOnly               = true;

      tbx_skladCd.JAM_Set_LookUpTable(ZXC.luiListaSkladista, (int)ZXC.Kolona.prva);
      tbx_skladCd.JAM_lui_NameTaker_JAM_Name = tbx_skladName.JAM_Name;
      tbx_skladCd.JAM_lui_IntegerTaker_JAM_Name = tbx_skladBr.JAM_Name;

      tbx_ulica      = hamper.CreateVvTextBox(3, 3, "tbx_dateSatrt", "Datum pocetka",64, 2, 0);
      tbx_kbr        = hamper.CreateVvTextBox(3, 4, "tbx_dateSatrt", "Datum pocetka");
      tbx_dodKbr     = hamper.CreateVvTextBox(3, 5, "tbx_dateSatrt", "Datum pocetka");
      tbx_pb         = hamper.CreateVvTextBox(3, 6, "tbx_dateSatrt", "Datum pocetka");
      tbx_naselje    = hamper.CreateVvTextBox(3, 7, "tbx_dateSatrt", "Datum pocetka",64, 2, 0);
      tbx_opcina     = hamper.CreateVvTextBox(3, 8, "tbx_dateSatrt", "Datum pocetka",64, 2, 0);
      tbx_radVrij    = hamper.CreateVvTextBox(3, 9, "tbx_dateSatrt", "Datum pocetka",64, 2, 0);
      
      tbx_dateStart = hamper.CreateVvTextBox(3, 10, "tbx_dateSatrt", "Datum pocetka",12, 1, 0);
      tbx_dateStart.JAM_IsForDateTimePicker = true;
      dtp_dateStart = hamper.CreateVvDateTimePicker(3, 10, "", 1, 0, tbx_dateStart);
      dtp_dateStart.Name = "dtp_DokDate";

      tbx_oibSw = hamper.CreateVvTextBox(3, 11, "tbx_dateSatrt", "Datum pocetka", 11, 1, 0);

      tbx_oib  .JAM_CharEdits = ZXC.JAM_CharEdits.DigitsOnly;
      tbx_kbr  .JAM_CharEdits = ZXC.JAM_CharEdits.DigitsOnly;
      tbx_oibSw.JAM_CharEdits = ZXC.JAM_CharEdits.DigitsOnly;

   }
   
#endregion Hampers 

