   private void InitializeHamper_Promjena(out VvHamper hamper)
   {
      hamper          = new VvHamper(4, 1, "", this, false);
      hamper.Location = new Point( hamp_artiklInfo.Left, hamp_artiklInfo.Bottom + ZXC.QUN);

      hamper.VvColWdt      = new int[] { ZXC.Q7un, ZXC.Q4un, ZXC.Q6un, 0};
      hamper.VvSpcBefCol   = new int[] {        0, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4 };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvColWdt[3] = hamp_artiklInfo.Width - hamper.VvColWdt   [0] - hamper.VvColWdt   [1] - hamper.VvColWdt   [2]
                                                 - hamper.VvSpcBefCol[0] - hamper.VvSpcBefCol[1] - hamper.VvSpcBefCol[2] - hamper.VvSpcBefCol[3];

      for(int i = 0; i < hamper.VvNumOfRows; i++)
      {
         hamper.VvRowHgt[i]    = ZXC.QUN;
         hamper.VvSpcBefRow[i] = ZXC.Qun4;
      }
      hamper.VvBottomMargin = hamper.VvTopMargin;

                           hamper.CreateVvLabel      (0, 0, "Promjena cijene za:", ContentAlignment.MiddleRight);
      tbx_iznosPromjene  = hamper.CreateVvTextBox    (1, 0, "tbx_iznosPromjene", "", 12);
      rbt_apsolutIzn     = hamper.CreateVvRadioButton(2, 0, new EventHandler(RecalcAndPutField_NewCijena), "U apsolut. iznosu",  TextImageRelation.ImageBeforeText);
      rbt_postotak       = hamper.CreateVvRadioButton(3, 0, new EventHandler(RecalcAndPutField_NewCijena), "U postotku", TextImageRelation.ImageBeforeText);
      rbt_apsolutIzn.Checked = true;
      rbt_apsolutIzn.Tag     = true;

      tbx_iznosPromjene.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);

      tbx_iznosPromjene.JAM_FieldExitMethod = new EventHandler(RecalcAndPutField_NewCijena);
      
      hamper.BackColor = colorCalc;
  }

   private void InitializeHamper_Rezultat(out VvHamper hamper)
   {
      hamper          = new VvHamper(4, 2, "", this, false);
      hamper.Location = new Point( hamp_artiklInfo.Left, hamp_promjena.Bottom);

      hamper.VvColWdt      = new int[] { ZXC.Q7un, ZXC.Q4un, ZXC.Q6un, 0};
      hamper.VvSpcBefCol   = new int[] {        0, ZXC.Qun4, ZXC.Qun4, ZXC.Qun4 };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvColWdt[3] = hamp_artiklInfo.Width - hamper.VvColWdt   [0] - hamper.VvColWdt   [1] - hamper.VvColWdt   [2]
                                                 - hamper.VvSpcBefCol[0] - hamper.VvSpcBefCol[1] - hamper.VvSpcBefCol[2] - hamper.VvSpcBefCol[3];

      for(int i = 0; i < hamper.VvNumOfRows; i++)
      {
         hamper.VvRowHgt[i]    = ZXC.QUN;
         hamper.VvSpcBefRow[i] = ZXC.Qun4;
      }
      hamper.VvBottomMargin = hamper.VvTopMargin;


                        hamper.CreateVvLabel  (0, 0, "Nova cijena za " + jedJM + ":", ContentAlignment.MiddleRight);
      tbx_newCijena   = hamper.CreateVvTextBox(1, 0, "tbx_cijena"  , "", 12);
                        hamper.CreateVvLabel  (0, 1,  doWeWant_OP ? "Nova cijena za " + orgPakJM  + ":" : "", ContentAlignment.MiddleRight);
      tbx_newCijenaOP = hamper.CreateVvTextBox(1, 1, "tbx_cijenaOP", "", 12);
      tbx_newCijenaOP.JAM_ForeColor = colorOpFc;

      tbx_newCijenaOP.JAM_ReadOnly =
      tbx_newCijena  .JAM_ReadOnly = true; 

      tbx_newCijena    .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);
      tbx_newCijenaOP  .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, true);

      rbt_calcViaCijena   = hamper.CreateVvRadioButton(2, 0, new EventHandler(RecalcAndPutField_NewCijena), "Promjena cijene po " + jedJM   , 1, 0,TextImageRelation.ImageBeforeText);
      rbt_calcViaCijenaOP = hamper.CreateVvRadioButton(2, 1, new EventHandler(RecalcAndPutField_NewCijena), "Promjena cijene po " + orgPakJM, 1, 0, TextImageRelation.ImageBeforeText);
      rbt_calcViaCijenaOP.Checked = true;
      rbt_calcViaCijenaOP.Tag = true;

      hamper.BackColor = colorCalc;
  }

