   public ZXC.ShowArtiklInfo_CijenaKind_Enum Fld_RbtCijenaKind
   {
      get
      {
              if(rbt_ulazProsCij    .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazProsCij   ;
         else if(rbt_ulazMinCij     .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazMinCij    ;
         else if(rbt_ulazMaxCij     .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazMaxCij    ;
         else if(rbt_ulazLastCij    .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazLastCij   ;
         else if(rbt_izlazProsCij   .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazProsCij  ;
         else if(rbt_izlazMinCij    .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazMinCij   ;
         else if(rbt_izlazMaxCij    .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazMaxCij   ;
         else if(rbt_izlazLastCij   .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazLastCij  ;
         else if(rbt_thisKupProsCij .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupProsCij;
         else if(rbt_thisKupMinCij  .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupMinCij ;
         else if(rbt_thisKupMaxCij  .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupMaxCij ;
         else if(rbt_thisKupLastCij .Checked) return ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupLastCij;

         else throw new Exception("Fld_ShowArtiklInfo: who df is checked?");
      }
      set
      {
         switch(value)
         {
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazProsCij   : rbt_ulazProsCij   .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazMinCij    : rbt_ulazMinCij    .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazMaxCij    : rbt_ulazMaxCij    .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.ulazLastCij   : rbt_ulazLastCij   .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazProsCij  : rbt_izlazProsCij  .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazMinCij   : rbt_izlazMinCij   .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazMaxCij   : rbt_izlazMaxCij   .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.izlazLastCij  : rbt_izlazLastCij  .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupProsCij: rbt_thisKupProsCij.Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupMinCij : rbt_thisKupMinCij .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupMaxCij : rbt_thisKupMaxCij .Checked = true; break;
            case ZXC.ShowArtiklInfo_CijenaKind_Enum.thisKupLastCij: rbt_thisKupLastCij.Checked = true; break;
         }
      }
   }

