   private void RecalcAndPutField_NewCijena(object sender, EventArgs e)
   {
      if(Fld_IsPostotak) // digni za postotak 
      {
                         Fld_NewCijena   = ZXC.VvGet_125_on_100(Fld_OldCijena  , Fld_IznosPromjene);
         if(doWeWant_OP) Fld_NewCijenaOP = ZXC.VvGet_125_on_100(Fld_OldCijenaOP, Fld_IznosPromjene);
      }
      else // digni za iznos
      {
         if(Fld_IsNewCijOP)
         {
            if(doWeWant_OP) Fld_NewCijenaOP = Fld_OldCijenaOP + Fld_IznosPromjene;
                            Fld_NewCijena   = Fld_NewCijenaOP * orgPak           ;
         }
         else // NewCij iz classic JM 
         {
                            Fld_NewCijena   = Fld_OldCijena + Fld_IznosPromjene ;
            if(doWeWant_OP) Fld_NewCijenaOP = ZXC.DivSafe(Fld_NewCijena, orgPak);
         }
      }
   }

