      colorKom  = Color.FromArgb(193, 208, 223);//Color.FromArgb(193, 205, 193); //Color.FromArgb(150, 191, 186);*/Color.FromArgb(193, 222, 181);
      colorOP   = Color.FromArgb(219, 234, 248);//Color.FromArgb(224, 238, 224); //Color.FromArgb(169, 215, 209);*/Color.FromArgb(215, 247, 202);
      colorCalc = Color.FromArgb(193, 208, 223);//Color.FromArgb(193, 205, 193); //Color.FromArgb(150, 191, 186);*/Color.FromArgb(193, 222, 181);
      colorOpFc = Color.FromArgb( 28, 100, 164);
   }
