#region Constructor

   public PutAndCalcOtpadPiljUC()
   {
      SuspendLayout();

      InitializeHamper(out hamp_artiklSpecif);
      
      VvHamper.Open_Close_Fields_ForWriting(this, ZXC.ZaUpis.Otvoreno, ZXC.ParentControlKind.VvOtherUC);

