      hamper          = new VvHamper(2, 3, "", this, false);
      hamper.Location = new Point(ZXC.QunMrgn, ZXC.QunMrgn);

      hamper.VvColWdt      = new int[] { ZXC.Q9un, ZXC.Q4un };
      hamper.VvSpcBefCol   = new int[] { ZXC.Qun4, ZXC.Qun4 };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt       = new int[] { ZXC.QUN , ZXC.QUN , ZXC.QUN };
      hamper.VvSpcBefRow    = new int[] { ZXC.Qun4, ZXC.Qun4, ZXC.Qun4};
      hamper.VvBottomMargin = hamper.VvTopMargin;

                         hamper.CreateVvLabel  (0, 0, "Cijena otpada:"  , ContentAlignment.MiddleRight);
      tbx_cijenaOtpada = hamper.CreateVvTextBox(1, 0, "tbx_cijenaOtpada", "Cijena otpada", 12);
      
                            hamper.CreateVvLabel  (0, 1, "Cijena piljevine:"   ,  ContentAlignment.MiddleRight);
      tbx_cijenaPiljevine = hamper.CreateVvTextBox(1, 1, "tbx_cijenaPiljevine", "Cijena piljevine", 12);

                            hamper.CreateVvLabel  (0, 2, "Udio piljevine u otpadu u %:", ContentAlignment.MiddleRight);
      tbx_udioPiljUOtpadu = hamper.CreateVvTextBox(1, 2, "tbx_udioPiljUOtpadu", "Udio piljevine", 12);

      tbx_cijenaOtpada   .JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, false);
      tbx_cijenaPiljevine.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, false);
      tbx_udioPiljUOtpadu.JAM_MarkAsNumericTextBox(2, true, decimal.MaxValue, decimal.MinValue, false);
      tbx_udioPiljUOtpadu.JAM_IsForPercent = true;

   }
   
#endregion Hamper

#region Fld_

   public decimal Fld_CijOtpada { get { return tbx_cijenaOtpada   .GetDecimalField(); } set { tbx_cijenaOtpada   .PutDecimalField(value); } }
   public decimal Fld_CijPiljev { get { return tbx_cijenaPiljevine.GetDecimalField(); } set { tbx_cijenaPiljevine.PutDecimalField(value); } }
   public decimal Fld_UdioPuO   { get { return tbx_udioPiljUOtpadu.GetDecimalField(); } set { tbx_udioPiljUOtpadu.PutDecimalField(value); } }

#endregion Fld_

}


