    //   //Fld_thCycleMoment2_PON = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay("XYZ2", Fld_nextZPCDate).Opis;
    //     Fld_thCycleMomentXY    = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay("XYZ2", Fld_nextZPCDate).Opis;
    //     return;
    //  }
    //  else if(_shopWeekKind == ZXC.TH_ShopWeekKind._2W_SRI)
    //  {
    //   //Fld_thCycleMoment2_SRI = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay("36M2", Fld_nextZPCDate).Opis; // Stavismo '36M2' da ga uguramo u ZXC.TH_ShopWeekKind._2W_SRI 
    //     Fld_thCycleMomentXY = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay("36M2", Fld_nextZPCDate).Opis; // Stavismo '36M2' da ga uguramo u ZXC.TH_ShopWeekKind._2W_SRI 
    //     return;
    //  }
    ////else if(is5week == true && ZXC.IsThisCycleMoment6week(ZXC.Get_TH_CycleMoment(initialDate, true, "")))
    //  else if(_shopWeekKind == ZXC.TH_ShopWeekKind._5W)
    //  {
    //   //Fld_thCycleMoment5 = ZXC.TH_GetCycleMoment_AsNiceString(Fld_nextZPCDate, "XYZ5").ToString();
    //     Fld_thCycleMomentXY = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay("XYZ5", Fld_nextZPCDate).Opis;
    //     return;
    //  }
    //  else if(_shopWeekKind == ZXC.TH_ShopWeekKind._3W_SRI)
    //  {
    //     Fld_thCycleMomentXY = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay("54M2", Fld_nextZPCDate).Opis; // Karlovac npr
    //     return;
    //  }

      string skladCD = "";
      switch(_shopWeekKind)
      {
         case ZXC.TH_ShopWeekKind._5W    : skladCD = "XYZ5"; break;
         case ZXC.TH_ShopWeekKind._2W_PON: skladCD = "XYZ2"; break;
         case ZXC.TH_ShopWeekKind._2W_SRI: skladCD = "68M2"; break;
         case ZXC.TH_ShopWeekKind._3W_SRI: skladCD = "36M2"; break;

         default: ZXC.aim_emsg(MessageBoxIcon.Error, "dtp_nextZPCDate_ValueChanged_SetTH_CycleMoments is null! ShopWeekKind[" + _shopWeekKind.ToString()); break;
      }
      Fld_thCycleMomentXY = TH_PriceRuleForCycleMoment.GetTHPR_ForThisDay(skladCD, Fld_nextZPCDate).Opis; 

      // idemo dalje 'po starom' dok nije bilo 2week transformacije u 3week 

      //Fld_nextZPCDate = ZXC.TH_GetNextZPCDate(Fld_nextZPCDate);
      Fld_nextZPCDate =                      (Fld_nextZPCDate.Date);
   }
   
