#endregion Filedz

#region Constructor

   public VvTakeRowsFromManyDocumentsDlg(string text, uint kupdobCd, string kupDobTK, string kupdobName, DateTime datumOd, DateTime datumDo)
   {
      this.StartPosition = FormStartPosition.CenterScreen;
      this.Text = text;

