public class SVD_Odobrenje_Dlg : VvDialog
{
#region Fieldz

   public  Button   okButton, cancelButton, changeButton;
   private VvHamper hampOdobrenje;
   public  VvTextBox tbx_password;
   private int dlgWidth, dlgHeight;
   public  ComboBox combbx_user;

   private string KupdobTKfirstLetter { get; set; }

#endregion Fieldz

#region Constructor


   public SVD_Odobrenje_Dlg(string _kupdobTKfirstLetter)
   {
      SuspendLayout();

      CreateOdobrenjeHamper(out hampOdobrenje);
      CalcSize();

      AddOkCancelButtons(out okButton, out cancelButton, dlgWidth, dlgHeight);
      okButton.Anchor = cancelButton.Anchor = AnchorStyles.Bottom | AnchorStyles.Right;

      okButton    .Text = "Odobri";
      cancelButton.Text = "Odustani";

      this.Text = "Odobrenje Zahtjevnice";
      this.StartPosition = FormStartPosition.CenterScreen;

      //this.FormClosing += new FormClosingEventHandler(FormClosing_GetFields);

      this.KupdobTKfirstLetter = _kupdobTKfirstLetter;

      PutFields(ZXC.TheVvForm.VvPref.SVDZAH);

      ResumeLayout();
   }
  
   private void PutFields(VvPref.SVDZAHPrefs SVDZAHPrefs)
   {
      List<string> allZAHodobravateljiUserNameList = SVDZAHPrefs.UserNameHistoryDecrypted.Distinct().ToList();

      Fld_UserNameHistory = allZAHodobravateljiUserNameList.Where(userName => userName.SubstringSafe(0,1) == KupdobTKfirstLetter).ToList();

      if(Fld_UserNameHistory.NotEmpty())
      {
         Fld_UserName = Fld_UserNameHistory.First();
      }
   }

   public void ComboBoxUser_AddEventuallyNewDataSourceMember()
   {
      if(Fld_UserName.NotEmpty() && combbx_user.FindStringExact(Fld_UserName) < 0) // new entry 
      {
         if(Fld_UserNameHistory == null) Fld_UserNameHistory = new List<string>(1);

         Fld_UserNameHistory                        .Add(                               Fld_UserName) ;

         if(ZXC.TheVvForm.VvPref.SVDZAH.userNameHistory.IsEmpty()) ZXC.TheVvForm.VvPref.SVDZAH.userNameHistory = new List<string>();

         ZXC.TheVvForm.VvPref.SVDZAH.userNameHistory.Add(ZXC.EncryptThis_LoginForm_Data(Fld_UserName));
      }

      //ZXC.TheVvForm.VvPref.SVDZAH.userNameHistory = GetUserHistoryEncrypted(Fld_UserNameHistory);
   }

   private List<string> GetUserHistoryEncrypted(List<string> userNameHistory)
   {
      if(userNameHistory == null) return null;

      List<string> encryptedArray = new List<string>(userNameHistory.Count);

      foreach(string user in userNameHistory)
      {
         encryptedArray.Add(ZXC.EncryptThis_LoginForm_Data(user));
      }

      return encryptedArray;
   }


#endregion Constructor

#region Fld_

   public string Fld_UserName { get { return combbx_user .Text; } set { combbx_user .SelectedItem = value; } }
   public string Fld_Password { get { return tbx_password.Text; } set { tbx_password.Text =         value; } }

   public List<string> Fld_UserNameHistory
   {
      get { return (List<string>)combbx_user.DataSource        ; }
      set {                      combbx_user.DataSource = value; }
   }

#endregion Fld_

#region hamper

   private void CreateOdobrenjeHamper(out VvHamper hamper)
   {
      hamper = new VvHamper(3, 2, "", this, false);
      hamper.Location = new Point(0, ZXC.QunMrgn);

      hamper.VvColWdt      = new int[] { ZXC.Q5un, ZXC.Q7un, ZXC.QunBtnW     };
      hamper.VvSpcBefCol   = new int[] { ZXC.Qun4, ZXC.Qun4, ZXC.QunMrgn / 2 };
      hamper.VvRightMargin = hamper.VvLeftMargin;

      hamper.VvRowHgt       = new int[] { ZXC.QUN , ZXC.QUN };
      hamper.VvSpcBefRow    = new int[] { ZXC.Qun2, ZXC.Qun2 };
      hamper.VvBottomMargin = hamper.VvTopMargin;

                    hamper.CreateVvLabel   (0, 0, "UserName:", ContentAlignment.MiddleRight);
      combbx_user = hamper.CreateVvComboBox(1, 0, "", "combbx_user", ComboBoxStyle.DropDown);

                     hamper.CreateVvLabel  (0, 1, "Password:", ContentAlignment.MiddleRight);
      tbx_password = hamper.CreateVvTextBox(1, 1, "tbx_password", "", 16);
      tbx_password.JAM_IsPassword = true;

      changeButton = hamper.CreateVvButton(2, 1, new EventHandler(ChangePassword_Click), "Promijeni");

      VvHamper.Open_Close_Fields_ForWriting(combbx_user, ZXC.ZaUpis.Otvoreno, ZXC.ParentControlKind.Login_Form);
      VvHamper.Open_Close_Fields_ForWriting(tbx_password, ZXC.ZaUpis.Otvoreno, ZXC.ParentControlKind.Login_Form);

   }

   private void CalcSize()
   {
      dlgWidth  = hampOdobrenje.Right + ZXC.Qun2;
      dlgHeight = hampOdobrenje.Bottom + 2 * ZXC.QunBtnH;
      this.ClientSize = new Size(dlgWidth, dlgHeight);
   }

#endregion hamper

   private void ChangePassword_Click(object sender, EventArgs e)
   {
      // ovdje si dosao kao obican (npr 'A10') user                                    
      // AAA odobravatelj si tu sad hoce promijebniti password                                        
      // ZXC.vvDB_User je, dakle, "A10" a ti zelis u vvSD_vektor user tablici RWTREC ati "AAA" usera  
      // PRIVREMENU konekciju pak zelis kreirati za "superuser" usera (i password) da bi ti MySQL dao 
      // dirati njegovu user tablicu                                                                  

      //ZXC.vvDB_Server   = this.Fld_ServerHost; //if(!ZXC.NotEmpty(ZXC.vvDB_Server)) ZXC.vvDB_Server = "localhost";
      //ZXC.vvDB_VvDomena = this.Fld_VvDomena;
      //ZXC.vvDB_User     = this.Fld_UserName;
      //ZXC.vvDB_Password = ZXC.EncryptThis_UserUC_Password(this.Fld_Password, this.Fld_UserName);
      //ZXC.projectYear   = this.Fld_ProjectYear.ToString(ZXC.VvDateYyyyFormat);

      if(ZXC.TheVvForm.Check_SVDZAH_OdobrenjeCredentials(KupdobTKfirstLetter, Fld_UserName, Fld_Password) == false)
      {
         ZXC.aim_emsg(MessageBoxIcon.Stop, "Pogrešan password i/ili username ovlaštene osobe za odobravanje zahtjevnice.");
         return;
      }

      bool OK;
    //string OLD_odobravateljPasswordEncrypted = ZXC.EncryptThis_UserUC_Password(this.Fld_Password, this.Fld_UserName);

    //string userName4connection = Fld_UserName;
    //string password4connection = ZXC.EncryptThis_UserUC_Password(this.Fld_Password, this.Fld_UserName);
      string userName4connection = ZXC.CURR_user_rec.UserName/*4Sql*/     ;
      string password4connection = ZXC.CURR_user_rec.PasswdEncodedAsInFile;

      using(XSqlConnection tmpUserConn = VvSQL.CREATE_AND_OPEN_XSqlConnection(ZXC.vvDB_Server, userName4connection, password4connection, ZXC.TheVvForm.GetvvDB_prjktDB_name(), true))
      {
         if(tmpUserConn == null || tmpUserConn.State != ConnectionState.Open) return;

         ChangePasswordForm cpf = new ChangePasswordForm();
         cpf.ShowDialog();

         if(cpf.DialogResult == DialogResult.Cancel) return;

         //===== RWTREC for selected 'ZXC.vvDB_User' =================================

         ZXC.UserDao = UserDao.Instance(/*ZXC.PrjConnection*/tmpUserConn, ZXC.TheVvForm.GetvvDB_prjktDB_name());
         User user_rec = new User(0); // Dakle ovaj type initializer bi dizao gore spomenuti Exception; Reference not set, ... 

         OK = ZXC.UserDao.SetMe_Record_byUserName(/*ZXC.PrjConnection*/tmpUserConn, user_rec, Fld_UserName);

         user_rec.BeginEdit(); // da ne dize 'RenameUser' 

         user_rec.PasswdEncodedAsInFile = ZXC.EncryptThis_UserUC_Password(cpf.Fld_NewPassword, user_rec.UserName);

         if(user_rec.PasswdEncodedAsInFile.Length > ZXC.UserDao.GetSchemaColumnSize(ZXC.UserDao.CI.password))
         {
            //ZXC.RaiseErrorProvider(tbx_passwd, "Password PREDUGACAK!");
            user_rec.PasswdEncodedAsInFile = "";
            return;
         }

         //=========== Save Changes ===================== 

         // SVDZAH odobravatelj user egzistira SAMO u vvektor.user         
         // tablici ALI NE i u                          mysql.user tablici 
         // kako inace ostali vektor useri budu                            

       //OK = VvSQL.RenameUserAndSetPassword(/*ZXC.PrjConnection*/tmpUserConn, user_rec);

         if(OK)
         {
            OK = ZXC.UserDao.RWTREC(/*ZXC.PrjConnection*/tmpUserConn, user_rec);
         }
         //=========== Save Changes ===================== 

         if(OK)
         {
            // ovo ne radi zbog rucno supressanog USER refreshanja u SifrarNeedsRefreshing 
            // a ne znam zasto je supresano prema komentaru "18.10.2017:"
          //ZXC.TheVvForm.TheVvUC.SetSifrarAndAutocomplete<User>(null, VvSQL.SorterType.Code);

            // kako je element liste immutuable, prvo ga treba izbaciti pa onda novoga dodati 
            VvUserControl.UserSifrar.RemoveAll(user => user.UserName == user_rec.UserName);
            VvUserControl.UserSifrar.Add(user_rec);
         }

         Fld_Password = cpf.Fld_NewPassword;

         cpf.Dispose();
      }

      return;
   }

}

